# DIAMOND 3D EDITION — OYUN RENDERER
# ══════════════════════════════════════════════════════════════════════════════

def _diamond_game_html(html_content: str, height: int = 680, scrolling: bool = False):
    """Diamond 3D Edition container ile oyun HTML'i render eder. Tam ekran butonu oyunun icinde."""
    # Tam ekran butonunu oyun HTML'inin icine ekle (Streamlit'e dokunmaz)
    fs_inject = """
    <div id="_fsBtn" style="position:fixed;top:6px;right:6px;z-index:99999;
        background:rgba(0,0,0,0.7);border:1px solid rgba(201,168,76,0.5);
        color:#c9a84c;padding:5px 12px;border-radius:6px;cursor:pointer;
        font-size:12px;font-weight:bold;user-select:none;"
        onclick="(function(){var el=document.documentElement;if(!document.fullscreenElement){
        el.requestFullscreen?el.requestFullscreen():el.webkitRequestFullscreen&&el.webkitRequestFullscreen();
        document.getElementById('_fsBtn').textContent='✕ Cik'}else{
        document.exitFullscreen?document.exitFullscreen():document.webkitExitFullscreen&&document.webkitExitFullscreen();
        document.getElementById('_fsBtn').textContent='⛶ Tam Ekran'}})()">⛶ Tam Ekran</div>
    """
    # </body> etiketinden once ekle
    if "</body>" in html_content:
        html_content = html_content.replace("</body>", fs_inject + "</body>")
    elif "</html>" in html_content:
        html_content = html_content.replace("</html>", fs_inject + "</html>")
    else:
        html_content = html_content + fs_inject

    st.markdown('<div class="dk-diamond-game-container">', unsafe_allow_html=True)
    st.components.v1.html(html_content, height=height, scrolling=scrolling)
    st.markdown('</div>', unsafe_allow_html=True)

def _render_diamond_game(
    title: str,
    subtitle: str,
    icon: str,
    games: list[tuple],
    key: str,
    accent: str = "#ffd700",
    category_stats: dict | None = None,
):
    """Premium Diamond 3D Edition oyun bölümü renderer.

    Args:
        title: Bölüm başlığı
        subtitle: Açıklama metni
        icon: Emoji ikon
        games: [(isim, builder_fn), ...] listesi
        key: Streamlit selectbox key
        accent: Vurgu rengi
        category_stats: Opsiyonel istatistik dict {label: value}
    """
    game_count = len(games)

    # ── Diamond Header ──
    stats_html = ""
    if category_stats:
        stats_items = "".join(
            f'<div class="dk-game-stat"><div class="val">{v}</div>'
            f'<div class="lbl">{k}</div></div>'
            for k, v in category_stats.items()
        )
        stats_html = f'<div class="dk-game-stats-bar">{stats_items}</div>'

    st.markdown(
        f'<div class="dk-diamond-game-header">'
        f'<div class="title">{icon} {title}'
        f'<span class="badge">Diamond 3D</span></div>'
        f'<div class="subtitle">{subtitle}</div>'
        f'</div>',
        unsafe_allow_html=True,
    )

    # ── Diamond Body ──
    st.markdown('<div class="dk-diamond-game-body">', unsafe_allow_html=True)

    # Stats bar
    if stats_html:
        st.markdown(stats_html, unsafe_allow_html=True)

    # Game selector
    st.markdown('<div class="dk-diamond-select-wrap">', unsafe_allow_html=True)
    game_names = [g[0] for g in games]
    selected = st.selectbox(
        f"🎮 Oyun Seç ({game_count} oyun)",
        game_names,
        key=key,
    )
    st.markdown("</div>", unsafe_allow_html=True)

    # Game container with Diamond frame
    builder = next(g[1] for g in games if g[0] == selected)
    st.markdown('<div class="dk-diamond-game-container">', unsafe_allow_html=True)
    st.components.v1.html(builder(), height=680, scrolling=False)
    st.markdown("</div>", unsafe_allow_html=True)

    # Close body
    st.markdown("</div>", unsafe_allow_html=True)


