# SUDOKU ÜRETECİ & İNTERAKTİF OYUN
# ══════════════════════════════════════════════════════════════════════════════

import random
import copy
import json as _json
from datetime import datetime


def _generate_complete_grid() -> list[list[int]]:
    """Backtracking + randomization ile geçerli 9×9 Sudoku grid üret."""
    grid = [[0] * 9 for _ in range(9)]

    def _possible(r: int, c: int, num: int) -> bool:
        if num in grid[r]:
            return False
        if any(grid[row][c] == num for row in range(9)):
            return False
        br, bc = 3 * (r // 3), 3 * (c // 3)
        for i in range(br, br + 3):
            for j in range(bc, bc + 3):
                if grid[i][j] == num:
                    return False
        return True

    def _fill(pos: int = 0) -> bool:
        if pos == 81:
            return True
        r, c = divmod(pos, 9)
        if grid[r][c] != 0:
            return _fill(pos + 1)
        nums = list(range(1, 10))
        random.shuffle(nums)
        for num in nums:
            if _possible(r, c, num):
                grid[r][c] = num
                if _fill(pos + 1):
                    return True
                grid[r][c] = 0
        return False

    _fill()
    return grid


def _remove_cells(
    grid: list[list[int]], count: int
) -> tuple[list[list[int]], list[list[int]]]:
    """Grid'den *count* hücre sil. ``(puzzle, solution)`` döndür."""
    solution = copy.deepcopy(grid)
    puzzle = copy.deepcopy(grid)
    positions = [(r, c) for r in range(9) for c in range(9)]
    random.shuffle(positions)
    for r, c in positions[:count]:
        puzzle[r][c] = 0
    return puzzle, solution


_ZORLUK_MAP = {"Kolay": 30, "Orta": 40, "Zor": 50}


def _generate_sudoku(
    difficulty: str = "Orta",
) -> tuple[list[list[int]], list[list[int]]]:
    """Zorluk seviyesine göre Sudoku üret. ``(puzzle, solution)`` döndür."""
    grid = _generate_complete_grid()
    count = _ZORLUK_MAP.get(difficulty, 40)
    return _remove_cells(grid, count)


def _build_interactive_sudoku_html(
    puzzle: list[list[int]], solution: list[list[int]]
) -> str:
    """Tam interaktif Sudoku HTML+CSS+JS üret."""
    sol_json = _json.dumps(solution)

    # --- hücre HTML ---
    rows_html = []
    for r in range(9):
        cells = []
        for c in range(9):
            extra_cls = ""
            if c % 3 == 0 and c != 0:
                extra_cls += " bb-left"
            if r % 3 == 0 and r != 0:
                extra_cls += " bb-top"
            if puzzle[r][c] != 0:
                cells.append(
                    f'<td class="sdk-fixed{extra_cls}">{puzzle[r][c]}</td>'
                )
            else:
                cells.append(
                    f'<td class="sdk-input{extra_cls}">'
                    f'<input type="number" min="1" max="9" id="c{r}{c}" '
                    f'autocomplete="off" inputmode="numeric">'
                    f"</td>"
                )
        rows_html.append("<tr>" + "".join(cells) + "</tr>")

    table_body = "".join(rows_html)

    return f"""
<!DOCTYPE html>
<html lang="tr">
<head><meta charset="utf-8">
<style>
*{{margin:0;padding:0;box-sizing:border-box}}
body{{font-family:'Segoe UI',system-ui,sans-serif;background:transparent;
      display:flex;flex-direction:column;align-items:center;padding:8px 0}}
.sdk-header{{text-align:center;margin-bottom:14px}}
.sdk-header h2{{font-size:1.25rem;color:#1e293b;font-weight:700}}
.sdk-header p{{font-size:.82rem;color:#64748b;margin-top:2px}}
table{{border-collapse:collapse;background:#fff;
       box-shadow:0 8px 32px rgba(68,114,196,.15),0 2px 8px rgba(0,0,0,.08);border-radius:12px;
       overflow:hidden;border:3px solid #4472C4}}
td{{width:46px;height:46px;text-align:center;font-size:1.15rem;
    border:1px solid #cbd5e1;position:relative;transition:all .2s ease}}
td.bb-left{{border-left:3px solid #4472C4}}
td.bb-top{{border-top:3px solid #4472C4}}
td.sdk-fixed{{background:linear-gradient(135deg,#1A2035,#e8eef5);color:#1e293b;font-weight:700;
    text-shadow:0 1px 0 rgba(255,255,255,.8)}}
td.sdk-input{{background:#fff}}
td.sdk-input input{{width:100%;height:100%;border:none;outline:none;
    text-align:center;font-size:1.15rem;font-weight:600;color:#4472C4;
    background:transparent;-moz-appearance:textfield}}
td.sdk-input input::-webkit-outer-spin-button,
td.sdk-input input::-webkit-inner-spin-button{{-webkit-appearance:none;margin:0}}
td.sdk-input:focus-within{{background:#eef2ff;box-shadow:inset 0 0 0 2px #818cf8,0 0 12px rgba(129,140,248,.2)}}
td.sdk-ok{{background:linear-gradient(135deg,#d1fae5,#bbf7d0) !important;animation:sdkPulse .4s ease}}
td.sdk-ok input{{color:#059669 !important}}
td.sdk-err{{background:linear-gradient(135deg,#fee2e2,#fecaca) !important;animation:sdkShake .3s ease}}
td.sdk-err input{{color:#dc2626 !important}}
@keyframes sdkPulse{{0%{{transform:scale(1)}}50%{{transform:scale(1.05)}}100%{{transform:scale(1)}}}}
@keyframes sdkShake{{0%,100%{{transform:translateX(0)}}25%{{transform:translateX(-3px)}}75%{{transform:translateX(3px)}}}}
.btn-row{{display:flex;gap:10px;margin-top:16px;flex-wrap:wrap;justify-content:center}}
.btn{{padding:10px 22px;border:none;border-radius:10px;font-size:.92rem;
      font-weight:600;cursor:pointer;transition:all .2s ease}}
.btn:active{{transform:scale(.95)}}
.btn:hover{{transform:translateY(-1px)}}
.btn-check{{background:linear-gradient(135deg,#4472C4,#1e3a5f);color:#fff;
            box-shadow:0 4px 16px rgba(68,114,196,.35)}}
.btn-check:hover{{box-shadow:0 6px 24px rgba(68,114,196,.5)}}
.btn-clear{{background:linear-gradient(135deg,#f59e0b,#d97706);color:#fff;
            box-shadow:0 4px 12px rgba(245,158,11,.3)}}
.btn-clear:hover{{box-shadow:0 6px 20px rgba(245,158,11,.45)}}
.btn-hint{{background:linear-gradient(135deg,#8b5cf6,#6d28d9);color:#fff;
           box-shadow:0 4px 12px rgba(139,92,246,.3)}}
.btn-hint:hover{{box-shadow:0 6px 20px rgba(139,92,246,.45)}}
.result{{margin-top:14px;padding:12px 22px;border-radius:10px;font-weight:600;
         font-size:.95rem;text-align:center;display:none;animation:sdkFadeIn .3s ease}}
@keyframes sdkFadeIn{{from{{opacity:0;transform:translateY(-5px)}}to{{opacity:1;transform:translateY(0)}}}}
.result.success{{display:block;background:linear-gradient(135deg,#d1fae5,#a7f3d0);color:#059669;
                 border:1px solid #6ee7b7;box-shadow:0 4px 16px rgba(16,185,129,.2)}}
.result.fail{{display:block;background:linear-gradient(135deg,#fee2e2,#fecaca);color:#dc2626;
              border:1px solid #fca5a5;box-shadow:0 4px 16px rgba(220,38,38,.15)}}
.timer{{font-size:.82rem;color:#64748b;margin-top:8px;text-align:center}}
@media(max-width:500px){{
  td{{width:36px;height:36px;font-size:1rem}}
  td.sdk-input input{{font-size:1rem}}
}}
</style>
</head>
<body>
<div class="sdk-header">
  <h2>&#129513; Sudoku Bulmacası</h2>
  <p>Boş hücrelere 1-9 arası sayıları yerleştirin</p>
</div>
<table>{table_body}</table>
<div class="timer" id="timer">&#9201; 00:00</div>
<div class="btn-row">
  <button class="btn btn-check" onclick="checkSolution()">&#9989; Kontrol Et</button>
  <button class="btn btn-hint" onclick="giveHint()">&#128161; İpucu</button>
  <button class="btn btn-clear" onclick="clearAll()">&#128260; Temizle</button>
</div>
<div class="result" id="result"></div>

<script>
const SOL={sol_json};
let seconds=0,timerInterval=null;

function startTimer(){{
  if(timerInterval) return;
  timerInterval=setInterval(()=>{{
    seconds++;
    const m=String(Math.floor(seconds/60)).padStart(2,'0');
    const s=String(seconds%60).padStart(2,'0');
    document.getElementById('timer').innerHTML='&#9201; '+m+':'+s;
  }},1000);
}}

document.addEventListener('input',function(e){{
  if(e.target.tagName==='INPUT') startTimer();
}});

function checkSolution(){{
  let errors=0,empty=0;
  document.querySelectorAll('td.sdk-ok,td.sdk-err').forEach(td=>{{
    td.classList.remove('sdk-ok','sdk-err');
  }});
  for(let r=0;r<9;r++){{
    for(let c=0;c<9;c++){{
      const inp=document.getElementById('c'+r+c);
      if(!inp) continue;
      const v=parseInt(inp.value);
      const td=inp.parentElement;
      if(!v||isNaN(v)){{ empty++; continue; }}
      if(v===SOL[r][c]){{ td.classList.add('sdk-ok'); }}
      else{{ td.classList.add('sdk-err'); errors++; }}
    }}
  }}
  const res=document.getElementById('result');
  if(empty>0){{
    res.className='result fail';
    res.style.display='block';
    res.textContent='&#9888; '+empty+' boş hücre var. Hepsini doldurun!';
  }} else if(errors>0){{
    res.className='result fail';
    res.style.display='block';
    res.textContent='&#10060; '+errors+' hatalı hücre var. Tekrar deneyin!';
  }} else {{
    res.className='result success';
    res.style.display='block';
    if(timerInterval) clearInterval(timerInterval);
    const m=String(Math.floor(seconds/60)).padStart(2,'0');
    const s=String(seconds%60).padStart(2,'0');
    res.textContent='&#127881; Tebrikler! Sudoku tamamlandı! Süre: '+m+':'+s;
  }}
}}

function clearAll(){{
  document.querySelectorAll('td.sdk-input input').forEach(inp=>{{
    inp.value='';
    inp.parentElement.classList.remove('sdk-ok','sdk-err');
  }});
  document.getElementById('result').style.display='none';
}}

function giveHint(){{
  const empties=[];
  for(let r=0;r<9;r++){{
    for(let c=0;c<9;c++){{
      const inp=document.getElementById('c'+r+c);
      if(inp && !inp.value) empties.push({{r,c,inp}});
    }}
  }}
  if(empties.length===0) return;
  const pick=empties[Math.floor(Math.random()*empties.length)];
  pick.inp.value=SOL[pick.r][pick.c];
  pick.inp.parentElement.classList.add('sdk-ok');
  startTimer();
}}
</script>
</body>
</html>"""


