def _can_place(grid: dict, word: str, row: int, col: int,
               direction: str, size: int) -> bool:
    """Kelimeyi grid'e yerleştirebilir miyiz kontrol et."""
    ln = len(word)
    dr, dc = (0, 1) if direction == "H" else (1, 0)
    er, ec = row + dr * ln, col + dc * ln

    # Sınır kontrolü
    if row < 0 or col < 0 or er > size or ec > size:
        return False

    # Başlangıç öncesi ve bitiş sonrası boş olmalı
    br, bc = row - dr, col - dc
    if 0 <= br < size and 0 <= bc < size and (br, bc) in grid:
        return False
    if 0 <= er < size and 0 <= ec < size and (er, ec) in grid:
        return False

    has_intersection = False
    for i in range(ln):
        r, c = row + dr * i, col + dc * i
        ch = word[i]
        if (r, c) in grid:
            if grid[(r, c)] != ch:
                return False
            has_intersection = True
        else:
            # Yanındaki hücreler boş olmalı (paralel komşuluk)
            pr, pc = (r, c - 1) if direction == "V" else (r - 1, c)
            nr, nc = (r, c + 1) if direction == "V" else (r + 1, c)
            if (pr, pc) in grid:
                return False
            if (nr, nc) in grid:
                return False

    # İlk kelime dışında en az bir kesişim olmalı
    return has_intersection


def _generate_crossword(word_count: int = 8, grid_size: int = 0) -> dict:
    """Rastgele kare bulmaca üret.

    Döndürür: {"grid": {(r,c): char}, "placed": [(word, clue, r, c, dir)],
               "rows": int, "cols": int, "offset_r": int, "offset_c": int}
    """
    if grid_size > 0:
        size = grid_size
    else:
        if word_count > 35:
            size = 50
        elif word_count > 25:
            size = 40
        elif word_count > 12:
            size = 30
        else:
            size = 20
    pool = list(_BULMACA_KELIMELER)
    random.shuffle(pool)
    extra = max(8, word_count)
    candidates = sorted(pool[:word_count + extra], key=lambda x: len(x[0]), reverse=True)

    grid: dict[tuple[int, int], str] = {}
    placed: list[tuple[str, str, int, int, str]] = []

    # İlk kelimeyi ortaya yatay yerleştir
    w0, c0 = candidates[0]
    mid = size // 2
    start_col = (size - len(w0)) // 2
    for i, ch in enumerate(w0):
        grid[(mid, start_col + i)] = ch
    placed.append((w0, c0, mid, start_col, "H"))

    for w, c in candidates[1:]:
        if len(placed) >= word_count:
            break
        best = None
        for pw, _, pr, pc, pd in placed:
            for i, ch_new in enumerate(w):
                for j, ch_old in enumerate(pw):
                    if ch_new == ch_old:
                        if pd == "H":
                            nr, nc, nd = pr - i, pc + j, "V"
                        else:
                            nr, nc, nd = pr + j, pc - i, "H"
                        if _can_place(grid, w, nr, nc, nd, size):
                            if best is None or len(w) > len(best[0]):
                                best = (w, c, nr, nc, nd)
        if best:
            bw, bc, br, bco, bd = best
            dr, dc = (0, 1) if bd == "H" else (1, 0)
            for i, ch in enumerate(bw):
                grid[(br + dr * i, bco + dc * i)] = ch
            placed.append((bw, bc, br, bco, bd))

    # Bounding box bul ve trim et
    if not grid:
        return {"grid": {}, "placed": [], "rows": 0, "cols": 0,
                "offset_r": 0, "offset_c": 0}

    min_r = min(r for r, _ in grid)
    max_r = max(r for r, _ in grid)
    min_c = min(c for _, c in grid)
    max_c = max(c for _, c in grid)

    trimmed: dict[tuple[int, int], str] = {}
    for (r, c), ch in grid.items():
        trimmed[(r - min_r, c - min_c)] = ch

    new_placed = [
        (w, cl, r - min_r, c - min_c, d) for w, cl, r, c, d in placed
    ]

    return {
        "grid": trimmed,
        "placed": new_placed,
        "rows": max_r - min_r + 1,
        "cols": max_c - min_c + 1,
        "offset_r": min_r,
        "offset_c": min_c,
    }


def _number_crossword(cw: dict) -> tuple[dict, list, list]:
    """Bulmacayı numaralandır.

    Döndürür: (numbered_cells, yatay_clues, dikey_clues)
    numbered_cells: {(r,c): number}
    yatay/dikey_clues: [(number, clue, word)]
    """
    placed = cw["placed"]
    starts: dict[tuple[int, int], int] = {}
    yatay: list[tuple[int, str, str]] = []
    dikey: list[tuple[int, str, str]] = []

    # Tüm başlangıç noktalarını topla
    all_starts = []
    for w, cl, r, c, d in placed:
        all_starts.append((r, c, w, cl, d))

    # Sol-üst'ten sağ-alt'a sırala
    all_starts.sort(key=lambda x: (x[0], x[1]))

    num = 1
    for r, c, w, cl, d in all_starts:
        if (r, c) not in starts:
            starts[(r, c)] = num
            num += 1
        n = starts[(r, c)]
        if d == "H":
            yatay.append((n, cl, w))
        else:
            dikey.append((n, cl, w))

    return starts, yatay, dikey


def _build_crossword_html(cw: dict) -> str:
    """İnteraktif kare bulmaca HTML+CSS+JS üret."""
    grid = cw["grid"]
    rows = cw["rows"]
    cols = cw["cols"]
    placed = cw["placed"]

    if not placed:
        return "<p>Bulmaca oluşturulamadı. Yeni bulmaca deneyin.</p>"

    numbered, yatay, dikey = _number_crossword(cw)

    # Solution dict for JS
    sol = {}
    for w, _, r, c, d in placed:
        dr, dc = (0, 1) if d == "H" else (1, 0)
        for i, ch in enumerate(w):
            sol[f"{r + dr * i}_{c + dc * i}"] = ch

    sol_json = _json.dumps(sol, ensure_ascii=False)

    # Grid HTML
    table_rows = []
    for r in range(rows):
        cells = []
        for c in range(cols):
            if (r, c) in grid:
                num_label = ""
                if (r, c) in numbered:
                    num_label = f'<span class="cw-num">{numbered[(r, c)]}</span>'
                cells.append(
                    f'<td class="cw-cell">{num_label}'
                    f'<input type="text" maxlength="1" id="cw{r}_{c}" '
                    f'autocomplete="off" spellcheck="false">'
                    f"</td>"
                )
            else:
                cells.append('<td class="cw-black"></td>')
        table_rows.append("<tr>" + "".join(cells) + "</tr>")

    table_html = "".join(table_rows)

    # Clue HTML
    yatay_html = "".join(
        f'<div class="cw-clue"><b>{n}.</b> {cl}</div>' for n, cl, _ in yatay
    )
    dikey_html = "".join(
        f'<div class="cw-clue"><b>{n}.</b> {cl}</div>' for n, cl, _ in dikey
    )

    cell_size = 38 if cols <= 12 else 34

    return f"""
<!DOCTYPE html>
<html lang="tr">
<head><meta charset="utf-8">
<style>
*{{margin:0;padding:0;box-sizing:border-box}}
body{{font-family:'Segoe UI',system-ui,sans-serif;background:transparent;padding:4px 0}}
.cw-wrap{{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;align-items:flex-start}}
.cw-grid-wrap{{display:flex;flex-direction:column;align-items:center}}
.cw-header{{text-align:center;margin-bottom:12px}}
.cw-header h2{{font-size:1.2rem;color:#1e293b;font-weight:700}}
.cw-header p{{font-size:.8rem;color:#64748b;margin-top:2px}}
table{{border-collapse:collapse;box-shadow:0 6px 24px rgba(0,0,0,.1),0 2px 8px rgba(68,114,196,.08);
    border:2px solid #1e293b;border-radius:8px;overflow:hidden}}
td{{width:{cell_size}px;height:{cell_size}px;padding:0;position:relative;transition:all .2s ease}}
td.cw-black{{background:linear-gradient(135deg,#1e293b,#0B0F19)}}
td.cw-cell{{background:#fff;border:1px solid #94a3b8}}
td.cw-cell input{{width:100%;height:100%;border:none;outline:none;text-align:center;
    font-size:1.05rem;font-weight:700;color:#1e293b;background:transparent;
    text-transform:uppercase;padding-top:8px}}
td.cw-cell:focus-within{{background:#eef2ff;box-shadow:inset 0 0 0 2px #6366f1,0 0 12px rgba(99,102,241,.15)}}
.cw-num{{position:absolute;top:1px;left:3px;font-size:.6rem;font-weight:700;color:#6366f1;
    pointer-events:none;line-height:1;z-index:2}}
td.cw-ok{{background:linear-gradient(135deg,#d1fae5,#a7f3d0) !important;animation:cwPulse .3s ease}}
td.cw-ok input{{color:#059669 !important}}
td.cw-err{{background:linear-gradient(135deg,#fee2e2,#fecaca) !important;animation:cwShake .3s ease}}
td.cw-err input{{color:#dc2626 !important}}
@keyframes cwPulse{{0%{{transform:scale(1)}}50%{{transform:scale(1.05)}}100%{{transform:scale(1)}}}}
@keyframes cwShake{{0%,100%{{transform:translateX(0)}}25%{{transform:translateX(-2px)}}75%{{transform:translateX(2px)}}}}
.cw-clues{{display:flex;gap:24px;flex-wrap:wrap;max-width:500px}}
.cw-clue-col{{flex:1;min-width:200px}}
.cw-clue-col h3{{font-size:.95rem;color:#4472C4;margin-bottom:8px;
    padding-bottom:4px;border-bottom:2px solid #4472C4}}
.cw-clue{{font-size:.82rem;color:#94A3B8;margin-bottom:5px;line-height:1.4}}
.cw-clue b{{color:#6366f1}}
.cw-btn-row{{display:flex;gap:10px;margin-top:14px;flex-wrap:wrap;justify-content:center}}
.cw-btn{{padding:10px 22px;border:none;border-radius:10px;font-size:.88rem;
    font-weight:600;cursor:pointer;transition:all .2s ease}}
.cw-btn:active{{transform:scale(.95)}}
.cw-btn:hover{{transform:translateY(-1px)}}
.cw-btn-check{{background:linear-gradient(135deg,#4472C4,#1e3a5f);color:#fff;
    box-shadow:0 4px 16px rgba(68,114,196,.3)}}
.cw-btn-check:hover{{box-shadow:0 6px 24px rgba(68,114,196,.5)}}
.cw-btn-clear{{background:linear-gradient(135deg,#f59e0b,#d97706);color:#fff;
    box-shadow:0 4px 12px rgba(245,158,11,.25)}}
.cw-btn-clear:hover{{box-shadow:0 6px 20px rgba(245,158,11,.4)}}
.cw-btn-hint{{background:linear-gradient(135deg,#8b5cf6,#6d28d9);color:#fff;
    box-shadow:0 4px 12px rgba(139,92,246,.25)}}
.cw-btn-hint:hover{{box-shadow:0 6px 20px rgba(139,92,246,.4)}}
.cw-result{{margin-top:12px;padding:10px 20px;border-radius:10px;font-weight:600;
    font-size:.9rem;text-align:center;display:none;animation:cwFadeIn .3s ease}}
@keyframes cwFadeIn{{from{{opacity:0;transform:translateY(-4px)}}to{{opacity:1;transform:translateY(0)}}}}
.cw-result.success{{display:block;background:linear-gradient(135deg,#d1fae5,#a7f3d0);color:#059669;
    border:1px solid #6ee7b7;box-shadow:0 4px 16px rgba(16,185,129,.15)}}
.cw-result.fail{{display:block;background:linear-gradient(135deg,#fee2e2,#fecaca);color:#dc2626;
    border:1px solid #fca5a5;box-shadow:0 4px 16px rgba(220,38,38,.1)}}
.cw-timer{{font-size:.8rem;color:#64748b;margin-top:6px;text-align:center}}
@media(max-width:600px){{
  .cw-wrap{{flex-direction:column;align-items:center}}
  td{{width:32px;height:32px}}
  td.cw-cell input{{font-size:.9rem}}
  .cw-num{{font-size:.5rem}}
}}
</style>
</head>
<body>
<div class="cw-header">
  <h2>&#128221; Kare Bulmaca</h2>
  <p>İpuçlarını okuyarak boş hücreleri doldurun</p>
</div>
<div class="cw-wrap">
  <div class="cw-grid-wrap">
    <table>{table_html}</table>
    <div class="cw-timer" id="cwTimer">&#9201; 00:00</div>
    <div class="cw-btn-row">
      <button class="cw-btn cw-btn-check" onclick="cwCheck()">&#9989; Kontrol Et</button>
      <button class="cw-btn cw-btn-hint" onclick="cwHint()">&#128161; İpucu</button>
      <button class="cw-btn cw-btn-clear" onclick="cwClear()">&#128260; Temizle</button>
    </div>
    <div class="cw-result" id="cwResult"></div>
  </div>
  <div class="cw-clues">
    <div class="cw-clue-col">
      <h3>&#10145; Yatay</h3>
      {yatay_html}
    </div>
    <div class="cw-clue-col">
      <h3>&#11015; Dikey</h3>
      {dikey_html}
    </div>
  </div>
</div>

<script>
const CW_SOL={sol_json};
const TR_UP={{"ı":"I","i":"İ","ö":"Ö","ü":"Ü","ç":"Ç","ş":"Ş","ğ":"Ğ"}};

function trUpper(s){{
  let r='';
  for(let c of s){{
    if(TR_UP[c]) r+=TR_UP[c];
    else r+=c.toUpperCase();
  }}
  return r;
}}

let cwSec=0,cwTimer=null;
function startCwTimer(){{
  if(cwTimer) return;
  cwTimer=setInterval(()=>{{
    cwSec++;
    const m=String(Math.floor(cwSec/60)).padStart(2,'0');
    const s=String(cwSec%60).padStart(2,'0');
    document.getElementById('cwTimer').innerHTML='&#9201; '+m+':'+s;
  }},1000);
}}

document.addEventListener('input',function(e){{
  if(e.target.closest('.cw-cell')){{
    startCwTimer();
    const inp=e.target;
    inp.value=trUpper(inp.value);
    // Sonraki hücreye geç
    const td=inp.closest('td');
    const next=td.nextElementSibling;
    if(next && next.classList.contains('cw-cell')){{
      const ni=next.querySelector('input');
      if(ni) ni.focus();
    }}
  }}
}});

function cwCheck(){{
  let errors=0,empty=0;
  document.querySelectorAll('td.cw-ok,td.cw-err').forEach(td=>{{
    td.classList.remove('cw-ok','cw-err');
  }});
  for(const[key,val] of Object.entries(CW_SOL)){{
    const inp=document.getElementById('cw'+key);
    if(!inp) continue;
    const v=trUpper(inp.value.trim());
    const td=inp.parentElement;
    if(!v){{ empty++; continue; }}
    if(v===val){{ td.classList.add('cw-ok'); }}
    else{{ td.classList.add('cw-err'); errors++; }}
  }}
  const res=document.getElementById('cwResult');
  if(empty>0){{
    res.className='cw-result fail';
    res.style.display='block';
    res.textContent='&#9888; '+empty+' boş hücre var!';
  }} else if(errors>0){{
    res.className='cw-result fail';
    res.style.display='block';
    res.textContent='&#10060; '+errors+' hatalı harf var. Tekrar deneyin!';
  }} else {{
    res.className='cw-result success';
    res.style.display='block';
    if(cwTimer) clearInterval(cwTimer);
    const m=String(Math.floor(cwSec/60)).padStart(2,'0');
    const s=String(cwSec%60).padStart(2,'0');
    res.textContent='&#127881; Tebrikler! Bulmaca tamamlandı! Süre: '+m+':'+s;
  }}
}}

function cwClear(){{
  document.querySelectorAll('td.cw-cell input').forEach(inp=>{{
    inp.value='';
    inp.parentElement.classList.remove('cw-ok','cw-err');
  }});
  document.getElementById('cwResult').style.display='none';
}}

function cwHint(){{
  const empties=[];
  for(const[key,val] of Object.entries(CW_SOL)){{
    const inp=document.getElementById('cw'+key);
    if(inp && !inp.value.trim()) empties.push({{key,val,inp}});
  }}
  if(empties.length===0) return;
  const pick=empties[Math.floor(Math.random()*empties.length)];
  pick.inp.value=pick.val;
  pick.inp.parentElement.classList.add('cw-ok');
  startCwTimer();
}}
</script>
</body>
</html>"""


# ══════════════════════════════════════════════════════════════════════════════
# HAFIZA OYUNU (MEMORY GAME)
# ══════════════════════════════════════════════════════════════════════════════

_HAFIZA_EMOJILER = [
    "🐶", "🐱", "🐼", "🦁", "🐸", "🦋", "🐬", "🦊",
    "🌸", "🌻", "🍎", "🍕", "⚽", "🎸", "🚀", "🌈",
    "🎭", "🧩", "📚", "🔬", "🌍", "⭐", "🎨", "🎵",
]

_HAFIZA_ZORLUK = {"Kolay": (3, 4, 6), "Orta": (4, 4, 8), "Zor": (4, 5, 10)}


def _generate_memory_cards(difficulty: str = "Orta") -> tuple[list[str], int, int]:
    """Hafıza kartları üret. ``(cards, rows, cols)`` döndür."""
    rows, cols, pairs = _HAFIZA_ZORLUK.get(difficulty, (4, 4, 8))
    selected = random.sample(_HAFIZA_EMOJILER, pairs)
    cards = selected * 2
    random.shuffle(cards)
    return cards, rows, cols


def _build_memory_html(cards: list[str], rows: int, cols: int) -> str:
    """Hafıza oyunu interaktif HTML+CSS+JS."""
    cards_json = _json.dumps(cards, ensure_ascii=False)
    card_size = 80 if cols <= 4 else 68
    return f"""
<!DOCTYPE html><html lang="tr"><head><meta charset="utf-8">
<style>
*{{margin:0;padding:0;box-sizing:border-box}}
body{{font-family:'Segoe UI',system-ui,sans-serif;background:transparent;
      display:flex;flex-direction:column;align-items:center;padding:6px 0}}
.mem-header{{text-align:center;margin-bottom:10px}}
.mem-header h2{{font-size:1.2rem;color:#1e293b;font-weight:700}}
.mem-stats{{display:flex;gap:16px;justify-content:center;margin:8px 0;font-size:.85rem;color:#475569}}
.mem-stats span{{background:#1A2035;padding:4px 12px;border-radius:6px;font-weight:600}}
.mem-grid{{display:grid;grid-template-columns:repeat({cols},1fr);gap:8px;
           max-width:{cols*(card_size+8)}px;margin:0 auto}}
.mem-card{{width:{card_size}px;height:{card_size}px;perspective:800px;cursor:pointer}}
.mem-card-inner{{width:100%;height:100%;position:relative;transform-style:preserve-3d;
                 transition:transform .2s ease}}
.mem-card.flipped .mem-card-inner{{transform:rotateY(180deg)}}
.mem-card.matched .mem-card-inner{{transform:rotateY(180deg)}}
.mem-card-front,.mem-card-back{{position:absolute;width:100%;height:100%;
    backface-visibility:hidden;border-radius:12px;display:flex;align-items:center;
    justify-content:center}}
.mem-card-front{{background:linear-gradient(135deg,#4472C4 0%,#6366f1 50%,#1e3a5f 100%);
    box-shadow:0 4px 16px rgba(68,114,196,.35),inset 0 1px 0 rgba(255,255,255,.15);
    color:#fff;font-size:1.6rem;font-weight:700;
    border:1px solid rgba(255,255,255,.1)}}
.mem-card-front::after{{content:'?';font-size:1.8rem;text-shadow:0 0 10px rgba(255,255,255,.4)}}
.mem-card-back{{transform:rotateY(180deg);background:#fff;
    box-shadow:0 4px 16px rgba(0,0,0,.12);font-size:2rem;
    border:2px solid #e2e8f0;transition:all .3s ease}}
.mem-card.matched .mem-card-back{{background:linear-gradient(135deg,#d1fae5,#a7f3d0);
    border-color:#34d399;box-shadow:0 0 16px rgba(52,211,153,.3)}}
.mem-card:hover .mem-card-inner{{transform:scale(1.03)}}
.mem-result{{margin-top:12px;padding:12px 22px;border-radius:10px;font-weight:600;
    font-size:.95rem;text-align:center;display:none;
    background:linear-gradient(135deg,#d1fae5,#a7f3d0);color:#059669;
    border:1px solid #6ee7b7;box-shadow:0 4px 16px rgba(16,185,129,.2);
    animation:memFadeIn .4s ease}}
@keyframes memFadeIn{{from{{opacity:0;transform:scale(.95)}}to{{opacity:1;transform:scale(1)}}}}
@media(max-width:500px){{
  .mem-card{{width:60px;height:60px}}
  .mem-card-back{{font-size:1.5rem}}
}}
</style>
</head><body>
<div class="mem-header">
  <h2>&#129504; Hafıza Oyunu</h2>
</div>
<div class="mem-stats">
  <span>&#128203; Hamle: <b id="memMoves">0</b></span>
  <span>&#9201; <span id="memTimer">00:00</span></span>
  <span>&#9989; Eşleşme: <b id="memMatched">0</b>/{len(cards)//2}</span>
</div>
<div class="mem-grid" id="memGrid"></div>
<div class="mem-result" id="memResult"></div>

<script>
const CARDS={cards_json};
const TOTAL_PAIRS={len(cards)//2};
let flipped=[],matched=new Set(),moves=0,memSec=0,memTimer=null,lockBoard=false;

function startMemTimer(){{
  if(memTimer) return;
  memTimer=setInterval(()=>{{
    memSec++;
    const m=String(Math.floor(memSec/60)).padStart(2,'0');
    const s=String(memSec%60).padStart(2,'0');
    document.getElementById('memTimer').textContent=m+':'+s;
  }},1000);
}}

function createBoard(){{
  const grid=document.getElementById('memGrid');
  grid.innerHTML='';
  CARDS.forEach((emoji,i)=>{{
    const card=document.createElement('div');
    card.className='mem-card';
    card.dataset.index=i;
    card.innerHTML=`<div class="mem-card-inner">
      <div class="mem-card-front">?</div>
      <div class="mem-card-back">${{emoji}}</div></div>`;
    card.addEventListener('click',()=>flipCard(card,i));
    grid.appendChild(card);
  }});
}}

function flipCard(card,index){{
  if(lockBoard||matched.has(index)||flipped.find(f=>f.index===index)) return;
  startMemTimer();
  card.classList.add('flipped');
  flipped.push({{card,index}});
  if(flipped.length===2){{
    moves++;
    document.getElementById('memMoves').textContent=moves;
    lockBoard=true;
    const[a,b]=flipped;
    if(CARDS[a.index]===CARDS[b.index]){{
      matched.add(a.index);matched.add(b.index);
      a.card.classList.add('matched');b.card.classList.add('matched');
      flipped=[];lockBoard=false;
      document.getElementById('memMatched').textContent=matched.size/2;
      if(matched.size===CARDS.length){{
        clearInterval(memTimer);
        const m=String(Math.floor(memSec/60)).padStart(2,'0');
        const s=String(memSec%60).padStart(2,'0');
        const res=document.getElementById('memResult');
        res.style.display='block';
        res.innerHTML='&#127881; Tebrikler! '+moves+' hamlede tamamladın! Süre: '+m+':'+s;
      }}
    }}else{{
      setTimeout(()=>{{
        a.card.classList.remove('flipped');b.card.classList.remove('flipped');
        flipped=[];lockBoard=false;
      }},350);
    }}
  }}
}}
createBoard();
</script>
</body></html>"""


