    # ── Final Ek (250 hedefine) ──
    {"k": "Sayısal Mantık", "s": "7 + 7 / 7 + 7 × 7 - 7 = ? (İşlem önceliğine göre)",
     "o": ["43", "50", "44", "56"], "d": 2, "a": "7 + (7/7) + (7×7) - 7 = 7+1+49-7 = 50... Düzeltme: 7+1+49-7=50"},
    {"k": "Sayısal Mantık", "s": "Bir üçgenin iki açısı 45° ve 90° ise üçüncü açı kaç derecedir?",
     "o": ["30°", "45°", "60°", "90°"], "d": 1, "a": "180 - 45 - 90 = 45°"},
