    {"k": "Seri Tamamlama", "s": "1, 1, 2, 6, 24, ?",
     "o": ["48", "100", "120", "720"], "d": 2, "a": "Faktöriyel: 0!, 1!, 2!, 3!, 4! → 5! = 120"},

    {"k": "Analoji", "s": "Ayakkabı : Ayak = Eldiven : ?",
     "o": ["Kol", "Bilek", "El", "Parmak"], "d": 2, "a": "Ayakkabı ayağa giyilir → Eldiven ele giyilir"},
    {"k": "Analoji", "s": "Ampul : Işık = Hoparlör : ?",
     "o": ["Elektrik", "Ses", "Müzik", "Kablo"], "d": 1, "a": "Ampul ışık üretir → Hoparlör ses üretir"},
