    {"k": "Sayısal Mantık", "s": "0.125 sayısının kesir karşılığı nedir?",
     "o": ["1/4", "1/6", "1/8", "1/10"], "d": 2, "a": "0.125 = 125/1000 = 1/8"},
    {"k": "Seri Tamamlama", "s": "1, 1, 2, 3, 5, 8, 13, 21, ? — Sıradaki sayı nedir?",
     "o": ["26", "29", "34", "42"], "d": 2, "a": "Fibonacci serisi: her sayı önceki ikisinin toplamı. 13+21=34"},
