_GY_KATEGORI_RENK = {
    "Sayısal Mantık": ("#2563eb", "#1d4ed8", "&#128290;"),
    "Sözel Mantık": ("#7c3aed", "#6d28d9", "&#128172;"),
    "Seri Tamamlama": ("#059669", "#047857", "&#128200;"),
    "Analoji": ("#dc2626", "#b91c1c", "&#128279;"),
    "Şekil-Örüntü": ("#d97706", "#b45309", "&#128310;"),
}


def _generate_gy_quiz(count: int = 10) -> list[dict]:
    """Rastgele GY soruları seç."""
    pool = list(_GY_SORULAR)
    random.shuffle(pool)
    return pool[:count]


def _build_quiz_html(
    questions: list[dict],
    title: str = "&#129504; Genel Yetenek Testi",
    cat_colors: dict | None = None,
) -> str:
    """Genel amaçlı quiz HTML+CSS+JS builder."""
    if cat_colors is None:
        cat_colors = _GY_KATEGORI_RENK
    cc_json = _json.dumps(
        {k: [v[0], v[1]] for k, v in cat_colors.items()},
        ensure_ascii=False,
    )
    q_json = _json.dumps(questions, ensure_ascii=False)
    total = len(questions)

    return f"""
<!DOCTYPE html><html lang="tr"><head><meta charset="utf-8">
<style>
*{{margin:0;padding:0;box-sizing:border-box}}
body{{font-family:'Segoe UI',system-ui,sans-serif;background:transparent;
      display:flex;flex-direction:column;align-items:center;padding:6px 0}}
.gy-header{{text-align:center;margin-bottom:8px}}
.gy-header h2{{font-size:1.15rem;color:#1e293b;font-weight:700}}
.gy-progress{{display:flex;align-items:center;gap:10px;margin:8px 0}}
.gy-bar{{flex:1;max-width:300px;height:8px;background:#e2e8f0;border-radius:4px;overflow:hidden}}
.gy-bar-fill{{height:100%;background:linear-gradient(90deg,#4472C4,#6366f1);
    border-radius:4px;transition:width .3s}}
.gy-bar-text{{font-size:.82rem;font-weight:600;color:#475569;min-width:60px}}
.gy-card{{background:#fff;border-radius:14px;padding:20px 22px;margin:8px auto;
    max-width:520px;width:100%;box-shadow:0 4px 20px rgba(0,0,0,.07),0 1px 4px rgba(99,102,241,.06);
    border:1px solid #e2e8f0;animation:gyCardIn .35s ease}}
@keyframes gyCardIn{{from{{opacity:0;transform:translateY(8px)}}to{{opacity:1;transform:translateY(0)}}}}
.gy-badge{{display:inline-block;padding:4px 12px;border-radius:8px;color:#fff;
    font-size:.72rem;font-weight:700;margin-bottom:8px;box-shadow:0 2px 8px rgba(0,0,0,.12)}}
.gy-q{{font-size:1.05rem;font-weight:600;color:#1e293b;margin-bottom:14px;line-height:1.5}}
.gy-opts{{display:flex;flex-direction:column;gap:8px}}
.gy-opt{{display:flex;align-items:center;gap:10px;padding:11px 15px;border-radius:10px;
    border:2px solid #e2e8f0;cursor:pointer;transition:all .2s ease;background:#fff}}
.gy-opt:hover{{border-color:#818cf8;background:#f5f3ff;transform:translateX(3px);
    box-shadow:0 2px 10px rgba(129,140,248,.12)}}
.gy-opt.selected{{border-color:#6366f1;background:#eef2ff;box-shadow:0 0 12px rgba(99,102,241,.15)}}
.gy-opt.correct{{border-color:#059669;background:linear-gradient(135deg,#d1fae5,#a7f3d0);
    box-shadow:0 0 12px rgba(5,150,105,.15);animation:gyOptPulse .4s ease}}
.gy-opt.wrong{{border-color:#dc2626;background:linear-gradient(135deg,#fee2e2,#fecaca);
    animation:gyOptShake .3s ease}}
@keyframes gyOptPulse{{0%{{transform:scale(1)}}50%{{transform:scale(1.01)}}100%{{transform:scale(1)}}}}
@keyframes gyOptShake{{0%,100%{{transform:translateX(0)}}25%{{transform:translateX(-4px)}}75%{{transform:translateX(4px)}}}}
.gy-opt.disabled{{pointer-events:none;opacity:.85}}
.gy-opt-letter{{width:30px;height:30px;border-radius:50%;background:linear-gradient(135deg,#1A2035,#e2e8f0);
    display:flex;align-items:center;justify-content:center;
    font-size:.82rem;font-weight:700;color:#475569;flex-shrink:0;transition:all .2s ease}}
.gy-opt.correct .gy-opt-letter{{background:linear-gradient(135deg,#059669,#10b981);color:#fff;
    box-shadow:0 0 8px rgba(16,185,129,.3)}}
.gy-opt.wrong .gy-opt-letter{{background:linear-gradient(135deg,#dc2626,#ef4444);color:#fff;
    box-shadow:0 0 8px rgba(239,68,68,.3)}}
.gy-opt-text{{font-size:.92rem;color:#1e293b}}
.gy-result-badge{{display:none;text-align:center;margin-top:10px;padding:8px 16px;border-radius:10px;
    font-size:1rem;font-weight:800;letter-spacing:.5px;animation:gyFadeIn .3s ease}}
.gy-result-badge.show{{display:block}}
.gy-result-badge.badge-correct{{background:linear-gradient(135deg,#059669,#10b981);color:#fff;
    box-shadow:0 4px 15px rgba(5,150,105,.3)}}
.gy-result-badge.badge-wrong{{background:linear-gradient(135deg,#dc2626,#ef4444);color:#fff;
    box-shadow:0 4px 15px rgba(220,38,38,.3)}}
.gy-explain{{margin-top:8px;padding:12px 16px;border-radius:10px;background:linear-gradient(135deg,#f0fdf4,#ecfdf5);
    border:1px solid #bbf7d0;font-size:.82rem;color:#166534;display:none;
    animation:gyFadeIn .3s ease;box-shadow:0 2px 8px rgba(16,185,129,.08)}}
.gy-explain.show{{display:block}}
@keyframes gyFadeIn{{from{{opacity:0;transform:translateY(-4px)}}to{{opacity:1;transform:translateY(0)}}}}
.gy-next{{margin-top:12px;padding:10px 24px;border:none;border-radius:10px;
    background:linear-gradient(135deg,#4472C4,#1e3a5f);color:#fff;
    font-size:.9rem;font-weight:600;cursor:pointer;display:none;
    box-shadow:0 4px 14px rgba(68,114,196,.3);transition:all .2s ease}}
.gy-next.show{{display:inline-block}}
.gy-next:hover{{transform:translateY(-1px);box-shadow:0 6px 20px rgba(68,114,196,.4)}}
.gy-next:active{{transform:scale(.96)}}
.gy-result{{text-align:center;padding:20px;display:none;animation:gyFadeIn .4s ease}}
.gy-result.show{{display:block}}
.gy-result h3{{font-size:1.3rem;color:#1e293b;margin-bottom:6px}}
.gy-score{{font-size:2.2rem;font-weight:800;color:#6366f1;margin:8px 0;
    text-shadow:0 2px 10px rgba(99,102,241,.2)}}
.gy-breakdown{{display:flex;flex-wrap:wrap;gap:6px;justify-content:center;margin:10px 0}}
.gy-br-item{{padding:5px 12px;border-radius:8px;font-size:.75rem;font-weight:600;color:#fff;
    box-shadow:0 2px 6px rgba(0,0,0,.1)}}
.gy-timer{{font-size:.82rem;color:#64748b;margin-top:4px}}
</style></head><body>
<div class="gy-header"><h2>{title}</h2></div>
<div class="gy-progress">
  <div class="gy-bar"><div class="gy-bar-fill" id="gyBar" style="width:0%"></div></div>
  <div class="gy-bar-text" id="gyProg">0 / {total}</div>
</div>
<div id="gyQuiz"></div>
<div class="gy-result" id="gyResult"></div>

<script>
const QS={q_json};
const TOTAL={total};
const CAT_CLR={cc_json};
const LETTERS=['A','B','C','D'];
let current=0,score=0,answered=false,catScores={{}},gySec=0,gyTimer=null;

function startGyTimer(){{
  if(gyTimer) return;
  gyTimer=setInterval(()=>gySec++,1000);
}}

function renderQ(){{
  if(current>=TOTAL){{showResult();return;}}
  const q=QS[current];
  const clr=CAT_CLR[q.k]||["#475569","#334155"];
  let html='<div class="gy-card">';
  html+='<div class="gy-badge" style="background:linear-gradient(135deg,'+clr[0]+','+clr[1]+')">'+q.k+'</div>';
  html+='<div class="gy-q">'+(current+1)+'. '+q.s+'</div>';
  html+='<div class="gy-opts">';
  q.o.forEach((opt,i)=>{{
    html+='<div class="gy-opt" id="gyO'+i+'" onclick="selectOpt('+i+')">'
      +'<div class="gy-opt-letter">'+LETTERS[i]+'</div>'
      +'<div class="gy-opt-text">'+opt+'</div></div>';
  }});
  html+='</div>';
  html+='<div class="gy-result-badge" id="gyBadge"></div>';
  html+='<div class="gy-explain" id="gyExp">'+q.a+'</div>';
  html+='<div style="text-align:center"><button class="gy-next" id="gyNext" onclick="nextQ()">Sonraki &#10145;</button></div>';
  html+='</div>';
  document.getElementById('gyQuiz').innerHTML=html;
  document.getElementById('gyBar').style.width=(current/TOTAL*100)+'%';
  document.getElementById('gyProg').textContent=(current)+' / '+TOTAL;
  answered=false;
}}

function selectOpt(idx){{
  if(answered) return;
  startGyTimer();
  answered=true;
  const q=QS[current];
  const correct=q.d;
  // Tum optionlari disable et
  for(let i=0;i<q.o.length;i++){{
    const el=document.getElementById('gyO'+i);
    el.classList.add('disabled');
    if(i===correct) el.classList.add('correct');
  }}
  const badge=document.getElementById('gyBadge');
  if(idx===correct){{
    score++;
    if(!catScores[q.k]) catScores[q.k]={{ok:0,total:0}};
    catScores[q.k].ok++;
    badge.innerHTML='&#10004; DO\u011eRU!';
    badge.className='gy-result-badge show badge-correct';
  }}else{{
    document.getElementById('gyO'+idx).classList.add('wrong');
    badge.innerHTML='&#10008; YANLI\u015e! Do\u011fru cevap: '+LETTERS[correct];
    badge.className='gy-result-badge show badge-wrong';
  }}
  if(!catScores[q.k]) catScores[q.k]={{ok:0,total:0}};
  catScores[q.k].total++;
  document.getElementById('gyExp').classList.add('show');
  document.getElementById('gyNext').classList.add('show');
}}

function nextQ(){{
  current++;
  renderQ();
}}

function showResult(){{
  if(gyTimer) clearInterval(gyTimer);
  const pct=Math.round(score/TOTAL*100);
  const m=String(Math.floor(gySec/60)).padStart(2,'0');
  const s=String(gySec%60).padStart(2,'0');
  let emoji=pct>=80?'&#127942;':pct>=60?'&#128170;':pct>=40?'&#128077;':'&#128218;';
  let bdown='';
  for(const[cat,val] of Object.entries(catScores)){{
    const clr=CAT_CLR[cat]?CAT_CLR[cat][0]:'#475569';
    bdown+='<div class="gy-br-item" style="background:'+clr+'">'+cat+': '+val.ok+'/'+val.total+'</div>';
  }}
  document.getElementById('gyQuiz').innerHTML='';
  const res=document.getElementById('gyResult');
  res.className='gy-result show';
  res.innerHTML='<h3>'+emoji+' Test Tamamlandı!</h3>'
    +'<div class="gy-score">'+score+' / '+TOTAL+' ('+pct+'%)</div>'
    +'<div class="gy-breakdown">'+bdown+'</div>'
    +'<div class="gy-timer">&#9201; Süre: '+m+':'+s+'</div>';
  document.getElementById('gyBar').style.width='100%';
  document.getElementById('gyProg').textContent=TOTAL+' / '+TOTAL;
}}
renderQ();
</script>
</body></html>"""


