# ── AI ile dinamik soru üretimi (GK + GY ortak altyapı) ──────────────────────

def _ensure_env_for_quiz():
    """OpenAI API key'i .env'den yükle."""
    if os.environ.get("OPENAI_API_KEY"):
        return
    env_path = os.path.join(
        os.path.dirname(os.path.dirname(os.path.abspath(__file__))), ".env"
    )
    if os.path.exists(env_path):
        with open(env_path, encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith("#") and "=" in line:
                    k, v = line.split("=", 1)
                    os.environ[k.strip()] = v.strip().strip('"').strip("'")


def _get_quiz_ai_client():
    """OpenAI client oluştur (quiz modülü için)."""
    _ensure_env_for_quiz()
    api_key = os.environ.get("OPENAI_API_KEY", "")
    if not api_key:
        return None
    try:
        from openai import OpenAI
        return OpenAI(api_key=api_key)
    except Exception:
        return None


def _generate_gk_ai_quiz(count: int = 10, kategori: str = "Karışık") -> list[dict] | None:
    """OpenAI ile dinamik GK soruları üret."""
    client = _get_quiz_ai_client()
    if client is None:
        return None

    kat_prompt = ""
    if kategori != "Karışık":
        kat_prompt = f"Tüm sorular '{kategori}' kategorisinden olsun."
    else:
        kat_prompt = "Sorular şu kategorilerden karışık olsun: Tarih, Coğrafya, Bilim, Edebiyat, Spor, Türkiye."

    prompt = f"""Türk eğitim müfredatına uygun, eğlenceli {count} adet genel kültür sorusu üret.
{kat_prompt}

Her soru için şu JSON formatını kullan:
{{"k": "Kategori", "s": "Soru metni?", "o": ["A şıkkı", "B şıkkı", "C şıkkı", "D şıkkı"], "d": 0, "a": "Kısa açıklama"}}

Kurallar:
- "d" alanı doğru cevabın 0-3 arası indeksi
- "a" alanı eğlenceli ve bilgilendirici olsun ("Bunu biliyor muydun?" tarzı)
- Sorular çoktan seçmeli, 4 şık
- Zorluk: orta-kolay (lise seviyesi)
- Cevaplar SADECE JSON dizisi olsun, başka metin ekleme

Çıktı formatı: [{{"k":...}}, {{"k":...}}, ...]"""

    try:
        resp = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": "Sen deneyimli bir Türk eğitimcisin. Sadece JSON formatında cevap ver."},
                {"role": "user", "content": prompt},
            ],
            max_tokens=2048,
            temperature=0.8,
        )
        raw = resp.choices[0].message.content.strip()
        # JSON dizisini parse et
        if raw.startswith("```"):
            raw = raw.split("\n", 1)[1].rsplit("```", 1)[0].strip()
        questions = _json.loads(raw)
        # Doğrulama
        valid = []
        for q in questions:
            if all(k in q for k in ("k", "s", "o", "d", "a")) and len(q["o"]) == 4 and isinstance(q["d"], int) and 0 <= q["d"] <= 3:
                valid.append(q)
        return valid if valid else None
    except Exception:
        return None


def _generate_gy_ai_quiz(count: int = 10, kategori: str = "Karışık") -> list[dict] | None:
    """OpenAI ile dinamik GY (Genel Yetenek) soruları üret."""
    client = _get_quiz_ai_client()
    if client is None:
        return None

    kat_prompt = ""
    if kategori != "Karışık":
        kat_prompt = f"Tüm sorular '{kategori}' kategorisinden olsun."
    else:
        kat_prompt = "Sorular şu kategorilerden karışık olsun: Sayısal Mantık, Sözel Mantık, Seri Tamamlama, Analoji, Şekil-Örüntü."

    prompt = f"""Türk eğitim müfredatına uygun {count} adet genel yetenek sorusu üret.
{kat_prompt}

Her soru için şu JSON formatını kullan:
{{"k": "Kategori", "s": "Soru metni?", "o": ["A şıkkı", "B şıkkı", "C şıkkı", "D şıkkı"], "d": 0, "a": "Çözüm açıklaması"}}

Kurallar:
- "d" alanı doğru cevabın 0-3 arası indeksi
- Sayısal Mantık: dört işlem, oran, yüzde, yaş problemleri
- Sözel Mantık: anlam, neden-sonuç, çıkarım
- Seri Tamamlama: sayı/harf dizileri
- Analoji: X:Y :: Z:? ilişki soruları
- Şekil-Örüntü: metin tabanlı örüntü soruları (ASCII/sayı matrisi)
- Cevaplar SADECE JSON dizisi olsun

Çıktı formatı: [{{"k":...}}, {{"k":...}}, ...]"""

    try:
        resp = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": "Sen deneyimli bir Türk eğitimcisin. Sadece JSON formatında cevap ver."},
                {"role": "user", "content": prompt},
            ],
            max_tokens=2048,
            temperature=0.8,
        )
        raw = resp.choices[0].message.content.strip()
        if raw.startswith("```"):
            raw = raw.split("\n", 1)[1].rsplit("```", 1)[0].strip()
        questions = _json.loads(raw)
        valid = []
        for q in questions:
            if all(k in q for k in ("k", "s", "o", "d", "a")) and len(q["o"]) == 4 and isinstance(q["d"], int) and 0 <= q["d"] <= 3:
                valid.append(q)
        return valid if valid else None
    except Exception:
        return None


