def _build_shbb_html(letter: str, answers: dict, countdown: int) -> str:
    """Şehir-Hayvan-Bitki-Başkent interaktif HTML+CSS+JS."""
    ans_json = _json.dumps(answers, ensure_ascii=False)

    categories = [
        ("sehir", "&#127961; Şehir", "#2563eb", "#1d4ed8"),
        ("hayvan", "&#128062; Hayvan", "#059669", "#047857"),
        ("bitki", "&#127807; Bitki", "#65a30d", "#4d7c0f"),
        ("baskent", "&#127963; Başkent", "#dc2626", "#b91c1c"),
    ]

    input_cards = ""
    for key, label, c1, c2 in categories:
        examples = ", ".join(answers.get(key, [])[:3])
        input_cards += f"""
<div class="sh-card">
  <div class="sh-card-label" style="background:linear-gradient(135deg,{c1},{c2})">{label}</div>
  <input type="text" id="sh_{key}" class="sh-inp" placeholder="{letter} ile başlayan..."
         autocomplete="off" spellcheck="false">
  <div class="sh-examples" id="shex_{key}" style="display:none">
    &#128218; Örnekler: {examples}</div>
</div>"""

    return f"""
<!DOCTYPE html><html lang="tr"><head><meta charset="utf-8">
<style>
*{{margin:0;padding:0;box-sizing:border-box}}
body{{font-family:'Segoe UI',system-ui,sans-serif;background:transparent;
      display:flex;flex-direction:column;align-items:center;padding:6px 0}}
.sh-header{{text-align:center;margin-bottom:6px}}
.sh-header h2{{font-size:1.15rem;color:#1e293b;font-weight:700}}
.sh-letter-wrap{{display:flex;justify-content:center;margin:10px 0}}
.sh-letter{{width:85px;height:85px;border-radius:50%;
    background:linear-gradient(135deg,#6366f1,#8b5cf6,#4f46e5);color:#fff;
    display:flex;align-items:center;justify-content:center;
    font-size:2.5rem;font-weight:800;box-shadow:0 8px 28px rgba(99,102,241,.45),0 0 40px rgba(99,102,241,.15);
    animation:shPulse 1.5s ease-in-out infinite alternate;
    text-shadow:0 2px 8px rgba(0,0,0,.2);border:2px solid rgba(255,255,255,.15)}}
@keyframes shPulse{{0%{{transform:scale(1);box-shadow:0 8px 28px rgba(99,102,241,.45)}}100%{{transform:scale(1.08);box-shadow:0 12px 36px rgba(99,102,241,.55)}}}}
.sh-timer-wrap{{display:flex;align-items:center;gap:10px;justify-content:center;margin:8px 0}}
.sh-timer-bar{{width:240px;height:10px;background:#e2e8f0;border-radius:5px;overflow:hidden}}
.sh-timer-fill{{height:100%;background:linear-gradient(90deg,#4472C4,#6366f1);
    border-radius:5px;transition:width .3s linear}}
.sh-timer-text{{font-size:.85rem;font-weight:700;color:#475569;min-width:50px}}
.sh-cards{{display:flex;flex-direction:column;gap:10px;width:100%;max-width:380px;margin:8px auto}}
.sh-card{{background:#fff;border-radius:12px;padding:12px 16px;
    box-shadow:0 3px 12px rgba(0,0,0,.06);border:1px solid #e2e8f0;transition:all .3s ease}}
.sh-card-label{{display:inline-block;padding:4px 12px;border-radius:8px;color:#fff;
    font-size:.78rem;font-weight:700;margin-bottom:6px;box-shadow:0 2px 6px rgba(0,0,0,.1)}}
.sh-inp{{width:100%;height:40px;border:2px solid #cbd5e1;border-radius:10px;
    padding:0 14px;font-size:1rem;font-weight:600;color:#1e293b;outline:none;
    transition:all .2s ease;text-transform:uppercase}}
.sh-inp:focus{{border-color:#6366f1;box-shadow:0 0 0 3px rgba(99,102,241,.15),0 0 12px rgba(99,102,241,.08)}}
.sh-inp:disabled{{background:#1A2035;color:#94a3b8}}
.sh-examples{{font-size:.75rem;color:#64748b;margin-top:4px}}
.sh-card.sh-ok{{border-color:#34d399;background:linear-gradient(135deg,#f0fdf4,#ecfdf5);
    box-shadow:0 2px 12px rgba(52,211,153,.12);animation:shCardPulse .3s ease}}
.sh-card.sh-ok .sh-inp{{color:#059669;border-color:#34d399}}
.sh-card.sh-err{{border-color:#f87171;background:linear-gradient(135deg,#fef2f2,#fee2e2);
    animation:shCardShake .3s ease}}
.sh-card.sh-err .sh-inp{{color:#dc2626;border-color:#f87171}}
.sh-card.sh-half{{border-color:#fbbf24;background:linear-gradient(135deg,#fffbeb,#fef3c7)}}
.sh-card.sh-half .sh-inp{{color:#d97706;border-color:#fbbf24}}
@keyframes shCardPulse{{0%{{transform:scale(1)}}50%{{transform:scale(1.01)}}100%{{transform:scale(1)}}}}
@keyframes shCardShake{{0%,100%{{transform:translateX(0)}}25%{{transform:translateX(-3px)}}75%{{transform:translateX(3px)}}}}
.sh-btn-row{{display:flex;gap:10px;margin-top:12px;justify-content:center}}
.sh-btn{{padding:10px 24px;border:none;border-radius:10px;font-size:.9rem;
    font-weight:600;cursor:pointer;transition:all .2s ease}}
.sh-btn:active{{transform:scale(.95)}}
.sh-btn:hover{{transform:translateY(-1px)}}
.sh-btn-submit{{background:linear-gradient(135deg,#4472C4,#1e3a5f);color:#fff;
    box-shadow:0 4px 16px rgba(68,114,196,.35)}}
.sh-btn-submit:hover{{box-shadow:0 6px 24px rgba(68,114,196,.5)}}
.sh-btn-submit:disabled{{opacity:.5;cursor:not-allowed;transform:none}}
.sh-result{{margin-top:10px;padding:12px 20px;border-radius:10px;font-weight:600;
    font-size:.95rem;text-align:center;display:none;animation:shFadeIn .4s ease}}
@keyframes shFadeIn{{from{{opacity:0;transform:scale(.95)}}to{{opacity:1;transform:scale(1)}}}}
.sh-result.show{{display:block;background:linear-gradient(135deg,#1A2035,#e8eef5);color:#1e293b;
    border:1px solid #cbd5e1;box-shadow:0 4px 16px rgba(0,0,0,.06)}}
.sh-score{{font-size:1.4rem;color:#6366f1;font-weight:800;margin-bottom:4px;
    text-shadow:0 2px 8px rgba(99,102,241,.15)}}
</style></head><body>
<div class="sh-header"><h2>&#127961; Şehir — Hayvan — Bitki — Başkent</h2></div>
<div class="sh-letter-wrap"><div class="sh-letter">{letter}</div></div>
<div class="sh-timer-wrap">
  <div class="sh-timer-bar"><div class="sh-timer-fill" id="shFill" style="width:100%"></div></div>
  <div class="sh-timer-text" id="shTime">{countdown}s</div>
</div>
<div class="sh-cards">{input_cards}</div>
<div class="sh-btn-row">
  <button class="sh-btn sh-btn-submit" id="shSubmit" onclick="shSubmit()">&#9989; Cevapla</button>
</div>
<div class="sh-result" id="shResult"></div>

<script>
const LETTER='{letter}';
const ANSWERS={ans_json};
const COUNTDOWN={countdown};
const CATS=['sehir','hayvan','bitki','baskent'];
const TR_UP={{"ı":"I","i":"İ","ö":"Ö","ü":"Ü","ç":"Ç","ş":"Ş","ğ":"Ğ"}};

function trUpper(s){{
  let r='';
  for(let c of s){{ r+=(TR_UP[c]||c.toUpperCase()); }}
  return r;
}}

let timeLeft=COUNTDOWN,timerInt=null,submitted=false;

function startTimer(){{
  timerInt=setInterval(()=>{{
    timeLeft--;
    document.getElementById('shTime').textContent=timeLeft+'s';
    document.getElementById('shFill').style.width=(timeLeft/COUNTDOWN*100)+'%';
    if(timeLeft<=10) document.getElementById('shFill').style.background='linear-gradient(90deg,#dc2626,#ef4444)';
    if(timeLeft<=0){{clearInterval(timerInt);shSubmit();}}
  }},1000);
}}

// İlk input'a focus olunca timer başlasın
document.querySelectorAll('.sh-inp').forEach(inp=>{{
  inp.addEventListener('focus',()=>{{if(!timerInt&&!submitted) startTimer();}});
}});

function shSubmit(){{
  if(submitted) return;
  submitted=true;
  if(timerInt) clearInterval(timerInt);
  document.getElementById('shSubmit').disabled=true;
  let totalScore=0;
  CATS.forEach(cat=>{{
    const inp=document.getElementById('sh_'+cat);
    const card=inp.closest('.sh-card');
    const exDiv=document.getElementById('shex_'+cat);
    inp.disabled=true;
    const val=trUpper(inp.value.trim());
    const valid=ANSWERS[cat]||[];

    if(!val){{
      card.classList.add('sh-err');
    }} else if(val.charAt(0)!==LETTER){{
      card.classList.add('sh-err');
    }} else {{
      const inDB=valid.some(v=>trUpper(v)===val);
      if(inDB){{
        card.classList.add('sh-ok');
        totalScore+=10;
      }} else {{
        card.classList.add('sh-half');
        totalScore+=5;
      }}
    }}
    exDiv.style.display='block';
  }});
  const res=document.getElementById('shResult');
  res.className='sh-result show';
  const elapsed=COUNTDOWN-Math.max(timeLeft,0);
  res.innerHTML='<div class="sh-score">'+totalScore+' / 40 Puan</div>'
    +'<div style="font-size:.82rem;color:#64748b">Süre: '+elapsed+'s &nbsp;|&nbsp; '
    +'&#128994; DB eşleşme = 10p &nbsp; &#128993; Doğru harf = 5p &nbsp; &#128308; Yanlış/Boş = 0p</div>';
}}
startTimer();
</script>
</body></html>"""


