# ══════════════════════════════════════════════════════════════════════════════
# HTML BUILDER FONKSİYONLARI
# ══════════════════════════════════════════════════════════════════════════════

def _build_resource_grid(resources: tuple, columns: int = 3, badge: str = "") -> str:
    """Tıklanabilir kart grid HTML'i üret."""
    parts = [
        f'<div style="display:grid;grid-template-columns:repeat({columns},1fr);'
        f'gap:12px;margin-bottom:16px;">'
    ]
    for ad, aciklama, link, r1, r2, rt in resources:
        badge_html = (
            f'<div style="font-size:11px;position:absolute;top:8px;left:12px;'
            f'background:rgba(255,255,255,0.2);color:white;border-radius:8px;'
            f'padding:1px 8px;">{badge}</div>'
        ) if badge else ""
        parts.append(
            f'<a href="{link}" target="_blank" rel="noopener" style="text-decoration:none;">'
            f'<div style="background:linear-gradient(135deg,{r1},{r2});border-radius:14px;'
            f'padding:22px 18px;text-align:center;position:relative;cursor:pointer;'
            f'min-height:90px;display:flex;flex-direction:column;justify-content:center;'
            f'transition:transform 0.15s,box-shadow 0.15s;">'
            f'{badge_html}'
            f'<div style="font-size:18px;font-weight:800;color:white;letter-spacing:0.5px;'
            f'margin-top:{"8px" if badge else "0"};">{ad}</div>'
            f'<div style="color:{rt};font-size:11px;margin-top:6px;">{aciklama}</div>'
            f'</div></a>'
        )
    parts.append("</div>")
    return "".join(parts)


def _build_video_konferans_grid(platforms: tuple) -> str:
    """Video konferans kartları — 'Giriş Yap' butonu ile."""
    parts = [
        '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-bottom:16px;">'
    ]
    for ad, aciklama, link, r1, r2, rt in platforms:
        parts.append(
            f'<a href="{link}" target="_blank" rel="noopener" style="text-decoration:none;">'
            f'<div style="background:linear-gradient(135deg,{r1},{r2});border-radius:14px;'
            f'padding:24px 18px;text-align:center;min-height:110px;display:flex;flex-direction:column;'
            f'justify-content:center;cursor:pointer;transition:transform 0.15s,box-shadow 0.15s;">'
            f'<div style="font-size:20px;font-weight:800;color:white;letter-spacing:0.5px;">{ad}</div>'
            f'<div style="color:{rt};font-size:11px;margin-top:6px;line-height:1.4;">{aciklama}</div>'
            f'<div style="margin-top:12px;background:rgba(255,255,255,0.22);color:white;'
            f'border-radius:20px;padding:5px 16px;font-size:12px;font-weight:700;'
            f'display:inline-block;letter-spacing:0.5px;">Giriş Yap →</div>'
            f'</div></a>'
        )
    parts.append("</div>")
    return "".join(parts)


# ── Pre-build HTML cache ──
_HTML_VIDEO_KONFERANS = _build_video_konferans_grid(_VIDEO_KONFERANS)
_HTML_EGITIM_PLATFORMLARI = _build_resource_grid(_EGITIM_PLATFORMLARI, 3)
_HTML_KODLAMA = _build_resource_grid(_KODLAMA_INTERAKTIF, 4)
_HTML_YT_YABANCI_DIL = _build_resource_grid(_YT_YABANCI_DIL, 3, "▶ YouTube")


