# KADEME İÇERİK FİLTRELEME
# ══════════════════════════════════════════════════════════════════════════════

def _get_platformlar_for_kademe(kademe: str) -> tuple:
    if kademe == "okul_oncesi":
        return tuple(p for p in _EGITIM_PLATFORMLARI if p[0] in ("EBA",))
    elif kademe == "ilkokul":
        return tuple(
            p for p in _EGITIM_PLATFORMLARI
            if p[0] in ("EBA", "Khan Akademi", "e-Okul YD", "MEBi", "OGDM Materyal")
        )
    else:
        return _EGITIM_PLATFORMLARI


def _get_kodlama_for_kademe(kademe: str) -> tuple:
    if kademe == "okul_oncesi":
        return _KODLAMA_OKUL_ONCESI
    if kademe == "ilkokul":
        return _KODLAMA_ILKOKUL
    return _KODLAMA_INTERAKTIF


