# YOUTUBE SECTION RENDERER
# ══════════════════════════════════════════════════════════════════════════════

def _render_youtube_section(kademe: str):
    """Kademe'ye özel YouTube kanalları grid."""
    if kademe == "okul_oncesi":
        styled_section("🎬 Türkçe — Çizgi Film / Şarkı / Masal", "#dc2626")
        st.markdown(_build_resource_grid(_YT_OKUL_ONCESI_TR, 4, "▶ YouTube"), unsafe_allow_html=True)
        styled_section("👩\u200d🏫 Türkçe — Etkinlik / Öğretmen Kanalları", "#2563eb")
        st.markdown(_build_resource_grid(_YT_OKUL_ONCESI_OGRETMEN, 3, "▶ YouTube"), unsafe_allow_html=True)
        styled_section("💻 Eğlenceli Bilim Kanalları", "#f57c00")
        st.markdown(_build_resource_grid(_YT_OKUL_ONCESI_KODLAMA, 4, "▶ YouTube"), unsafe_allow_html=True)
        styled_section("🌍 İngilizce — Eğitsel Kanallar", "#7c3aed")
        st.markdown(_build_resource_grid(_YT_OKUL_ONCESI_EN, 4, "▶ YouTube"), unsafe_allow_html=True)
    elif kademe == "ilkokul":
        styled_section("🎓 İlkokul (1-4) Kanalları", "#dc2626")
        st.markdown(_build_resource_grid(_YT_ILKOKUL, 3, "▶ YouTube"), unsafe_allow_html=True)
        styled_section("💻 Eğlenceli Bilim Kanalları", "#f57c00")
        st.markdown(_build_resource_grid(_YT_ILKOKUL_KODLAMA, 4, "▶ YouTube"), unsafe_allow_html=True)
    elif kademe == "ortaokul":
        styled_section("🎓 Ortaokul (5-8) Kanalları", "#2563eb")
        st.markdown(_build_resource_grid(_YT_ORTAOKUL, 3, "▶ YouTube"), unsafe_allow_html=True)
        styled_section("📚 LGS Ücretsiz Kanallar", "#dc2626")
        st.markdown(_build_resource_grid(_YT_LGS_UCRETSIZ, 3, "▶ YouTube"), unsafe_allow_html=True)
    elif kademe == "lise":
        styled_section("🎓 Lise (9-12) Kanalları", "#0891b2")
        st.markdown(_build_resource_grid(_YT_LISE, 3, "▶ YouTube"), unsafe_allow_html=True)
        styled_section("📚 YKS Ücretsiz Kanallar", "#dc2626")
        st.markdown(_build_resource_grid(_YT_YKS_UCRETSIZ, 3, "▶ YouTube"), unsafe_allow_html=True)
    elif kademe == "tum":
        for label, data in [
            ("🎒 Okul Öncesi — Türkçe", _YT_OKUL_ONCESI_TR),
            ("🎒 Okul Öncesi — Bilişim & Kodlama", _YT_OKUL_ONCESI_KODLAMA),
            ("🎒 Okul Öncesi — İngilizce", _YT_OKUL_ONCESI_EN),
            ("📕 İlkokul (1-4)", _YT_ILKOKUL),
            ("📕 İlkokul — Bilişim & Kodlama", _YT_ILKOKUL_KODLAMA),
            ("📗 Ortaokul (5-8)", _YT_ORTAOKUL),
            ("📗 LGS Ücretsiz", _YT_LGS_UCRETSIZ),
            ("📘 Lise (9-12)", _YT_LISE),
            ("📘 YKS Ücretsiz", _YT_YKS_UCRETSIZ),
        ]:
            styled_section(label, "#dc2626")
            st.markdown(_build_resource_grid(data, 3, "▶ YouTube"), unsafe_allow_html=True)


