def _render_hikayeler_section(key_prefix: str):
    """MEB 365 Gün Öykü hikayelerini flipbook olarak gösterir."""
    styled_info_banner(
        "MEB Temel Eğitim Genel Müdürlüğü tarafından hazırlanan sesli ve interaktif hikayeler. "
        "Bir hikaye seçin ve okumaya başlayın!",
        "info",
    )

    hikaye_isimleri = [h[0] for h in _MEB_365_HIKAYELER]
    secilen = st.selectbox(
        "📖 Hikaye Seç",
        hikaye_isimleri,
        key=f"{key_prefix}_hikaye_sel",
    )
    hikaye_id = next(h[1] for h in _MEB_365_HIKAYELER if h[0] == secilen)
    url = f"https://cdn.eba.gov.tr/icerik/365GunOyku/{hikaye_id}/"

    st.components.v1.html(
        f'''<iframe src="{url}" width="100%" height="750"
             style="border:none;border-radius:12px;box-shadow:0 4px 24px rgba(0,0,0,0.15);"
             allowfullscreen></iframe>''',
        height=770,
        scrolling=False,
    )


