def _render_dikkat_oyunlari(key_prefix: str):
    """Dikkat oyunlarını kart şeklinde gösterir."""
    styled_info_banner(
        "Sınıfta oynayabileceğiniz dikkat, konsantrasyon ve gözlem becerisi geliştiren 16 etkinlik. "
        "Bir oyun seçin ve açıklamasını okuyun!",
        "info",
    )
    secilen = st.selectbox(
        "🎯 Oyun Seç",
        [o[0] for o in _DIKKAT_OYUNLARI],
        key=f"{key_prefix}_dikkat_oyun_sel",
    )
    aciklama = next(o[1] for o in _DIKKAT_OYUNLARI if o[0] == secilen)
    st.markdown(
        f"""<div style="background:linear-gradient(135deg,#f0f4ff,#e8f0fe);border-radius:16px;
        padding:24px 28px;margin-top:12px;border-left:5px solid #4f46e5;
        box-shadow:0 2px 12px rgba(79,70,229,0.10);">
        <h3 style="margin:0 0 12px 0;color:#4f46e5;">🎯 {secilen}</h3>
        <p style="font-size:15px;line-height:1.8;color:#1e293b;margin:0;white-space:pre-line;">{aciklama}</p>
        <p style="font-size:12px;color:#94a3b8;margin-top:12px;">
        Kaynak: acevokuloncesi.org — Dikkat Oyunları</p>
        </div>""",
        unsafe_allow_html=True,
    )


