def _render_sinif_etkinligi(oyunlar: list[tuple[str, str]], key_prefix: str, renk: str, kaynak: str):
    """Sınıf etkinlik oyunlarını kart şeklinde gösterir."""
    secilen = st.selectbox(
        "🎯 Oyun Seç",
        [o[0] for o in oyunlar],
        key=f"{key_prefix}_oyun_sel",
    )
    aciklama = next(o[1] for o in oyunlar if o[0] == secilen)
    st.markdown(
        f"""<div style="background:linear-gradient(135deg,#f0f4ff,#e8f0fe);border-radius:16px;
        padding:24px 28px;margin-top:12px;border-left:5px solid {renk};
        box-shadow:0 2px 12px rgba(0,0,0,0.08);">
        <h3 style="margin:0 0 12px 0;color:{renk};">🎯 {secilen}</h3>
        <p style="font-size:15px;line-height:1.8;color:#1e293b;margin:0;white-space:pre-line;">{aciklama}</p>
        <p style="font-size:12px;color:#94a3b8;margin-top:12px;">
        Kaynak: {kaynak}</p>
        </div>""",
        unsafe_allow_html=True,
    )


