def _render_yyegm_hikayeler(kitaplar: list[tuple[str, str]], key_prefix: str):
    """YYEGM hikaye kitaplarını iframe ile gösterir."""
    styled_info_banner(
        "MEB Yurtdışı Türkler ve Akraba Topluluklar Başkanlığı tarafından hazırlanan interaktif hikaye kitapları.",
        "info",
    )
    secilen = st.selectbox(
        "📖 Kitap Seç",
        [k[0] for k in kitaplar],
        key=f"{key_prefix}_yyegm_sel",
    )
    url = next(k[1] for k in kitaplar if k[0] == secilen)
    st.components.v1.html(
        f'''<iframe src="{url}" width="100%" height="750"
             style="border:none;border-radius:12px;box-shadow:0 4px 24px rgba(0,0,0,0.15);"
             allowfullscreen></iframe>''',
        height=770,
        scrolling=False,
    )


