# KADEME TAB RENDERER
# ══════════════════════════════════════════════════════════════════════════════

def _render_kademe_tab(kademe: str, store: DijitalKutuphaneDataStore):
    """Tek bir kademe sekmesini render et — tüm bölümler."""
    r1, r2, label = _KADEME_RENKLER[kademe]
    ikon = _KADEME_IKONLAR[kademe]
    admin_kaynaklar = store.get_kaynaklar_by_kademe(kademe)
    toplam = _toplam_kaynak(kademe, len(admin_kaynaklar))
    ks = _KAYNAK_SAYILARI.get(kademe, {})

    # ── Premium Header ──
    styled_header(
        f"Dijital Kütüphane — {label}",
        f"{toplam} dijital kaynak mevcut",
        icon=ikon,
    )

    # ── Stat Row ──
    styled_stat_row([
        ("Platform", str(ks.get("platform", 0)), _CLR_BLUE, "🌐"),
        ("YouTube", str(ks.get("youtube", 0)), _CLR_RED, "▶"),
        ("Canlı Ders", str(ks.get("konferans", 0)), _CLR_PURPLE, "📹"),
        ("Kodlama", str(ks.get("kodlama", 0)), _CLR_ORANGE, "💻"),
        ("Toplam", str(toplam), "#0369a1", "📊"),
    ])

    # ── 1. Canlı Ders Platformları ──
    with st.expander("📹 Canlı Ders Platformları (Zoom, Teams, Classroom, Meet)", expanded=False):
        styled_info_banner(
            "Öğretmeniniz canlı ders linki paylaştığında aşağıdaki platformlardan giriş yapabilirsiniz.",
            "info",
        )
        st.markdown(_HTML_VIDEO_KONFERANS, unsafe_allow_html=True)

    # ── 2. Eğitim Platformları ──
    platformlar = _get_platformlar_for_kademe(kademe)
    with st.expander(f"🌐 Eğitim Platformları ({len(platformlar)} platform)", expanded=False):
        st.markdown(_build_resource_grid(platformlar, 3), unsafe_allow_html=True)

    # ── 3. YouTube Kanalları ──
    with st.expander(f"▶ YouTube Eğitim Kanalları ({ks.get('youtube', 0)} kanal)", expanded=False):
        _render_youtube_section(kademe)

    # ── 4. Kodlama & İnteraktif ──
    kodlama = _get_kodlama_for_kademe(kademe)
    if kodlama:
        lbl = "Bilişim & Kodlama Platformları" if kademe in ("okul_oncesi", "ilkokul") else "Kodlama & İnteraktif Platformlar"
        with st.expander(f"💻 {lbl} ({len(kodlama)} araç)", expanded=False):
            styled_info_banner(
                "Kodlama ve interaktif araçlarla öğrenmeyi eğlenceli hale getirin.",
                "info",
            )
            st.markdown(_build_resource_grid(kodlama, 4), unsafe_allow_html=True)

    # ── 5. Yabancı Dil ──
    if kademe in ("ortaokul", "lise", "tum"):
        with st.expander("🌍 Yabancı Dil Kanalları (3 kanal)", expanded=False):
            st.markdown(_HTML_YT_YABANCI_DIL, unsafe_allow_html=True)

    # ── 6. Okul Öncesi Dijital İçerikler ──
    if kademe == "okul_oncesi":
        render_okul_oncesi_dijital_icerik("dk")

    # ── 6b. İlkokul Dijital İçerikler ──
    if kademe == "ilkokul":
        render_ilkokul_dijital_icerik("dk")

    # ── 7. Yönetici Eklenen Kaynaklar ──
    if admin_kaynaklar:
        with st.expander(f"📌 Yönetici Eklenen Kaynaklar ({len(admin_kaynaklar)})", expanded=False):
            admin_tuples = tuple(
                (k.baslik, k.aciklama, k.url, k.renk1, k.renk2, "#ffffff")
                for k in admin_kaynaklar
            )
            st.markdown(_build_resource_grid(admin_tuples, 3), unsafe_allow_html=True)


