cx.fillStyle='rgba(255,255,255,0.12)';
cx.beginPath();cx.arc(TX+TW*0.27,TY+TH*0.25,2,0,Math.PI*2);cx.fill();
cx.beginPath();cx.arc(TX+TW*0.27,TY+TH*0.75,2,0,Math.PI*2);cx.fill();
cx.beginPath();cx.arc(TX+TW*0.33,TY+TH/2,2,0,Math.PI*2);cx.fill();
