def _render_air_hockey_game():
    """Havali Hokey oyunu renderer."""
    col1, col2, col3 = st.columns([2, 2, 6])
    with col1:
        difficulty = st.selectbox(
            "Zorluk",
            ["Kolay", "Normal", "Zor", "Uzman"],
            index=1,
            key="ahk_diff",
        )
    with col2:
        win_score = st.selectbox(
            "Kazanma Skoru",
            [5, 7, 10],
            index=1,
            key="ahk_wscore",
        )

    html = _build_air_hockey_html(difficulty, win_score)
    _diamond_game_html(html, height=720, scrolling=False)

    styled_info_banner(
        "Mavi tokmagi **mouse/parmak** ile surukle! "
        "**PRO:** Slam mekanigi (hizli hareket), 4 power-up (Buyuk/Hiz/Dondur/Kucultu), "
        "Kombo sistemi, detayli istatistikler. "
        "Ilk **" + str(win_score) + "** sayiya ulasan kazanir!",
        "info",
    )


