        '    }\n'
        '    cx.restore();\n'
        '  }\n'
        '}\n'
        '\n'
        'function drawPowerups(){\n'
        '  var icons={hp:"\\u2764",fuel:"\\u26FD",shield:"\\u{1F6E1}",rapid:"\\u26A1"};\n'
        '  var clrs={hp:"#00ff60",fuel:"#00bbff",shield:"#8888ff",rapid:"#ffdd00"};\n'
        '  for(var i=0;i<powerups.length;i++){\n'
        '    var pw=powerups[i];\n'
        '    var py2=pw.y+Math.sin(pw.t*4)*6;\n'
        '    cx.save();\n'
        '    cx.shadowColor=clrs[pw.type];cx.shadowBlur=14;\n'
        '    /* outer glow ring */\n'
        '    var pulse=0.5+0.5*Math.sin(pw.t*6);\n'
        '    cx.globalAlpha=0.2+0.15*pulse;\n'
        '    cx.strokeStyle=clrs[pw.type];cx.lineWidth=2;\n'
        '    cx.beginPath();cx.arc(pw.x,py2,14+pulse*3,0,6.28);cx.stroke();\n'
        '    /* bg circle */\n'
        '    cx.globalAlpha=0.85;\n'
        '    var pg=cx.createRadialGradient(pw.x,py2,2,pw.x,py2,12);\n'
