        '    cx.fillStyle=pg;\n'
        '    cx.beginPath();cx.arc(pw.x,py2,11,0,6.28);cx.fill();\n'
        '    /* icon */\n'
        '    cx.globalAlpha=1;\n'
        '    cx.font="12px Segoe UI Emoji,sans-serif";cx.textAlign="center";cx.textBaseline="middle";\n'
        '    cx.fillText(icons[pw.type],pw.x,py2+1);\n'
        '    cx.restore();\n'
        '  }\n'
        '}\n'
        '\n'
        'function drawFloats(){\n'
        '  for(var i=0;i<floats.length;i++){\n'
