        '\n'
        'function drawHUD(){\n'
        '  /* top HUD bar */\n'
        '  cx.save();\n'
        '  var topBg=cx.createLinearGradient(0,0,0,48);\n'
        '  topBg.addColorStop(0,"rgba(0,8,20,0.92)");topBg.addColorStop(1,"rgba(0,8,20,0)");\n'
        '  cx.fillStyle=topBg;cx.fillRect(0,0,W,48);\n'
        '\n'
        '  cx.textBaseline="middle";cx.font="bold 13px Segoe UI,sans-serif";\n'
        '  /* score */\n'
        '  cx.textAlign="left";\n'
        '  cx.fillStyle="#0fa";cx.fillText("SKOR",14,12);\n'
        '  cx.font="bold 16px Segoe UI,sans-serif";\n'
        '  cx.fillText(score,14,30);\n'
        '\n'
        '  /* level */\n'
        '  cx.font="bold 13px Segoe UI,sans-serif";\n'
        '  cx.fillStyle="#ff0";cx.fillText("SEV."+level,100,12);\n'
        '  cx.fillStyle="rgba(255,255,0,0.4)";cx.fillText("Imha: "+kills,100,30);\n'
        '\n'
        '  /* HP hearts */\n'
        '  cx.textAlign="right";cx.font="14px Segoe UI Emoji,sans-serif";\n'
        '  for(var i=0;i<P.maxHp;i++){\n'
        '    cx.globalAlpha=i<P.hp?1:0.2;\n'
        '    cx.fillText("\\u2764",W-10-i*20,14);\n'
        '  }\n'
        '  cx.globalAlpha=1;\n'
        '\n'
        '  /* fuel bar */\n'
        '  var fbx=W-170,fby=28,fbw=155,fbh=8;\n'
        '  cx.fillStyle="rgba(0,0,0,0.5)";cx.beginPath();cx.roundRect(fbx-1,fby-1,fbw+2,fbh+2,4);cx.fill();\n'
        '  var fRatio=P.fuel/P.maxFuel;\n'
        '  var fClr=fRatio>0.4?"#00bbff":(fRatio>0.2?"#ffaa00":"#ff3030");\n'
        '  if(fuelWarn&&Math.floor(tm/8)%2===0)fClr="#ff0000";\n'
        '  var fg=cx.createLinearGradient(fbx,fby,fbx+fbw*fRatio,fby);\n'
        '  fg.addColorStop(0,fClr);fg.addColorStop(1,fClr.replace("ff","88"));\n'
        '  cx.fillStyle=fg;cx.beginPath();cx.roundRect(fbx,fby,fbw*fRatio,fbh,3);cx.fill();\n'
        '  cx.font="bold 9px Segoe UI,sans-serif";cx.textAlign="right";\n'
        '  cx.fillStyle="rgba(200,220,255,0.6)";cx.fillText("YAKIT",fbx-5,fby+6);\n'
        '\n'
        '  /* boost/dodge cooldown indicators */\n'
        '  cx.textAlign="left";cx.font="10px Segoe UI,sans-serif";\n'
        '  cx.fillStyle=P.boostCd<=0?"rgba(100,200,255,0.8)":"rgba(100,100,100,0.4)";\n'
        '  cx.fillText("[SHIFT] Boost"+(P.boost?" ON":""),14,H-12);\n'
        '  cx.fillStyle=P.dodgeCd<=0?"rgba(255,200,80,0.8)":"rgba(100,100,100,0.4)";\n'
        '  cx.fillText("[Q/E] Kacis",140,H-12);\n'
        '  if(P.shield>0){cx.fillStyle="rgba(130,130,255,0.8)";cx.fillText("Kalkan: "+Math.ceil(P.shield)+"s",260,H-12);}\n'
        '\n'
        '  /* combo */\n'
        '  if(P.combo>1){\n'
        '    cx.textAlign="center";cx.font="bold 20px Segoe UI,sans-serif";\n'
        '    cx.globalAlpha=0.3+0.3*Math.sin(tm*0.15);\n'
        '    cx.fillStyle="#ffd700";cx.fillText("x"+P.combo+" COMBO",W/2,H-14);\n'
        '    cx.globalAlpha=1;\n'
        '  }\n'
        '  cx.restore();\n'
        '\n'
        '  /* start screen */\n'
        '  if(!started){\n'
        '    cx.save();\n'
        '    cx.fillStyle="rgba(0,0,0,0.7)";cx.fillRect(0,0,W,H);\n'
        '    /* title glow */\n'
        '    cx.shadowColor="rgba(0,200,255,0.5)";cx.shadowBlur=30;\n'
        '    cx.font="bold 36px Segoe UI,sans-serif";cx.textAlign="center";cx.textBaseline="middle";\n'
        '    cx.fillStyle="#4ac8ff";cx.fillText("ATARI UCAK",W/2,H/2-60);\n'
        '    cx.shadowBlur=0;\n'
        '    cx.font="14px Segoe UI,sans-serif";cx.fillStyle="#88bbdd";\n'
        '    cx.fillText("DIAMOND EDITION",W/2,H/2-32);\n'
        '\n'
        '    cx.font="13px Segoe UI,sans-serif";cx.fillStyle="#aaa";\n'
        '    cx.fillText("Baslamak icin SPACE veya TIKLA",W/2,H/2+10);\n'
        '    cx.font="11px Segoe UI,sans-serif";cx.fillStyle="#667";\n'
        '    cx.fillText("W/A/S/D: Hareket | Space: Ates | Shift: Boost",W/2,H/2+35);\n'
        '    cx.fillText("Q/E: Saga-Sola Kacis | Yakit topla, hayatta kal!",W/2,H/2+52);\n'
        '    if(hiScore>0){cx.fillStyle="#ffd700";cx.fillText("En Yuksek Skor: "+hiScore,W/2,H/2+75);}\n'
        '    cx.restore();\n'
        '  }\n'
        '\n'
        '  /* game over */\n'
        '  if(gameOver){\n'
        '    cx.save();\n'
        '    cx.fillStyle="rgba(0,0,0,0.75)";\n'
        '    cx.beginPath();cx.roundRect(W/2-185,H/2-85,370,175,16);cx.fill();\n'
        '    cx.strokeStyle="rgba(255,60,60,0.4)";cx.lineWidth=2;\n'
        '    cx.beginPath();cx.roundRect(W/2-185,H/2-85,370,175,16);cx.stroke();\n'
        '    cx.textAlign="center";cx.textBaseline="middle";\n'
        '    cx.shadowColor="rgba(255,60,60,0.4)";cx.shadowBlur=15;\n'
        '    cx.font="bold 26px Segoe UI,sans-serif";cx.fillStyle="#ff4444";\n'
        '    cx.fillText("OYUN BITTI",W/2,H/2-60);\n'
        '    cx.shadowBlur=0;\n'
        '    cx.font="bold 18px Segoe UI,sans-serif";cx.fillStyle="#ffd700";\n'
        '    cx.fillText("Skor: "+score,W/2,H/2-35);\n'
        '    cx.font="12px Segoe UI,sans-serif";cx.fillStyle="#aaddff";\n'
        '    var acc=totalShots>0?Math.round(totalHits/totalShots*100):0;\n'
        '    cx.fillText("Seviye: "+level+"  |  Imha: "+kills+"  |  Boss: "+bossKills,W/2,H/2-12);\n'
