def _render_canli_radyo():
    """Canli Radyo sekmesi — Zeka Oyunları tarzı kart grid + tekli oynatıcı."""

    # 10 garantili çalışan istasyon (Karnaval / streamtheworld AAC)
    radyolar = [
        ("⭐", "Süper FM", "Pop",
         "https://playerservices.streamtheworld.com/api/livestream-redirect/SUPER_FMAAC.aac"),
        ("🎶", "Virgin Radio", "Pop",
         "https://playerservices.streamtheworld.com/api/livestream-redirect/VIRGIN_RADIOAAC.aac"),
        ("🎸", "Metro FM", "Pop",
         "https://playerservices.streamtheworld.com/api/livestream-redirect/METRO_FM128AAC.aac"),
        ("😊", "Joy Türk", "Türk Müzik",
         "https://playerservices.streamtheworld.com/api/livestream-redirect/JOY_TURKAAC.aac"),
        ("🎸", "Joy Türk Akustik", "Türk Müzik",
         "https://playerservices.streamtheworld.com/api/livestream-redirect/JOYTURK_AKUSTIK128AAC.aac"),
        ("📼", "Retro Türk", "Türk Müzik",
         "https://playerservices.streamtheworld.com/api/livestream-redirect/RETROTURK128AAC.aac"),
        ("🤘", "Joy Türk Rock", "Rock",
         "https://playerservices.streamtheworld.com/api/livestream-redirect/JOYTURK_ROCK128AAC.aac"),
        ("🌈", "Başka Radyo", "Rock",
         "https://playerservices.streamtheworld.com/api/livestream-redirect/BASKA_SC"),
        ("🎻", "Borusan Klasik", "Klasik",
         "https://playerservices.streamtheworld.com/api/livestream-redirect/BORUSAN_KLASIKAAC.aac"),
        ("⛰️", "Karadeniz Radyo", "Özel",
         "https://playerservices.streamtheworld.com/api/livestream-redirect/KARADENIZ128AAC.aac"),
    ]

    styled_header(
        "Canlı Radyo",
        "Karnaval.com radyoları — canlı dinle",
        icon="📻",
    )

    styled_stat_row([
        ("İstasyon", "10", "#7c3aed", "📻"),
        ("Kategori", "5", "#2563eb", "🏷️"),
        ("Kalite", "HD", "#059669", "🔊"),
        ("Kaynak", "Karnaval.com", "#dc2626", "🌐"),
    ])

    styled_info_banner(
        "Bir radyo istasyonu seçin. "
        "Bazı istasyonlar tarayıcı politikaları nedeniyle doğrudan çalmayabilir.",
        "info",
    )

    # ── Aktif radyo seçili mi? ──
    active = st.session_state.get("_dk_active_radio")
    if active is not None and 0 <= active < len(radyolar):
        ikon, isim, kat, url = radyolar[active]
        if st.button("⬅ Radyo Listesine Dön", key="dk_radyo_back"):
            del st.session_state["_dk_active_radio"]
            st.rerun()
        styled_section(f"{ikon} {isim}  —  {kat}")
        # Minimal HTML5 audio player
        player_html = (
            "<!DOCTYPE html><html><head><meta charset='utf-8'>"
            "<style>"
            "*{margin:0;padding:0;box-sizing:border-box}"
            "body{font-family:'Segoe UI',system-ui,sans-serif;background:#111827;"
            "display:flex;flex-direction:column;align-items:center;padding:24px}"
            ".card{background:linear-gradient(135deg,#1e1b4b,#312e81,#4c1d95);"
            "border-radius:20px;padding:32px 40px;text-align:center;color:#fff;"
            "box-shadow:0 8px 32px rgba(30,27,75,.35);max-width:420px;width:100%}"
            ".icon{font-size:56px;margin-bottom:12px}"
            ".name{font-size:22px;font-weight:700;color:#e9d5ff;margin-bottom:4px}"
            ".cat{font-size:13px;color:#a78bfa;margin-bottom:16px}"
            ".live{display:inline-flex;align-items:center;gap:6px;font-size:12px;"
            "color:#4ade80;margin-bottom:16px}"
            ".live .dot{width:8px;height:8px;border-radius:50%;background:#ef4444;"
            "animation:pulse 1s ease infinite}"
            "@keyframes pulse{0%,100%{box-shadow:0 0 0 0 rgba(239,68,68,.5)}"
            "50%{box-shadow:0 0 0 6px rgba(239,68,68,0)}}"
            "audio{width:100%;margin-top:8px;filter:hue-rotate(250deg)}"
            ".credit{margin-top:12px;font-size:11px;color:#94a3b8}"
            ".credit a{color:#7c3aed;text-decoration:none;font-weight:600}"
            "</style></head><body>"
            "<div class='card'>"
            f"<div class='icon'>{ikon}</div>"
            f"<div class='name'>{isim}</div>"
            f"<div class='cat'>{kat}</div>"
            "<div class='live'><span class='dot'></span> CANLI YAYIN</div>"
            f"<audio controls autoplay src='{url}' style='width:100%'></audio>"
            "</div>"
            "<div class='credit'>Kaynak: <a href='https://karnaval.com' target='_blank'>Karnaval.com</a></div>"
            "</body></html>"
        )
        _diamond_game_html(player_html, height=320, scrolling=False)
        return

    # ── Kart Grid — 5 sütun ──
    styled_section("Bir radyo istasyonu seçin")
    cols_per_row = 5
    for row_start in range(0, len(radyolar), cols_per_row):
        cols = st.columns(cols_per_row)
        for j, col in enumerate(cols):
            idx = row_start + j
            if idx >= len(radyolar):
                break
            ikon, isim, kat, _url = radyolar[idx]
            with col:
                if st.button(f"{ikon}\n{isim}\n({kat})", key=f"dk_radyo_{idx}", use_container_width=True):
                    st.session_state["_dk_active_radio"] = idx
                    st.rerun()






