# ══════════════════════════════════════════════════════════════════════════════
# SANAL YANARDAG LABORATUVARI
# ══════════════════════════════════════════════════════════════════════════════


def _build_volcano_html() -> str:
    """Ultra premium interaktif yanardağ simülasyonu."""
    return """<!DOCTYPE html>
<html><head><meta charset="utf-8"><style>
*{margin:0;padding:0;box-sizing:border-box}
body{background:#1a0a00;overflow:hidden;font-family:'Segoe UI',system-ui,sans-serif;user-select:none}
canvas{display:block;width:100%;height:100vh}
#ui{position:fixed;top:10px;left:10px;z-index:10;display:flex;gap:6px;flex-wrap:wrap;max-width:70%}
.btn{padding:6px 12px;border-radius:16px;border:1px solid rgba(255,100,0,.25);background:rgba(40,10,0,.8);
color:#ffb070;font-size:11px;font-weight:600;cursor:pointer;backdrop-filter:blur(8px);transition:all .2s}
.btn:hover{background:rgba(80,20,0,.7);border-color:rgba(255,150,50,.5)}
.btn.active{background:rgba(150,40,0,.5);border-color:#ff6a00}
#panel{position:fixed;top:10px;right:10px;z-index:10;background:rgba(30,5,0,.85);border:1px solid rgba(255,100,0,.15);
border-radius:14px;padding:12px 16px;backdrop-filter:blur(8px);color:#cc8860;font-size:11px;min-width:160px}
#panel .v{color:#ffb070;font-weight:700;font-size:13px}
#panel .hot{color:#ff4400}#panel .warm{color:#ff8c00}#panel .cool{color:#66aa66}
#info{position:fixed;bottom:10px;left:50%;transform:translateX(-50%);z-index:10;background:rgba(30,5,0,.9);
border:1px solid rgba(255,100,0,.15);border-radius:14px;padding:10px 18px;backdrop-filter:blur(8px);
color:#ffb070;font-size:12px;text-align:center;display:none;max-width:500px}
</style></head><body>
<div id="ui">
  <button class="btn" onclick="addPressure(10)">🔥 Basinc+</button>
  <button class="btn" onclick="addPressure(-10)">❄ Basinc-</button>
  <button class="btn" onclick="triggerEruption()">🌋 Patlat!</button>
  <button class="btn" onclick="cycleType()">🏔 Tur Degistir</button>
  <button class="btn" onclick="toggleCrossSection()">🔍 Kesit</button>
  <button class="btn" onclick="triggerEarthquake()">💥 Deprem</button>
  <button class="btn" onclick="toggleTsunami()">🌊 Tsunami</button>
  <button class="btn" onclick="toggleLabels()">🏷 Etiketler</button>
  <button class="btn" onclick="toggleHeatMap()">🌡 Isi Haritasi</button>
  <button class="btn" onclick="showInfoCard('magma')">📖 Magma</button>
  <button class="btn" onclick="showInfoCard('pyroclastic')">📖 Piroklastik</button>
  <button class="btn" onclick="showInfoCard('lahar')">📖 Lahar</button>
  <button class="btn" onclick="showInfoCard('tectonic')">📖 Tektonik</button>
</div>
<div id="panel"></div>
<div id="info"></div>
<canvas id="cv"></canvas>
<script>
(function(){
"use strict";
const cv=document.getElementById('cv'),C=cv.getContext('2d');
let W,H;
function resize(){W=cv.width=window.innerWidth;H=cv.height=window.innerHeight;}
resize();window.addEventListener('resize',resize);

// ══════ STATE ══════
let pressure=25,maxPressure=100,magmaTemp=900,lavaLevel=0;
let erupting=false,eruptionIntensity=0,eruptionTimer=0;
let volcanoType=0;const VTYPES=['Kalkan','Stratovulkan','Supervulkan'];
const VCOLORS=[['#4a3a2a','#5a4a3a','#6a5a4a'],['#3a3a3a','#4a4a4a','#5a5a5a'],['#2a2a1a','#3a3a2a','#4a4a3a']];
const VSHAPES=[[.15,.6],[.35,.55],[.12,.7]]; // steepness, width
let crossSection=false,showLabels=true;
let earthquakeShake=0,earthquakeWave=[];
let tsunamiActive=false,tsunamiWave=0,tsunamiHeight=0;
let particles=[],lavaFlows=[],ashClouds=[],rocks=[],smoke=[];
let pyroclasticFlows=[],lahars=[],volcanicBombs=[];
let t=0,starsArr=[],heatMap=false;
let infoCards={
  magma:{title:'Magma Odasi',text:'Yer kabugunun altinda eriyen kayacin toplandigi bolge. Sicaklik 700-1300°C arasi. Basinc artisyla magma yukselir.'},
  conduit:{title:'Magma Kanali',text:'Magma odasindan kratere uzanan boru seklinde kanal. Magma burada yukselirken gaz kaybeder.'},
  pyroclastic:{title:'Piroklastik Akis',text:'800°C sicakliginda gaz, kul ve kaya parcalarindan olusan olumcul akis. Saatte 700 km hiza ulasir.'},
  lahar:{title:'Lahar',text:'Volkanik camur akintisi. Kar/buz erimesi veya yagmurla tetiklenir. Beton gibi donar.'},
  tsunami:{title:'Volkanik Tsunami',text:'Deniz altindaki patlamalar veya yamac cokmeleri dev dalgalar olusturur. 1883 Krakatoa tsunamisi 30m yukseklige ulasti.'},
  tectonic:{title:'Tektonik Plakalar',text:'Yer kabugunun hareketli parcalari. Dalma-batma (subduksiyon) zonlarinda volkanlar olusur.'}
};
let activeInfo=null;

// Stars
for(let i=0;i<120;i++){
  starsArr.push({x:Math.random()*2000,y:Math.random()*300,r:.5+Math.random()*1.5,b:Math.random()});
}

// ══════ CONTROLS ══════
window.addPressure=function(d){
  pressure=Math.max(0,Math.min(maxPressure,pressure+d));
  magmaTemp=800+pressure*6;
  updatePanel();
};
window.triggerEruption=function(){
  if(pressure<30){showMsg('Basinc cok dusuk! En az 30 gerekli.');return;}
  erupting=true;eruptionIntensity=pressure/maxPressure;eruptionTimer=200+pressure*3;
  // Pyroclastic particles
  let count=20+pressure*2|0;
  for(let i=0;i<count;i++){
    particles.push({
      x:W/2+(Math.random()-.5)*20,y:H*.42,
      vx:(Math.random()-.5)*8*eruptionIntensity,
      vy:-4-Math.random()*12*eruptionIntensity,
      size:2+Math.random()*5,life:100+Math.random()*200,
      type:Math.random()>.3?'lava':'rock',
      glow:Math.random()
    });
  }
  // Ash cloud
  for(let i=0;i<8;i++){
    ashClouds.push({
      x:W/2+(Math.random()-.5)*40,y:H*.38-Math.random()*30,
      vx:(Math.random()-.5)*3,vy:-1-Math.random()*2,
      size:20+Math.random()*40,life:300+Math.random()*200,
      opacity:.6+Math.random()*.3
    });
  }
  // Lava flows
  for(let i=0;i<3+Math.random()*3;i++){
    let side=Math.random()>.5?1:-1;
    lavaFlows.push({
      x:W/2+side*(Math.random()*15),y:H*.42,
      vx:side*(.5+Math.random()*1.5),vy:.5+Math.random(),
      points:[],life:400+Math.random()*200,width:3+Math.random()*4
    });
  }
  // Pyroclastic flows (ground-hugging hot gas+debris)
  if(pressure>50){
    for(let i=0;i<2;i++){
      let side=i===0?-1:1;
      pyroclasticFlows.push({x:W/2+side*20,y:H*.43,vx:side*(3+eruptionIntensity*5),vy:.3,
        particles:[],life:250+Math.random()*150,size:15+Math.random()*20});
    }
  }
  // Volcanic bombs (large projectiles)
  for(let i=0;i<3+eruptionIntensity*5|0;i++){
    volcanicBombs.push({x:W/2+(Math.random()-.5)*10,y:H*.4,
      vx:(Math.random()-.5)*10*eruptionIntensity,vy:-8-Math.random()*10*eruptionIntensity,
      size:4+Math.random()*6,life:200,rotation:Math.random()*6.28,rotSpeed:.1+Math.random()*.2,
      trail:[]});
  }
  // Lahar (mudflow)
  if(pressure>60){
    lahars.push({x:W/2-30,y:H*.5,vx:-2-Math.random()*2,vy:1+Math.random(),
      points:[],life:350,width:8+Math.random()*6,color:'#5a3a20'});
    lahars.push({x:W/2+30,y:H*.5,vx:2+Math.random()*2,vy:1+Math.random(),
      points:[],life:350,width:8+Math.random()*6,color:'#5a3a20'});
  }
  pressure=Math.max(5,pressure-pressure*.6);
  magmaTemp=800+pressure*6;
  updatePanel();
};
window.cycleType=function(){
  volcanoType=(volcanoType+1)%3;
  showMsg(VTYPES[volcanoType]+' Yanardagi secildi');
  updatePanel();
};
window.toggleCrossSection=function(){crossSection=!crossSection;updatePanel();};
window.triggerEarthquake=function(){
  earthquakeShake=40;
  earthquakeWave=[];
  for(let i=0;i<5;i++){
    earthquakeWave.push({x:W/2,y:H*.85,r:10+i*30,life:60+i*15,speed:3+i});
  }
  pressure=Math.min(maxPressure,pressure+15);
  magmaTemp=800+pressure*6;
  showMsg('Deprem! Basinc artti: '+pressure.toFixed(0));
  updatePanel();
};
window.toggleTsunami=function(){
  if(!tsunamiActive){tsunamiActive=true;tsunamiWave=0;tsunamiHeight=0;showMsg('Tsunami tetiklendi!');}
};
window.toggleLabels=function(){showLabels=!showLabels;};
window.toggleHeatMap=function(){heatMap=!heatMap;};
window.showInfoCard=function(key){
  let info=infoCards[key];if(!info)return;
  let el=document.getElementById('info');
  el.innerHTML='<b style="color:#ff8c00;font-size:14px">'+info.title+'</b><br>'+info.text;
  el.style.display='block';
  setTimeout(function(){el.style.display='none';},6000);
};

function showMsg(txt){
  let el=document.getElementById('info');
  el.textContent=txt;el.style.display='block';
  setTimeout(function(){el.style.display='none';},3000);
}

// ══════ UPDATE PANEL ══════
function updatePanel(){
  let el=document.getElementById('panel');
  let pC=pressure>70?'hot':pressure>40?'warm':'cool';
  let tC=magmaTemp>1100?'hot':magmaTemp>900?'warm':'cool';
  el.innerHTML=
    '<div style="margin-bottom:4px;font-weight:700;color:#ff6a00;font-size:12px">🌋 Yanardlag</div>'+
    '<div>🏔 Tur: <span class="v">'+VTYPES[volcanoType]+'</span></div>'+
    '<div>🔥 Basinc: <span class="v '+pC+'">'+pressure.toFixed(0)+'/'+maxPressure+'</span></div>'+
    '<div>🌡 Magma: <span class="v '+tC+'">'+magmaTemp.toFixed(0)+'°C</span></div>'+
    '<div>💨 Durum: <span class="v">'+(erupting?'PATLAMA!':'Beklemede')+'</span></div>'+
    '<div>🔍 Kesit: '+(crossSection?'Acik':'Kapali')+'</div>'+
    (pressure>70?'<div style="color:#ff4400;font-size:10px;margin-top:3px">⚠ Kritik basinc!</div>':'');
}

// ══════ DRAW SKY ══════
function drawSky(){
  let skyG=C.createLinearGradient(0,0,0,H*.5);
  if(erupting&&eruptionIntensity>.5){
    skyG.addColorStop(0,'#1a0000');skyG.addColorStop(.5,'#3a1000');skyG.addColorStop(1,'#5a2a10');
  }else{
    skyG.addColorStop(0,'#0a0a1a');skyG.addColorStop(.3,'#1a1a3a');skyG.addColorStop(.7,'#2a1a2a');skyG.addColorStop(1,'#4a2a1a');
  }
  C.fillStyle=skyG;C.fillRect(0,0,W,H*.6);
  // Stars
  if(!erupting||eruptionIntensity<.3){
    for(let s of starsArr){
      C.globalAlpha=.3+Math.sin(t*.02+s.b*10)*.2;
      C.fillStyle='#fff';C.beginPath();C.arc(s.x%W,s.y,s.r,0,6.283);C.fill();
    }
    C.globalAlpha=1;
  }
}

// ══════ DRAW GROUND ══════
function drawGround(){
  let gG=C.createLinearGradient(0,H*.7,0,H);
  gG.addColorStop(0,'#2a1a0a');gG.addColorStop(.5,'#1a1008');gG.addColorStop(1,'#0a0804');
  C.fillStyle=gG;C.fillRect(0,H*.65,W,H*.35);
  // Grass/terrain texture
  C.fillStyle='rgba(40,60,20,.15)';
  for(let i=0;i<30;i++){
    let gx=i*(W/30)+Math.sin(i*3.7)*10,gy=H*.68+Math.sin(i*2.1)*8;
    C.beginPath();C.ellipse(gx,gy,8+Math.random()*5,3,0,0,6.283);C.fill();
  }
}

// ══════ DRAW VOLCANO ══════
function drawVolcano(){
  let cx=W/2,baseY=H*.7,peakY=H*.4;
  let steep=VSHAPES[volcanoType][0];
  let wide=VSHAPES[volcanoType][1]*W*.4;
  let colors=VCOLORS[volcanoType];

  // Mountain body
  let mG=C.createLinearGradient(cx-wide,baseY,cx,peakY);
  mG.addColorStop(0,colors[2]);mG.addColorStop(.5,colors[1]);mG.addColorStop(1,colors[0]);
  C.fillStyle=mG;
  C.beginPath();
  C.moveTo(cx-wide,baseY);
  C.bezierCurveTo(cx-wide*.6,baseY-steep*H*.5,cx-20,peakY+10,cx-15,peakY);
  C.lineTo(cx+15,peakY);
  C.bezierCurveTo(cx+20,peakY+10,cx+wide*.6,baseY-steep*H*.5,cx+wide,baseY);
  C.closePath();C.fill();

  // Snow cap (for Strato)
  if(volcanoType===1){
    C.fillStyle='rgba(220,230,240,.3)';
    C.beginPath();C.moveTo(cx-25,peakY+15);C.lineTo(cx-15,peakY);C.lineTo(cx+15,peakY);
    C.lineTo(cx+25,peakY+15);C.closePath();C.fill();
  }

  // Crater
  C.fillStyle=erupting?'rgba(255,100,0,.8)':'rgba(60,30,10,.9)';
  C.beginPath();C.ellipse(cx,peakY+2,18,6,0,0,6.283);C.fill();
  // Crater glow
  if(pressure>30||erupting){
    let glow=erupting?eruptionIntensity:pressure/maxPressure*.4;
    C.globalAlpha=glow;
    let crG=C.createRadialGradient(cx,peakY,5,cx,peakY,60);
    crG.addColorStop(0,'rgba(255,100,0,.6)');crG.addColorStop(.5,'rgba(255,50,0,.2)');crG.addColorStop(1,'rgba(255,0,0,0)');
    C.fillStyle=crG;C.beginPath();C.arc(cx,peakY,60,0,6.283);C.fill();
    C.globalAlpha=1;
  }

  // Smoke from crater
  if(pressure>20||erupting){
    let smokeCount=erupting?5:2;
    if(Math.random()<.15*smokeCount){
      smoke.push({x:cx+(Math.random()-.5)*10,y:peakY-5,
        vx:(Math.random()-.5)*1,vy:-1-Math.random()*2*(erupting?2:1),
        size:5+Math.random()*10,life:80+Math.random()*60,
        opacity:.3+Math.random()*.2});
    }
  }
}

// ══════ DRAW CROSS SECTION ══════
function drawCrossSection(){
  if(!crossSection)return;
  let cx=W/2,baseY=H*.7,peakY=H*.4;
  let mBright=pressure/maxPressure;
  C.globalAlpha=.88;

  // ─── EARTH LAYERS (from bottom) ───
  // Inner core hint
  C.fillStyle='#8a2a00';C.fillRect(cx-150,H*.95,300,H*.05);
  // Outer mantle
  let mantleG=C.createLinearGradient(cx,baseY,cx,H);
  mantleG.addColorStop(0,'#3a1500');mantleG.addColorStop(.3,'#5a2000');
  mantleG.addColorStop(.6,'#6a2a00');mantleG.addColorStop(1,'#8a3500');
  C.fillStyle=mantleG;
  C.beginPath();C.moveTo(cx-180,baseY);C.lineTo(cx-130,H);C.lineTo(cx+130,H);C.lineTo(cx+180,baseY);C.closePath();C.fill();
  // Crust layer
  C.fillStyle='rgba(80,60,40,.6)';
  C.beginPath();C.moveTo(cx-180,baseY);C.lineTo(cx-175,baseY+18);C.lineTo(cx+175,baseY+18);C.lineTo(cx+180,baseY);C.closePath();C.fill();
  // Layer boundary lines
  C.strokeStyle='rgba(255,200,100,.1)';C.lineWidth=1;C.setLineDash([4,6]);
  C.beginPath();C.moveTo(cx-170,baseY+18);C.lineTo(cx+170,baseY+18);C.stroke(); // crust/mantle
  C.beginPath();C.moveTo(0,H*.88);C.lineTo(W,H*.88);C.stroke(); // deep mantle
  C.setLineDash([]);

  // ─── MAGMA CHAMBER (primary) ───
  let magmaG=C.createRadialGradient(cx,H*.8,8,cx,H*.8,65+mBright*20);
  magmaG.addColorStop(0,'rgba(255,'+(180+mBright*75|0)+',50,'+(0.7+mBright*.3)+')');
  magmaG.addColorStop(.4,'rgba(255,'+(100+mBright*80|0)+',0,'+(0.5+mBright*.3)+')');
  magmaG.addColorStop(.7,'rgba(200,50,0,.35)');magmaG.addColorStop(1,'rgba(100,20,0,.1)');
  C.fillStyle=magmaG;
  C.beginPath();C.ellipse(cx,H*.8,60+mBright*18,38+mBright*12,0,0,6.283);C.fill();
  // Convection currents in magma
  C.strokeStyle='rgba(255,200,80,'+(0.15+mBright*.2)+')';C.lineWidth=1.5;
  for(let i=0;i<3;i++){
    let angle=t*.008+i*2.1;
    let rx=25+i*10,ry=15+i*6;
    C.beginPath();
    for(let a=0;a<6.283;a+=.2){
      let px=cx+Math.cos(a+angle)*rx,py=H*.8+Math.sin(a+angle)*ry;
      a===0?C.moveTo(px,py):C.lineTo(px,py);
    }
    C.stroke();
  }

  // ─── SECONDARY MAGMA POCKET ───
  let sg=C.createRadialGradient(cx-70,H*.75,3,cx-70,H*.75,25);
  sg.addColorStop(0,'rgba(255,150,30,.5)');sg.addColorStop(1,'rgba(180,40,0,.1)');
  C.fillStyle=sg;C.beginPath();C.ellipse(cx-70,H*.75,22,14,.3,0,6.283);C.fill();

  // ─── MAGMA CONDUIT (main pipe) ───
  let condW=10+mBright*6;
  let condG=C.createLinearGradient(cx-condW,0,cx+condW,0);
  condG.addColorStop(0,'rgba(180,30,0,'+(0.2+mBright*.3)+')');
  condG.addColorStop(.5,'rgba(255,'+(100+mBright*100|0)+',0,'+(0.4+mBright*.4)+')');
  condG.addColorStop(1,'rgba(180,30,0,'+(0.2+mBright*.3)+')');
  C.fillStyle=condG;
  C.beginPath();C.moveTo(cx-condW*.8,peakY+6);C.lineTo(cx-condW,H*.78);
  C.lineTo(cx+condW,H*.78);C.lineTo(cx+condW*.8,peakY+6);C.closePath();C.fill();

  // ─── SILL (horizontal intrusion) ───
  C.fillStyle='rgba(220,80,10,'+(0.2+mBright*.15)+')';
  C.beginPath();
  C.moveTo(cx-10,H*.65);C.bezierCurveTo(cx-50,H*.64,cx-80,H*.65,cx-90,H*.66);
  C.lineTo(cx-90,H*.67);C.bezierCurveTo(cx-80,H*.67,cx-50,H*.66,cx-10,H*.66);
  C.closePath();C.fill();

  // ─── DIKE (angled intrusion) ───
  C.save();C.translate(cx+30,H*.68);C.rotate(.6);
  C.fillStyle='rgba(200,70,10,'+(0.15+mBright*.1)+')';
  C.fillRect(-3,-40,6,80);C.restore();

  // ─── MAGMA BUBBLES rising in conduit ───
  for(let i=0;i<6;i++){
    let by=peakY+25+i*((H*.78-peakY)/7)+Math.sin(t*.06+i*1.3)*8;
    let bx=cx+(Math.sin(t*.04+i*2.5))*condW*.5;
    let br=2+Math.sin(t*.12+i)*1.2;
    C.fillStyle='rgba(255,220,80,'+(0.3+mBright*.35)+')';
    C.beginPath();C.arc(bx,by,br,0,6.283);C.fill();
    // Gas bubble glow
    C.fillStyle='rgba(255,255,150,'+(0.1+mBright*.15)+')';
    C.beginPath();C.arc(bx,by-br*.3,br*.5,0,6.283);C.fill();
  }

  // ─── OLD LAVA LAYERS in mountain body ───
  C.globalAlpha=.25;
  for(let i=0;i<5;i++){
    let ly=peakY+20+i*((baseY-peakY)/6);
    let lw=15+i*25;
    C.strokeStyle=i%2===0?'#5a2a1a':'#4a3a2a';C.lineWidth=2;
    C.beginPath();C.moveTo(cx-lw,ly);
    C.bezierCurveTo(cx-lw*.5,ly-3,cx+lw*.5,ly+3,cx+lw,ly);
    C.stroke();
  }
  C.globalAlpha=.88;

  // ─── GROUNDWATER TABLE ───
  C.strokeStyle='rgba(60,120,200,.2)';C.lineWidth=1.5;C.setLineDash([3,4]);
  let gwY=baseY+8;
  C.beginPath();C.moveTo(cx-160,gwY);
  for(let x=cx-160;x<cx+160;x+=5){C.lineTo(x,gwY+Math.sin(x*.03+t*.01)*2);}
  C.stroke();C.setLineDash([]);

  // ─── TECTONIC PLATES ───
  C.strokeStyle='rgba(255,180,100,.12)';C.lineWidth=2;
  C.beginPath();C.moveTo(0,H*.88);C.lineTo(W,H*.88);C.stroke();
  // Subduction arrows
  C.fillStyle='rgba(255,180,100,.15)';
  for(let i=0;i<3;i++){
    let ax=cx-100+i*100,ay=H*.88;
    C.beginPath();C.moveTo(ax,ay);C.lineTo(ax-8,ay+10);C.lineTo(ax+8,ay+10);C.closePath();C.fill();
  }
  C.globalAlpha=1;

  // ─── LABELS ───
  if(showLabels){
    C.font='bold 11px Segoe UI';C.textAlign='center';
    C.fillStyle='#ffcc80';
    C.fillText('MAGMA ODASI',cx,H*.85);
    C.font='10px Segoe UI';
    C.fillStyle='#ffb070';
    C.fillText('Ana Kanal (Conduit)',cx+condW+40,H*.62);
    C.fillText('Krater',cx,peakY-10);
    C.fillText('Sill (Yatay Sokulum)',cx-65,H*.63);
    C.fillText('Dayk',cx+55,H*.65);
    C.fillText('Yer Alti Suyu',cx+100,gwY-5);
    C.fillText('Yan Magma Cebi',cx-70,H*.73);
    C.fillStyle='rgba(255,200,100,.35)';
    C.fillText('KABUK (Crust)',cx-130,baseY+12);
    C.fillText('MANTO (Mantle)',cx-130,H*.88-5);
    C.fillStyle='rgba(100,80,60,.5)';
    C.font='9px Segoe UI';
    for(let i=0;i<5;i++){
      let ly=peakY+20+i*((baseY-peakY)/6);
      C.fillText('Lav Katmani '+(5-i),cx+40+i*12,ly-3);
    }
    // Temperature gradient indicator
    C.font='9px Segoe UI';C.textAlign='right';
    C.fillStyle='#ff6644';C.fillText('~1200°C',cx+125,H*.82);
    C.fillStyle='#ff9944';C.fillText('~800°C',cx+125,H*.72);
    C.fillStyle='#cc6644';C.fillText('~400°C',cx+125,baseY+5);
  }
}

// ══════ DRAW PARTICLES ══════
function drawParticles(){
  for(let i=particles.length-1;i>=0;i--){
    let p=particles[i];
    p.vy+=.12; // gravity
    p.x+=p.vx;p.y+=p.vy;p.life--;
    if(p.life<=0||p.y>H){particles.splice(i,1);continue;}
    let a=Math.min(1,p.life/40);
    if(p.type==='lava'){
      C.shadowColor='#ff4400';C.shadowBlur=8*p.glow;
      C.fillStyle='rgba(255,'+(100+p.glow*100|0)+',0,'+a+')';
    }else{
      C.shadowBlur=0;
      C.fillStyle='rgba(80,60,40,'+a+')';
    }
    C.beginPath();C.arc(p.x,p.y,p.size,0,6.283);C.fill();
    C.shadowBlur=0;
  }
}

// ══════ DRAW LAVA FLOWS ══════
function drawLavaFlows(){
  for(let i=lavaFlows.length-1;i>=0;i--){
    let lf=lavaFlows[i];
    lf.x+=lf.vx;lf.y+=lf.vy;lf.life--;
    lf.points.push({x:lf.x,y:lf.y});
    if(lf.points.length>80)lf.points.shift();
    if(lf.life<=0||lf.y>H*.85){lavaFlows.splice(i,1);continue;}
    // Draw flowing lava trail
    if(lf.points.length<2)continue;
    C.strokeStyle='rgba(255,80,0,'+(lf.life/400*.7)+')';
    C.lineWidth=lf.width;C.lineCap='round';C.lineJoin='round';
    C.shadowColor='#ff4400';C.shadowBlur=10;
    C.beginPath();C.moveTo(lf.points[0].x,lf.points[0].y);
    for(let j=1;j<lf.points.length;j++){C.lineTo(lf.points[j].x,lf.points[j].y);}
    C.stroke();
    // Bright core
    C.strokeStyle='rgba(255,200,50,'+(lf.life/400*.4)+')';C.lineWidth=lf.width*.4;C.shadowBlur=0;
    C.beginPath();C.moveTo(lf.points[0].x,lf.points[0].y);
    for(let j=1;j<lf.points.length;j++){C.lineTo(lf.points[j].x,lf.points[j].y);}
    C.stroke();C.shadowBlur=0;
  }
}

// ══════ DRAW ASH CLOUDS ══════
function drawAshClouds(){
  for(let i=ashClouds.length-1;i>=0;i--){
    let ac=ashClouds[i];
    ac.x+=ac.vx;ac.y+=ac.vy;ac.size+=.3;ac.life--;ac.opacity-=.001;
    if(ac.life<=0||ac.opacity<=0){ashClouds.splice(i,1);continue;}
    C.globalAlpha=ac.opacity*(ac.life/300);
    let acG=C.createRadialGradient(ac.x,ac.y,ac.size*.2,ac.x,ac.y,ac.size);
    acG.addColorStop(0,'rgba(80,70,60,.5)');acG.addColorStop(.5,'rgba(60,50,40,.3)');acG.addColorStop(1,'rgba(40,30,20,0)');
    C.fillStyle=acG;C.beginPath();C.arc(ac.x,ac.y,ac.size,0,6.283);C.fill();
    C.globalAlpha=1;
  }
}

// ══════ DRAW SMOKE ══════
function drawSmoke(){
  for(let i=smoke.length-1;i>=0;i--){
    let s=smoke[i];
    s.x+=s.vx+Math.sin(t*.02+i)*.3;s.y+=s.vy;s.size+=.2;s.life--;s.opacity-=.003;
    if(s.life<=0||s.opacity<=0){smoke.splice(i,1);continue;}
    C.globalAlpha=s.opacity*(s.life/100);
    C.fillStyle='rgba(100,90,80,.3)';
    C.beginPath();C.arc(s.x,s.y,s.size,0,6.283);C.fill();
    C.globalAlpha=1;
  }
}

// ══════ PYROCLASTIC FLOWS ══════
function drawPyroclasticFlows(){
  for(let i=pyroclasticFlows.length-1;i>=0;i--){
    let pf=pyroclasticFlows[i];
    pf.x+=pf.vx;pf.y+=pf.vy;pf.life--;pf.size+=.15;
    if(pf.life<=0||pf.x<-50||pf.x>W+50){pyroclasticFlows.splice(i,1);continue;}
    let a=Math.min(1,pf.life/100);
    // Hot gas cloud (ground-hugging)
    let pfG=C.createRadialGradient(pf.x,pf.y,pf.size*.2,pf.x,pf.y,pf.size);
    pfG.addColorStop(0,'rgba(180,80,20,'+a*.4+')');
    pfG.addColorStop(.4,'rgba(120,60,30,'+a*.3+')');
    pfG.addColorStop(.7,'rgba(80,40,20,'+a*.15+')');
    pfG.addColorStop(1,'rgba(40,20,10,0)');
    C.fillStyle=pfG;C.beginPath();C.arc(pf.x,pf.y,pf.size,0,6.283);C.fill();
    // Glowing embers inside
    C.fillStyle='rgba(255,120,30,'+a*.3+')';
    for(let e=0;e<3;e++){
      let ex=pf.x+(Math.random()-.5)*pf.size,ey=pf.y+(Math.random()-.5)*pf.size*.3;
      C.beginPath();C.arc(ex,ey,1+Math.random()*2,0,6.283);C.fill();
    }
  }
}

// ══════ VOLCANIC BOMBS ══════
function drawVolcanicBombs(){
  for(let i=volcanicBombs.length-1;i>=0;i--){
    let vb=volcanicBombs[i];
    vb.vy+=.15;vb.x+=vb.vx;vb.y+=vb.vy;vb.rotation+=vb.rotSpeed;vb.life--;
    vb.trail.push({x:vb.x,y:vb.y,life:30});
    if(vb.trail.length>15)vb.trail.shift();
    if(vb.life<=0||vb.y>H*.75){
      // Impact
      if(vb.y>H*.6){
        for(let j=0;j<5;j++){
          particles.push({x:vb.x,y:vb.y,vx:(Math.random()-.5)*3,vy:-1-Math.random()*3,
            size:1+Math.random()*2,life:40+Math.random()*30,type:'rock',glow:0});
        }
      }
      volcanicBombs.splice(i,1);continue;
    }
    // Trail
    for(let j=vb.trail.length-1;j>=0;j--){
      let tr=vb.trail[j];tr.life--;
      if(tr.life<=0){vb.trail.splice(j,1);continue;}
      C.fillStyle='rgba(255,100,20,'+(tr.life/30*.3)+')';
      C.beginPath();C.arc(tr.x,tr.y,1.5,0,6.283);C.fill();
    }
    // Bomb body (rotating rock)
    C.save();C.translate(vb.x,vb.y);C.rotate(vb.rotation);
    C.shadowColor='#ff4400';C.shadowBlur=10;
    C.fillStyle='#3a2a1a';
    C.beginPath();
    for(let a=0;a<6.283;a+=1.05){
      let r=vb.size*(0.8+Math.sin(a*3)*.2);
      a===0?C.moveTo(Math.cos(a)*r,Math.sin(a)*r):C.lineTo(Math.cos(a)*r,Math.sin(a)*r);
    }
    C.closePath();C.fill();
    // Glowing cracks
    C.strokeStyle='rgba(255,120,30,.6)';C.lineWidth=1;
    C.beginPath();C.moveTo(-vb.size*.3,-vb.size*.2);C.lineTo(vb.size*.3,vb.size*.1);C.stroke();
    C.beginPath();C.moveTo(vb.size*.1,-vb.size*.3);C.lineTo(-vb.size*.2,vb.size*.3);C.stroke();
    C.shadowBlur=0;C.restore();
  }
}

// ══════ LAHARS ══════
function drawLahars(){
  for(let i=lahars.length-1;i>=0;i--){
    let lh=lahars[i];
    lh.x+=lh.vx;lh.y+=lh.vy*.8;lh.life--;
    lh.points.push({x:lh.x,y:lh.y});
    if(lh.points.length>60)lh.points.shift();
    if(lh.life<=0||lh.y>H*.85||lh.x<0||lh.x>W){lahars.splice(i,1);continue;}
    if(lh.points.length<2)continue;
    let a=lh.life/350;
    // Mudflow trail
    C.strokeStyle='rgba(90,58,32,'+a*.7+')';C.lineWidth=lh.width;C.lineCap='round';C.lineJoin='round';
    C.beginPath();C.moveTo(lh.points[0].x,lh.points[0].y);
    for(let j=1;j<lh.points.length;j++){C.lineTo(lh.points[j].x,lh.points[j].y);}
    C.stroke();
    // Lighter core
    C.strokeStyle='rgba(130,90,50,'+a*.4+')';C.lineWidth=lh.width*.4;
    C.beginPath();C.moveTo(lh.points[0].x,lh.points[0].y);
    for(let j=1;j<lh.points.length;j++){C.lineTo(lh.points[j].x,lh.points[j].y);}
    C.stroke();
    // Debris particles
    if(Math.random()<.1){
      C.fillStyle='rgba(70,50,30,'+a*.5+')';
      C.beginPath();C.arc(lh.x+(Math.random()-.5)*lh.width,lh.y+(Math.random()-.5)*5,2+Math.random()*2,0,6.283);C.fill();
    }
  }
}

// ══════ HEAT MAP OVERLAY ══════
function drawHeatMap(){
  if(!heatMap)return;
  C.globalAlpha=.35;
  let cx=W/2;
  // Crater heat
  let h1=C.createRadialGradient(cx,H*.4,5,cx,H*.4,100);
  h1.addColorStop(0,'rgba(255,0,0,.6)');h1.addColorStop(.3,'rgba(255,100,0,.3)');
  h1.addColorStop(.6,'rgba(255,200,0,.1)');h1.addColorStop(1,'rgba(0,0,255,0)');
  C.fillStyle=h1;C.beginPath();C.arc(cx,H*.4,100,0,6.283);C.fill();
  // Underground heat
  let h2=C.createRadialGradient(cx,H*.8,10,cx,H*.8,150);
  h2.addColorStop(0,'rgba(255,0,0,.5)');h2.addColorStop(.4,'rgba(255,80,0,.2)');
  h2.addColorStop(1,'rgba(0,0,100,0)');
  C.fillStyle=h2;C.beginPath();C.arc(cx,H*.8,150,0,6.283);C.fill();
  // Lava flow heat
  for(let lf of lavaFlows){
    C.fillStyle='rgba(255,50,0,.15)';
    C.beginPath();C.arc(lf.x,lf.y,20,0,6.283);C.fill();
  }
  C.globalAlpha=1;
  // Legend
  C.font='10px Segoe UI';C.textAlign='left';
  let lx=W-120,ly=H-80;
  C.fillStyle='rgba(0,0,0,.5)';C.fillRect(lx-5,ly-15,110,60);
  C.fillStyle='#ffb070';C.fillText('Isi Haritasi',lx,ly);
  let grd=C.createLinearGradient(lx,0,lx+80,0);
  grd.addColorStop(0,'blue');grd.addColorStop(.5,'yellow');grd.addColorStop(1,'red');
  C.fillStyle=grd;C.fillRect(lx,ly+5,80,10);
  C.fillStyle='#8888aa';C.font='8px Segoe UI';
  C.fillText('Soguk',lx,ly+28);C.textAlign='right';C.fillText('Sicak',lx+80,ly+28);C.textAlign='left';
}

// ══════ EARTHQUAKE ══════
function drawEarthquake(){
  if(earthquakeShake>0){earthquakeShake--;}
  for(let i=earthquakeWave.length-1;i>=0;i--){
    let w=earthquakeWave[i];
    w.r+=w.speed;w.life--;
    if(w.life<=0){earthquakeWave.splice(i,1);continue;}
    C.strokeStyle='rgba(255,150,50,'+(w.life/80*.3)+')';C.lineWidth=2;
    C.beginPath();C.ellipse(w.x,w.y,w.r,w.r*.2,0,0,6.283);C.stroke();
  }
}

// ══════ TSUNAMI ══════
function drawTsunami(){
  if(!tsunamiActive)return;
  tsunamiWave+=.03;tsunamiHeight=Math.min(80,tsunamiHeight+.4);
  let baseY=H*.78;
  // Water
  C.fillStyle='rgba(20,80,140,.6)';
  C.beginPath();C.moveTo(0,baseY);
  for(let x=0;x<W;x+=3){
    let y=baseY-tsunamiHeight*Math.sin(x*.008+tsunamiWave)*Math.sin(tsunamiWave*.5);
    C.lineTo(x,y);
  }
  C.lineTo(W,H);C.lineTo(0,H);C.closePath();C.fill();
  // Foam
  C.strokeStyle='rgba(200,230,255,.4)';C.lineWidth=2;
  C.beginPath();
  for(let x=0;x<W;x+=3){
    let y=baseY-tsunamiHeight*Math.sin(x*.008+tsunamiWave)*Math.sin(tsunamiWave*.5)-2;
    x===0?C.moveTo(x,y):C.lineTo(x,y);
  }
  C.stroke();
  if(tsunamiWave>12){tsunamiActive=false;tsunamiHeight=0;}
}

// ══════ LABELS ON VOLCANO ══════
function drawVolcanoLabels(){
  if(!showLabels||crossSection)return;
  let cx=W/2,peakY=H*.4;
  C.font='11px Segoe UI';C.fillStyle='rgba(255,180,120,.6)';C.textAlign='center';
  C.fillText('Krater',cx,peakY-12);
  C.fillText(VTYPES[volcanoType],cx,H*.72);
  if(pressure>50){
    C.fillStyle='rgba(255,100,50,.7)';
    C.fillText('⚠ Yuksek Basinc',cx,peakY+30);
  }
}

// ══════ PRESSURE BAR ══════
function drawPressureBar(){
  let bx=30,by=H-50,bw=150,bh=14;
  C.fillStyle='rgba(0,0,0,.4)';C.fillRect(bx-1,by-1,bw+2,bh+2);
  let pRatio=pressure/maxPressure;
  let barG=C.createLinearGradient(bx,0,bx+bw,0);
  barG.addColorStop(0,'#22aa44');barG.addColorStop(.5,'#ffaa00');barG.addColorStop(1,'#ff2200');
  C.fillStyle=barG;C.fillRect(bx,by,bw*pRatio,bh);
  C.strokeStyle='rgba(255,180,120,.3)';C.lineWidth=1;C.strokeRect(bx,by,bw,bh);
  C.font='10px Segoe UI';C.fillStyle='#ffb070';C.textAlign='left';
  C.fillText('Basinc: '+pressure.toFixed(0)+'%',bx,by-5);
}

// ══════ MAIN LOOP ══════
let loopErr2=false;
function loop(){
  try{
  t++;
  // Auto pressure build
  if(!erupting&&pressure<maxPressure)pressure+=.005+volcanoType*.003;
  magmaTemp=800+pressure*6;
  // Eruption timer
  if(erupting){eruptionTimer--;if(eruptionTimer<=0){erupting=false;eruptionIntensity=0;}}
  // Continuous eruption particles
  if(erupting&&Math.random()<.3*eruptionIntensity){
    particles.push({x:W/2+(Math.random()-.5)*15,y:H*.41,
      vx:(Math.random()-.5)*5*eruptionIntensity,vy:-3-Math.random()*8*eruptionIntensity,
      size:1+Math.random()*4,life:60+Math.random()*100,type:Math.random()>.4?'lava':'rock',glow:Math.random()});
  }
  if(erupting&&Math.random()<.08){
    ashClouds.push({x:W/2+(Math.random()-.5)*30,y:H*.36,vx:(Math.random()-.5)*2,vy:-.5-Math.random(),
      size:15+Math.random()*25,life:200+Math.random()*150,opacity:.4+Math.random()*.2});
  }

  // Shake offset
  let sx=earthquakeShake>0?(Math.random()-.5)*earthquakeShake*.3:0;
  let sy=earthquakeShake>0?(Math.random()-.5)*earthquakeShake*.2:0;
  C.save();C.translate(sx,sy);

  drawSky();
  drawGround();
  drawCrossSection();
  drawVolcano();
  drawLahars();
  drawLavaFlows();
  drawPyroclasticFlows();
  drawParticles();
  drawVolcanicBombs();
  drawAshClouds();
  drawSmoke();
  drawEarthquake();
  drawTsunami();
  drawHeatMap();
  drawVolcanoLabels();
  drawPressureBar();

  C.restore();
  if(t%60===0)updatePanel();
  }catch(e){
    if(!loopErr2){loopErr2=true;
      document.getElementById('info').style.display='block';
      document.getElementById('info').innerHTML='<b>HATA:</b> '+e.message;
    }
  }
  requestAnimationFrame(loop);
}

updatePanel();
requestAnimationFrame(loop);
})();
</script></body></html>"""


def _render_sanal_yanardagi():
    """Sanal Yanardağ Laboratuvarı sekmesi."""
    styled_header(
        "Sanal Yanardağ Laboratuvarı",
        "Interaktif volkan simulasyonu — patlama, deprem, tsunami",
        icon="🌋",
    )
    styled_stat_row([
        ("Mod", "Interaktif", "#ef4444", "🔥"),
        ("Tur", "3 Volkan Turu", "#f59e0b", "🏔️"),
        ("Ozellik", "Kesit & Deprem", "#8b5cf6", "💥"),
        ("Kalite", "Ultra HD", "#f59e0b", "💎"),
    ])
    styled_info_banner(
        "**Basinc+** ile magma basincini artir | **Patlat!** ile patlama baslat | "
        "**Kesit** ile ic yapiyi gor | **Deprem** tetikle | **Tsunami** dalgasi olustur | "
        "3 volkan turu: Kalkan, Stratovulkan, Supervulkan",
        "info",
    )
    import streamlit.components.v1 as components
    components.html(_build_volcano_html(), height=680, scrolling=False)


