  {name:'Gul',petals:8,shape:'round',colors:['#FF1493','#FF69B4','#C71585']},
  {name:'Papatya',petals:12,shape:'thin',colors:['#FFFAFA','#FFF8DC','#FAFAD2']},
  {name:'Lavanta',petals:6,shape:'spike',colors:['#9370DB','#8A2BE2','#BA55D3']},
