def _render_sanal_muze():
    """Sanal Müze Turu sekmesi — 30 Türkiye + 10 Dünya müzesi."""
    styled_header(
        "Sanal M\u00fcze Turu",
        "T\u00fcrkiye ve D\u00fcnya'n\u0131n en \u00f6nemli m\u00fczeleri \u2014 360\u00b0 sanal turlar",
        icon="\U0001F3DB\uFE0F",
    )

    styled_stat_row([
        ("T\u00fcrkiye", "30", "#b45309", "\U0001F1F9\U0001F1F7"),
        ("D\u00fcnya", "10", "#1d4ed8", "\U0001F30D"),
        ("Toplam", "40", "#059669", "\U0001F3DB\uFE0F"),
        ("Eri\u015fim", "\u00dccretsiz", "#7c3aed", "\U0001F513"),
    ])

    styled_info_banner(
        "A\u015fa\u011f\u0131daki m\u00fcze kartlar\u0131na t\u0131klayarak sanal turlar\u0131 "
        "do\u011frudan taray\u0131c\u0131n\u0131zda ba\u015flatabilirsiniz. "
        "T\u00fcm turlar resmi kaynaklar \u00fczerinden sunulmaktad\u0131r.",
        "info",
    )

    if st.button("🏛️ Sanal Müze Turlarını Yükle", key="dk_muze_load", use_container_width=True):
        st.session_state["_dk_muze_loaded"] = True
    if st.session_state.get("_dk_muze_loaded"):
        _diamond_game_html(_build_sanal_muze_html(), height=1800, scrolling=True)


