def _render_deney_lab():
    """Deney Laboratuvarı — interaktif HTML5 bilim simülasyonları."""
    styled_header("Deney Laboratuvarı", "İnteraktif bilim simülasyonları — Fizik, Kimya, Biyoloji", icon="🔬")

    # Kategori seçimi
    kat_cols = st.columns(3)
    kat_keys = list(_DENEY_KATEGORILERI.keys())
    secili_kat = st.session_state.get("_dk_lab_kat", "fizik")

    for i, key in enumerate(kat_keys):
        info = _DENEY_KATEGORILERI[key]
        with kat_cols[i]:
            if st.button(
                f"{info['icon']} {info['baslik']}",
                key=f"dk_lab_kat_{key}",
                use_container_width=True,
                type="primary" if secili_kat == key else "secondary",
            ):
                st.session_state["_dk_lab_kat"] = key
                st.rerun()

    secili_kat = st.session_state.get("_dk_lab_kat", "fizik")
    if secili_kat not in _DENEY_KATEGORILERI:
        secili_kat = "fizik"
        st.session_state["_dk_lab_kat"] = secili_kat
    kat_info = _DENEY_KATEGORILERI[secili_kat]

    # Deneyleri filtrele (sadece kategori bazli)
    filtered = [d for d in _DENEYLER if d["kategori"] == secili_kat]

    styled_stat_row([
        ("Deney Sayısı", str(len(filtered)), kat_info["renk"], "🧪"),
        ("Kategori", kat_info["baslik"], kat_info["renk"], kat_info["icon"]),
        ("Toplam", str(len(_DENEYLER)), "#64748b", "📊"),
        ("Mod", "İnteraktif", "#22c55e", "🖱️"),
    ])

    # Deney seçimi
    styled_section(f"{kat_info['icon']} {kat_info['baslik']} Deneyleri")

    deney_labels = [f"{kat_info['icon']} {d['baslik']}" for d in filtered]
    sel_idx = st.selectbox(
        "Deney Seçin",
        range(len(filtered)),
        format_func=lambda i: deney_labels[i],
        key="dk_lab_deney_sel",
    )
    deney = filtered[sel_idx]

    # Deney bilgi kartı
    detayli = deney.get("detayli_aciklama", "")
    yapilis = deney.get("yapilis", [])
    yapilis_html = ""
    if yapilis:
        steps = "".join(
            f'<div style="display:flex;gap:8px;padding:3px 0">'
            f'<span style="color:{kat_info["renk"]};font-weight:700;min-width:22px">{i+1}.</span>'
            f'<span style="color:#334155;font-size:.88rem">{s}</span></div>'
            for i, s in enumerate(yapilis)
        )
        yapilis_html = (
            f'<div style="margin-top:10px;padding-top:10px;border-top:1px solid {kat_info["renk"]}30">'
            f'<div style="font-weight:700;font-size:.95rem;color:#1e293b;margin-bottom:6px">📋 Yapılış Adımları</div>'
            f'{steps}</div>'
        )
    st.markdown(
        f'<div style="background:linear-gradient(135deg,{kat_info["renk"]}15,{kat_info["renk"]}08);'
        f'border-left:4px solid {kat_info["renk"]};border-radius:0 12px 12px 0;padding:14px 18px;margin:10px 0">'
        f'<div style="font-weight:700;font-size:1.1rem;color:#1e293b;margin-bottom:6px">{kat_info["icon"]} {deney["baslik"]}</div>'
        f'<div style="color:#475569;font-size:.9rem;line-height:1.5">{deney["aciklama"]}</div>'
        f'{"<div style=\"color:#334155;font-size:.88rem;line-height:1.6;margin-top:8px;padding:8px 10px;background:#ffffff80;border-radius:8px\">" + detayli + "</div>" if detayli else ""}'
        f'{yapilis_html}'
        f'</div>',
        unsafe_allow_html=True,
    )

    # Simülasyon alanı
    sim_func = _SIM_MAP.get(deney["sim_type"])
    if sim_func:
        styled_section("Simülasyon")
        sim_html = sim_func()
        import streamlit.components.v1 as components
        _sim_heights = {
            "renk": 580, "hucre": 580, "yogunluk": 580, "bitki": 560,
            "mercek": 540, "kaldirac": 560, "isi": 540, "manyetik": 520,
            "ses": 500, "hal": 540, "tepkime": 520, "elektroliz": 560,
            "periyodik": 560, "karisim": 540, "atom": 580, "gaz": 520,
            "sindirim": 560, "dolasim": 540, "genetik": 560, "ekosistem": 560,
            "solunum": 540, "fotosentez": 560, "sinir": 540, "dna": 540,
        }
        _sim_h = _sim_heights.get(deney["sim_type"], 540)
        components.html(sim_html, height=_sim_h, scrolling=True)
    else:
        styled_info_banner("Bu deney için simülasyon henüz hazırlanmadı.", "info", "🔧")

    # Malzeme listesi + Kazanımlar yan yana
    col_left, col_right = st.columns(2)
    with col_left:
        styled_section("Malzemeler")
        malzeme_html = "".join(
            f'<div style="display:flex;align-items:center;gap:8px;padding:4px 0">'
            f'<span style="color:{kat_info["renk"]};font-size:1.1rem">•</span>'
            f'<span style="color:#334155;font-size:.9rem">{m}</span></div>'
            for m in deney["malzemeler"]
        )
        st.markdown(
            f'<div style="background:#111827;border-radius:10px;padding:12px 16px;border:1px solid #e2e8f0">'
            f'{malzeme_html}</div>',
            unsafe_allow_html=True,
        )

    with col_right:
        styled_section("Kazanımlar")
        kazanim_html = "".join(
            f'<div style="display:flex;align-items:center;gap:8px;padding:4px 0">'
            f'<span style="color:#22c55e;font-size:1rem">✓</span>'
            f'<span style="color:#334155;font-size:.9rem">{k}</span></div>'
            for k in deney["kazanimlar"]
        )
        st.markdown(
            f'<div style="background:#f0fdf4;border-radius:10px;padding:12px 16px;border:1px solid #bbf7d0">'
            f'{kazanim_html}</div>',
            unsafe_allow_html=True,
        )

    # Deney Raporu
    styled_section("Deney Raporu")
    with st.expander("📝 Deney Raporu Yaz", expanded=False):
        rapor_cols = st.columns(2)
        with rapor_cols[0]:
            st.text_input("Öğrenci Adı", key=f"dk_lab_rapor_ad_{deney['id']}")
            st.date_input("Tarih", key=f"dk_lab_rapor_tarih_{deney['id']}")
        with rapor_cols[1]:
            st.text_input("Sınıf", key=f"dk_lab_rapor_sinif_{deney['id']}")

        st.text_area("Hipotez (Beklentiniz neydi?)", key=f"dk_lab_rapor_hipotez_{deney['id']}", height=80)
        st.text_area("Gözlemler (Ne gördünüz?)", key=f"dk_lab_rapor_gozlem_{deney['id']}", height=100)
        st.text_area("Sonuç (Ne öğrendiniz?)", key=f"dk_lab_rapor_sonuc_{deney['id']}", height=80)

        if st.button("💾 Raporu Kaydet", key=f"dk_lab_rapor_kaydet_{deney['id']}"):
            st.success("Deney raporu başarıyla kaydedildi!")


