def _gunun_bilgileri_getir(tarih: date, kategori: str | None = None, kademe: str | None = None) -> list[dict]:
    """Bugünün tarihine göre bilgi kartlarını döndürür. Deterministik seçim."""
    import hashlib
    gun_hash = int(hashlib.md5(f"{tarih.year}-{tarih.month}-{tarih.day}".encode()).hexdigest(), 16)

    havuz = _BILGI_BANKASI.copy()
    if kategori and kategori != "Tümü":
        kat_key = next((k for k, v in _GUNUN_KATEGORILERI.items() if v["baslik"] == kategori), None)
        if kat_key:
            havuz = [b for b in havuz if b["kategori"] == kat_key]
    if kademe and kademe != "Tümü":
        kademe_map = {"İlkokul": "ilkokul", "Ortaokul": "ortaokul", "Lise": "lise"}
        km = kademe_map.get(kademe, "")
        if km:
            havuz = [b for b in havuz if km in b["kademe"]]

    if not havuz:
        return []

    # Tarihe göre karıştır (her gün aynı sıra)
    havuz_sorted = sorted(havuz, key=lambda b: (gun_hash + hash(b["baslik"])) % 10000)

    # Her kategoriden en az 1 tane olmaya çalış
    secilen: list[dict] = []
    gorulmus_kat: set[str] = set()
    for b in havuz_sorted:
        if b["kategori"] not in gorulmus_kat and len(secilen) < 8:
            secilen.append(b)
            gorulmus_kat.add(b["kategori"])
    # Geri kalanından tamamla
    for b in havuz_sorted:
        if b not in secilen and len(secilen) < 8:
            secilen.append(b)

    return secilen


def _render_gunun_bilgisi():
    """Günün Bilgisi sekmesi — her gün değişen bilgi kartları + quiz."""
    from datetime import date as _date

    styled_header(
        "Günün Bilgisi",
        "Her gün yeni bir keşif — Bilim, Tarih, Doğa, Uzay ve daha fazlası",
        icon="💡",
    )

    bugun = _date.today()

    # Filtreler
    filtre_cols = st.columns([2, 2, 2, 1])
    with filtre_cols[0]:
        kat_secenekler = ["Tümü"] + [v["baslik"] for v in _GUNUN_KATEGORILERI.values()]
        kat_filtre = st.selectbox("Kategori", kat_secenekler, key="dk_gb_kat")
    with filtre_cols[1]:
        kademe_filtre = st.selectbox("Kademe", ["Tümü", "İlkokul", "Ortaokul", "Lise"], key="dk_gb_kademe")
    with filtre_cols[2]:
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#1e293b,#334155);border-radius:10px;'
            f'padding:8px 14px;margin-top:26px;text-align:center">'
            f'<span style="color:#94a3b8;font-size:.75rem">Tarih</span><br>'
            f'<span style="color:#1A2035;font-weight:700;font-size:1rem">'
            f'{bugun.strftime("%d %B %Y")}</span></div>',
            unsafe_allow_html=True,
        )

    bilgiler = _gunun_bilgileri_getir(bugun, kat_filtre, kademe_filtre)

    if not bilgiler:
        styled_info_banner("Bu filtrelerle eşleşen bilgi kartı bulunamadı.", "info", "🔍")
        return

    # Kategori dağılım stat
    kat_sayilari: dict[str, int] = {}
    for b in bilgiler:
        kat = _GUNUN_KATEGORILERI.get(b["kategori"], {}).get("baslik", "?")
        kat_sayilari[kat] = kat_sayilari.get(kat, 0) + 1

    stats = [(f"{len(bilgiler)} Kart", "Bugün", "#3b82f6", "💡")]
    for kat_ad, sayi in list(kat_sayilari.items())[:3]:
        kat_key = next((k for k, v in _GUNUN_KATEGORILERI.items() if v["baslik"] == kat_ad), None)
        kat_info = _GUNUN_KATEGORILERI.get(kat_key, {})
        stats.append((str(sayi), kat_ad, kat_info.get("renk", "#64748b"), kat_info.get("icon", "📌")))
    styled_stat_row(stats)

    # Bilgi kartları — 3'lü kompakt grid (HTML)
    cards_html = '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin:10px 0">'
    for bilgi in bilgiler:
        kat_info = _GUNUN_KATEGORILERI.get(bilgi["kategori"], {})
        renk = kat_info.get("renk", "#3b82f6")
        icon = kat_info.get("icon", "")
        kat_baslik = kat_info.get("baslik", "")
        kademe_str = ", ".join(
            {"ilkokul": "Ilkokul", "ortaokul": "Ortaokul", "lise": "Lise"}.get(k, k)
            for k in bilgi["kademe"]
        )
        icerik_kisa = bilgi["icerik"][:120] + "..." if len(bilgi["icerik"]) > 120 else bilgi["icerik"]

        cards_html += (
            f'<div style="background:#0f172a;border:1px solid {renk}25;border-radius:12px;overflow:hidden">'
            f'<div style="background:linear-gradient(135deg,{renk}20,{renk}08);padding:10px 12px;'
            f'display:flex;align-items:center;gap:8px;border-bottom:1px solid {renk}15">'
            f'<span style="font-size:1.2rem">{icon}</span>'
            f'<div><div style="color:#e2e8f0;font-weight:700;font-size:.88rem">{bilgi["baslik"]}</div>'
            f'<div style="color:{renk};font-size:.65rem">{kat_baslik}</div></div></div>'
            f'<div style="padding:10px 12px">'
            f'<div style="color:#94a3b8;font-size:.78rem;line-height:1.5">{icerik_kisa}</div>'
            f'<div style="margin-top:6px;display:flex;gap:4px;flex-wrap:wrap">'
            f'<span style="background:{renk}12;color:{renk};padding:1px 8px;border-radius:10px;font-size:.62rem;font-weight:600">{kat_baslik}</span>'
            f'<span style="background:#1e293b;color:#64748b;padding:1px 8px;border-radius:10px;font-size:.62rem">🎓 {kademe_str}</span>'
            f'</div></div></div>'
        )
    cards_html += '</div>'
    st.markdown(cards_html, unsafe_allow_html=True)

    # Quiz'ler ayrı — sadece açılabilir bölümde
    quiz_bilgiler = [b for b in bilgiler if b.get("quiz_soru")]
    if quiz_bilgiler:
        with st.expander(f"🧠 Mini Quiz — {len(quiz_bilgiler)} soru", expanded=False):
            for qi, bilgi in enumerate(quiz_bilgiler):
                kat_info = _GUNUN_KATEGORILERI.get(bilgi["kategori"], {})
                quiz_key = f"dk_gb_q{qi}_{bugun.isoformat()}"
                cevap_key = f"{quiz_key}_c"
                done_key = f"{quiz_key}_d"
                secenekler = bilgi["quiz_secenekler"]
                dogru_idx = bilgi["quiz_dogru"]

                st.markdown(f"**{qi+1}. {bilgi['baslik']}:** {bilgi['quiz_soru']}")
                if not st.session_state.get(done_key):
                    secim = st.radio("Cevap:", secenekler, key=quiz_key, label_visibility="collapsed")
                    if st.button("Kontrol", key=f"{quiz_key}_btn"):
                        st.session_state[cevap_key] = secenekler.index(secim)
                        st.session_state[done_key] = True
                        st.rerun()
                else:
                    cidx = st.session_state.get(cevap_key, -1)
                    if cidx == dogru_idx:
                        st.success(f"Dogru! {secenekler[dogru_idx]}")
                    else:
                        st.error(f"Yanlis. Dogru: {secenekler[dogru_idx]}")
                st.markdown("---")

    # Öğretmen kendi kartını eklesin
    styled_section("Kendi Bilgi Kartını Ekle")
    with st.expander("📝 Öğretmen / Yönetici — Özel Bilgi Kartı Ekle", expanded=False):
        ek_cols = st.columns(2)
        with ek_cols[0]:
            ek_baslik = st.text_input("Başlık", key="dk_gb_ek_baslik", placeholder="Bilgi kartı başlığı")
            ek_kat = st.selectbox(
                "Kategori",
                list(_GUNUN_KATEGORILERI.keys()),
                format_func=lambda k: f"{_GUNUN_KATEGORILERI[k]['icon']} {_GUNUN_KATEGORILERI[k]['baslik']}",
                key="dk_gb_ek_kat",
            )
        with ek_cols[1]:
            ek_kademe = st.multiselect(
                "Kademe",
                ["ilkokul", "ortaokul", "lise"],
                default=["ilkokul", "ortaokul", "lise"],
                format_func=lambda k: {"ilkokul": "İlkokul", "ortaokul": "Ortaokul", "lise": "Lise"}[k],
                key="dk_gb_ek_kademe",
            )
        ek_icerik = st.text_area("İçerik", key="dk_gb_ek_icerik", height=100, placeholder="Bilgi kartı açıklaması...")
        ek_soru = st.text_input("Quiz Sorusu (opsiyonel)", key="dk_gb_ek_soru")
        if ek_soru:
            ek_sec_cols = st.columns(4)
            ek_secenekler = []
            for si in range(4):
                with ek_sec_cols[si]:
                    s = st.text_input(f"Seçenek {si+1}", key=f"dk_gb_ek_sec_{si}")
                    ek_secenekler.append(s)
            ek_dogru = st.selectbox("Doğru Cevap", range(4), format_func=lambda i: f"Seçenek {i+1}", key="dk_gb_ek_dogru")

        if st.button("💾 Kartı Kaydet", key="dk_gb_ek_kaydet", use_container_width=True):
            if ek_baslik and ek_icerik and ek_kademe:
                yeni_kart = {
                    "kategori": ek_kat,
                    "baslik": ek_baslik,
                    "icerik": ek_icerik,
                    "kademe": ek_kademe,
                    "ay": bugun.month,
                    "gun": bugun.day,
                }
                if ek_soru and all(ek_secenekler):
                    yeni_kart["quiz_soru"] = ek_soru
                    yeni_kart["quiz_secenekler"] = ek_secenekler
                    yeni_kart["quiz_dogru"] = ek_dogru

                # JSON dosyasına kaydet
                import json as _json
                ozel_path = os.path.join(get_tenant_dir(), "dijital_kutuphane", "ozel_bilgi_kartlari.json")
                os.makedirs(os.path.dirname(ozel_path), exist_ok=True)
                mevcut: list[dict] = []
                if os.path.exists(ozel_path):
                    try:
                        with open(ozel_path, "r", encoding="utf-8") as _f:
                            mevcut = _json.load(_f)
                    except Exception:
                        mevcut = []
                yeni_kart["id"] = f"ozel_{len(mevcut)+1}_{bugun.isoformat()}"
                yeni_kart["ekleyen"] = st.session_state.get("user", {}).get("name", "Anonim")
                yeni_kart["ekleme_tarihi"] = bugun.isoformat()
                mevcut.append(yeni_kart)
                with open(ozel_path, "w", encoding="utf-8") as _f:
                    _json.dump(mevcut, _f, ensure_ascii=False, indent=2)
                st.success(f"'{ek_baslik}' bilgi kartı eklendi!")
                st.rerun()
            else:
                st.warning("Başlık, içerik ve kademe zorunludur.")


