def _get_daily_challenge(tarih) -> dict:
    """Tarihe göre deterministik günlük challenge seç."""
    import hashlib
    h = int(hashlib.md5(f"challenge_{tarih.year}_{tarih.month}_{tarih.day}".encode()).hexdigest(), 16)
    valid = [c for c in _KOD_CHALLENGELAR if "baslik" in c]
    return valid[h % len(valid)] if valid else _KOD_CHALLENGELAR[0]


def _build_code_runner_html(kod: str, dil: str) -> str:
    """Tarayıcı içi kod editörü + çalıştırıcı HTML. Python: Pyodide (WebAssembly), JS: eval."""
    if dil == "html_css":
        return f"""
<div style="font-family:Inter,monospace;background:#1e1e2e;border-radius:12px;overflow:hidden;border:2px solid #313244">
<div style="background:#313244;padding:8px 16px;display:flex;justify-content:space-between;align-items:center">
  <span style="color:#cdd6f4;font-weight:700;font-size:.9rem">🌐 HTML/CSS Önizleme</span>
  <button onclick="runHTML()" style="background:#a6e3a1;color:#1e1e2e;border:none;padding:4px 16px;border-radius:6px;font-weight:700;cursor:pointer">▶ Çalıştır</button>
</div>
<textarea id="codeArea" style="width:100%;height:200px;background:#1e1e2e;color:#cdd6f4;border:none;padding:12px;font-family:'Fira Code',monospace;font-size:13px;resize:vertical;outline:none">{kod}</textarea>
<div style="background:#181825;padding:4px 16px"><span style="color:#6c7086;font-size:.75rem">Çıktı:</span></div>
<iframe id="previewFrame" style="width:100%;height:250px;border:none;background:#fff"></iframe>
</div>
<script>
function runHTML(){{
  var code=document.getElementById('codeArea').value;
  var frame=document.getElementById('previewFrame');
  frame.srcdoc=code;
}}
runHTML();
</script>"""
    elif dil == "python":
        escaped = kod.replace("\\", "\\\\").replace("`", "\\`").replace("$", "\\$")
        return f"""
<div style="font-family:Inter,monospace;background:#1e1e2e;border-radius:12px;overflow:hidden;border:2px solid #313244">
<div style="background:#313244;padding:8px 16px;display:flex;justify-content:space-between;align-items:center">
  <span style="color:#cdd6f4;font-weight:700;font-size:.9rem">🐍 Python (Pyodide — Gerçek Python)</span>
  <div style="display:flex;gap:8px;align-items:center">
    <span id="pyStatus" style="color:#f59e0b;font-size:11px;font-weight:600">⏳ Yükleniyor...</span>
    <button id="runBtn" onclick="runPython()" disabled style="background:#a6e3a1;color:#1e1e2e;border:none;padding:4px 16px;border-radius:6px;font-weight:700;cursor:pointer;opacity:.5">▶ Çalıştır</button>
    <button onclick="clearOutput()" style="background:#f38ba8;color:#1e1e2e;border:none;padding:4px 14px;border-radius:6px;font-weight:700;cursor:pointer">🗑️</button>
  </div>
</div>
<textarea id="codeArea" style="width:100%;height:220px;background:#1e1e2e;color:#cdd6f4;border:none;padding:12px;font-family:'Fira Code',monospace;font-size:13px;resize:vertical;outline:none;tab-size:4" spellcheck="false">{kod}</textarea>
<div style="background:#181825;padding:4px 16px;display:flex;justify-content:space-between">
  <span style="color:#6c7086;font-size:.75rem">Python Çıktısı</span>
  <span style="color:#6c7086;font-size:.7rem">Pyodide WebAssembly — tarayıcıda gerçek Python</span>
</div>
<div id="output" style="background:#11111b;min-height:80px;max-height:220px;overflow-y:auto;padding:10px 14px;color:#a6e3a1;font-family:'Fira Code',monospace;font-size:13px;white-space:pre-wrap"></div>
</div>
<script>
var pyodideReady=false, pyodide=null;
function clearOutput(){{document.getElementById('output').textContent='';}}

// Tab tusu destegi
document.getElementById('codeArea').addEventListener('keydown',function(e){{
  if(e.key==='Tab'){{
    e.preventDefault();
    var s=this.selectionStart,end=this.selectionEnd;
    this.value=this.value.substring(0,s)+'    '+this.value.substring(end);
    this.selectionStart=this.selectionEnd=s+4;
  }}
  if(e.key==='Enter'&&e.ctrlKey){{runPython();}}
}});

async function loadPyodide_(){{
  try{{
    const st=document.getElementById('pyStatus');
    const btn=document.getElementById('runBtn');
    st.textContent='⏳ Python motoru yükleniyor...';
    st.style.color='#f59e0b';

    // Pyodide CDN
    const script=document.createElement('script');
    script.src='https://cdn.jsdelivr.net/pyodide/v0.25.1/full/pyodide.js';
    document.head.appendChild(script);

    await new Promise((resolve,reject)=>{{
      script.onload=resolve;
      script.onerror=()=>reject(new Error('CDN yuklenemedi'));
      setTimeout(()=>reject(new Error('Zaman asimi')),30000);
    }});

    st.textContent='⏳ Python başlatılıyor...';
    pyodide=await loadPyodide({{
      indexURL:'https://cdn.jsdelivr.net/pyodide/v0.25.1/full/'
    }});

    pyodideReady=true;
    st.textContent='✅ Python Hazır';
    st.style.color='#a6e3a1';
    btn.disabled=false;
    btn.style.opacity='1';
  }}catch(err){{
    const st=document.getElementById('pyStatus');
    st.textContent='❌ Yüklenemedi (internet?)';
    st.style.color='#f38ba8';
    // Fallback: butonu yine de ac, hata mesaji gosterir
    document.getElementById('runBtn').disabled=false;
    document.getElementById('runBtn').style.opacity='1';
  }}
}}

async function runPython(){{
  const code=document.getElementById('codeArea').value;
  const out=document.getElementById('output');
  out.textContent='';

  if(!pyodideReady){{
    out.innerHTML='<span style="color:#f38ba8">Python motoru henüz yüklenmedi. İnternet bağlantısını kontrol edin ve sayfayı yenileyin.</span>';
    return;
  }}

  try{{
    // stdout/stderr yakalama
    pyodide.runPython(`
import sys, io
sys.stdout = io.StringIO()
sys.stderr = io.StringIO()
`);

    // Kullanici kodunu calistir
    await pyodide.runPythonAsync(code);

    // Ciktiyi al
    const stdout=pyodide.runPython('sys.stdout.getvalue()');
    const stderr=pyodide.runPython('sys.stderr.getvalue()');

    // stdout/stderr sifirla
    pyodide.runPython(`
sys.stdout = io.StringIO()
sys.stderr = io.StringIO()
`);

    if(stdout) out.textContent=stdout;
    if(stderr) out.innerHTML+='<span style="color:#f38ba8">'+stderr+'</span>';
    if(!stdout && !stderr) out.textContent='(Çıktı yok — print() kullanmayı deneyin)';

  }}catch(err){{
    let msg=err.message||String(err);
    // Pyodide Python hata mesajini temizle
    const lines=msg.split('\\n');
    const pyErr=lines.filter(l=>!l.startsWith('  File "<exec>"')&&l.trim()).join('\\n');
    out.innerHTML='<span style="color:#f38ba8">'+pyErr+'</span>';
  }}
}}

// Sayfa acildiginda Pyodide yukle
loadPyodide_();
</script>"""
    else:
        # JavaScript
        return f"""
<div style="font-family:Inter,monospace;background:#1e1e2e;border-radius:12px;overflow:hidden;border:2px solid #313244">
<div style="background:#313244;padding:8px 16px;display:flex;justify-content:space-between;align-items:center">
  <span style="color:#cdd6f4;font-weight:700;font-size:.9rem">🟨 JavaScript Editör</span>
  <div style="display:flex;gap:8px">
    <button onclick="runCode()" style="background:#a6e3a1;color:#1e1e2e;border:none;padding:4px 16px;border-radius:6px;font-weight:700;cursor:pointer">▶ Çalıştır</button>
    <button onclick="clearOutput()" style="background:#f38ba8;color:#1e1e2e;border:none;padding:4px 14px;border-radius:6px;font-weight:700;cursor:pointer">🗑️</button>
  </div>
</div>
<textarea id="codeArea" style="width:100%;height:200px;background:#1e1e2e;color:#cdd6f4;border:none;padding:12px;font-family:'Fira Code',monospace;font-size:13px;resize:vertical;outline:none" spellcheck="false">{kod}</textarea>
<div style="background:#181825;padding:4px 16px"><span style="color:#6c7086;font-size:.75rem">Konsol Çıktısı</span></div>
<div id="output" style="background:#11111b;min-height:80px;max-height:200px;overflow-y:auto;padding:10px 14px;color:#a6e3a1;font-family:monospace;font-size:13px;white-space:pre-wrap"></div>
</div>
<script>
function clearOutput(){{document.getElementById('output').textContent='';}}
document.getElementById('codeArea').addEventListener('keydown',function(e){{
  if(e.key==='Enter'&&e.ctrlKey){{runCode();}}
}});
function runCode(){{
  var code=document.getElementById('codeArea').value;
  var out=document.getElementById('output');
  out.textContent='';
  var logs=[];
  var origLog=console.log;
  console.log=function(){{
    var args=Array.from(arguments).map(a=>typeof a==='object'?JSON.stringify(a,null,2):String(a));
    logs.push(args.join(' '));
  }};
  try{{
    var result=eval(code);
    if(logs.length) out.textContent=logs.join('\\n');
    else if(result!==undefined) out.textContent=String(result);
    else out.textContent='(Çıktı yok)';
  }}catch(e){{
    out.innerHTML='<span style="color:#f38ba8">Hata: '+e.message+'</span>';
  }}
  console.log=origLog;
}}
</script>"""


def _render_kodlama_bahcesi():
    """Kodlama Bahçesi — interaktif kod editörü, dersler, günlük challenge."""
    from datetime import date as _date
    import streamlit.components.v1 as components

    styled_header(
        "Kodlama Bahçesi",
        "Python, JavaScript, HTML/CSS ve Scratch ile kodlamayı öğrenin",
        icon="💻",
    )

    bugun = _date.today()

    # Alt sekmeler
    alt_tab_labels = ["📚 Dersler", "🏆 Günlük Challenge", "🧩 Scratch Stüdyo", "🎨 Canlı Editör"]
    alt_tabs = st.tabs(alt_tab_labels)

    # ══════════════ DERSLER ══════════════
    with alt_tabs[0]:
        styled_section("Programlama Dilleri")

        # Dil seçimi
        dil_cols = st.columns(4)
        secili_dil = st.session_state.get("_dk_kod_dil", "python")
        for i, (key, info) in enumerate(_KOD_DILLER.items()):
            with dil_cols[i]:
                if st.button(
                    f"{info['icon']} {info['baslik']}",
                    key=f"dk_kod_dil_{key}",
                    use_container_width=True,
                    type="primary" if secili_dil == key else "secondary",
                ):
                    st.session_state["_dk_kod_dil"] = key
                    st.rerun()
        secili_dil = st.session_state.get("_dk_kod_dil", "python")
        dil_info = _KOD_DILLER[secili_dil]

        # Kademe filtresi
        kademe_f = st.radio(
            "Kademe", ["Tümü", "İlkokul", "Ortaokul", "Lise"],
            horizontal=True, key="dk_kod_kademe", label_visibility="collapsed",
        )
        kademe_map = {"İlkokul": "ilkokul", "Ortaokul": "ortaokul", "Lise": "lise"}

        # Dersler filtrele
        filtered = [d for d in _KOD_DERSLER if d["dil"] == secili_dil]
        if kademe_f != "Tümü":
            km = kademe_map.get(kademe_f, "")
            filtered = [d for d in filtered if km in d["kademe"]]

        if not filtered:
            styled_info_banner("Bu dil ve kademe için ders bulunamadı.", "info", "🔍")
        else:
            styled_stat_row([
                ("Ders", str(len(filtered)), dil_info["renk"], "📖"),
                ("Dil", dil_info["baslik"], dil_info["renk"], dil_info["icon"]),
                ("Kademe", kademe_f, "#64748b", "🎓"),
                ("Mod", "İnteraktif", "#22c55e", "🖱️"),
            ])

            # Ders seçimi
            ders_labels = [f"{dil_info['icon']} {d['baslik']} ({d['seviye']})" for d in filtered]
            sel_idx = st.selectbox(
                "Ders Seçin", range(len(filtered)),
                format_func=lambda i: ders_labels[i], key="dk_kod_ders_sel",
            )
            ders = filtered[sel_idx]
            kademe_str = ", ".join(
                {"ilkokul": "İlkokul", "ortaokul": "Ortaokul", "lise": "Lise"}.get(k, k)
                for k in ders["kademe"]
            )

            # Ders bilgi kartı
            st.markdown(
                f'<div style="background:linear-gradient(135deg,{dil_info["renk"]}18,{dil_info["renk"]}08);'
                f'border-left:4px solid {dil_info["renk"]};border-radius:0 12px 12px 0;padding:14px 18px;margin:8px 0">'
                f'<div style="font-weight:700;font-size:1.05rem;color:#1e293b">{dil_info["icon"]} {ders["baslik"]}</div>'
                f'<div style="color:#475569;font-size:.88rem;margin:4px 0">{ders["aciklama"]}</div>'
                f'<div style="display:flex;gap:10px;margin-top:6px">'
                f'<span style="background:{dil_info["renk"]}20;color:{dil_info["renk"]};padding:2px 10px;border-radius:12px;font-size:.75rem;font-weight:600">{ders["seviye"]}</span>'
                f'<span style="background:#1A2035;color:#64748b;padding:2px 10px;border-radius:12px;font-size:.75rem;font-weight:600">🎓 {kademe_str}</span>'
                f'</div></div>',
                unsafe_allow_html=True,
            )

            # Canlı kod editörü
            if secili_dil != "scratch":
                styled_section("Canlı Kod Editörü")
                html = _build_code_runner_html(ders["kod"], secili_dil)
                components.html(html, height=550, scrolling=False)
            else:
                styled_section("Scratch Adımları")
                st.code(ders["kod"], language="python")

            # İpucu ve görev
            col_tip, col_task = st.columns(2)
            with col_tip:
                st.markdown(
                    f'<div style="background:#fef3c7;border:1px solid #fbbf24;border-radius:10px;padding:12px 16px">'
                    f'<div style="font-weight:700;color:#92400e;margin-bottom:4px">💡 İpucu</div>'
                    f'<div style="color:#78350f;font-size:.88rem">{ders["ipucu"]}</div></div>',
                    unsafe_allow_html=True,
                )
            with col_task:
                st.markdown(
                    f'<div style="background:#dbeafe;border:1px solid #60a5fa;border-radius:10px;padding:12px 16px">'
                    f'<div style="font-weight:700;color:#1e40af;margin-bottom:4px">🎯 Görev</div>'
                    f'<div style="color:#1d4ed8;font-size:.88rem">{ders["gorev"]}</div></div>',
                    unsafe_allow_html=True,
                )

            # Beklenen çıktı
            with st.expander("✅ Beklenen Çıktı", expanded=False):
                st.code(ders["beklenen"], language="text")

    # ══════════════ GÜNLÜK CHALLENGE ══════════════
    with alt_tabs[1]:
        challenge = _get_daily_challenge(bugun)
        ch_dil_info = _KOD_DILLER.get(challenge.get("dil", "python"), _KOD_DILLER["python"])

        styled_section("Günün Kodlama Challenge'ı")

        st.markdown(
            f'<div style="background:linear-gradient(135deg,#ffffff,#f0f9ff);border-radius:14px;'
            f'padding:20px 24px;margin:8px 0;border:2px solid #bae6fd">'
            f'<div style="display:flex;align-items:center;gap:12px;margin-bottom:12px">'
            f'<span style="font-size:2rem">🏆</span>'
            f'<div>'
            f'<div style="color:#0c4a6e;font-weight:800;font-size:1.2rem">{challenge.get("baslik", "Challenge")}</div>'
            f'<div style="color:#64748b;font-size:.8rem">{bugun.strftime("%d %B %Y")} • {ch_dil_info["icon"]} {ch_dil_info["baslik"]} • {challenge.get("seviye", "")}</div>'
            f'</div></div>'
            f'<div style="color:#334155;font-size:.95rem;line-height:1.6;margin-bottom:12px">{challenge.get("aciklama", "")}</div>'
            f'<div style="background:#eff6ff;border:1px solid #93c5fd;border-radius:8px;padding:10px 14px">'
            f'<span style="color:#92400e;font-weight:600">💡 İpucu:</span> '
            f'<span style="color:#475569">{challenge.get("ipucu", "")}</span>'
            f'</div></div>',
            unsafe_allow_html=True,
        )

        # Challenge çözüm alanı
        st.text_area(
            "Çözümünüzü yazın:",
            height=180,
            key="dk_kod_challenge_cozum",
            placeholder="# Kodunuzu buraya yazın...",
        )

        ch_cols = st.columns(3)
        with ch_cols[0]:
            if st.button("💾 Kaydet", key="dk_kod_ch_kaydet", use_container_width=True):
                st.success("Çözümünüz kaydedildi!")
        with ch_cols[1]:
            if st.button("🔄 Yeni Challenge", key="dk_kod_ch_yeni", use_container_width=True):
                st.info("Her gün yeni bir challenge gelir!")
        with ch_cols[2]:
            if st.button("📊 İstatistikler", key="dk_kod_ch_stats", use_container_width=True):
                st.info("Challenge tamamlama istatistikleri yakında!")

        # Tüm challenge'lar listesi
        styled_section("Tüm Challenge'lar")
        for ci, ch in enumerate(_KOD_CHALLENGELAR):
            if "baslik" not in ch:
                continue
            ch_dil = _KOD_DILLER.get(ch.get("dil", "python"), _KOD_DILLER["python"])
            st.markdown(
                f'<div style="background:#111827;border:1px solid #e2e8f0;border-radius:10px;'
                f'padding:10px 16px;margin:4px 0;display:flex;align-items:center;gap:12px">'
                f'<span style="font-size:1.2rem;min-width:30px">{ch_dil["icon"]}</span>'
                f'<div style="flex:1">'
                f'<span style="font-weight:700;color:#1e293b;font-size:.9rem">{ch["baslik"]}</span>'
                f'<span style="color:#64748b;font-size:.8rem;margin-left:8px">({ch.get("seviye", "")})</span>'
                f'</div>'
                f'<span style="background:{ch_dil["renk"]}20;color:{ch_dil["renk"]};padding:2px 10px;'
                f'border-radius:12px;font-size:.72rem;font-weight:600">{ch_dil["baslik"]}</span>'
                f'</div>',
                unsafe_allow_html=True,
            )

    # ══════════════ SCRATCH STÜDYO ══════════════
    with alt_tabs[2]:
        styled_section("Scratch Online Stüdyo")
        st.markdown(
            '<div style="background:linear-gradient(135deg,#ff9800,#ff5722);border-radius:14px;'
            'padding:18px 22px;margin:8px 0;color:#fff">'
            '<div style="font-weight:800;font-size:1.1rem;margin-bottom:6px">🧩 Scratch ile Kodla!</div>'
            '<div style="font-size:.9rem;opacity:.9">Blok tabanlı programlama — sürükle, bırak, çalıştır. '
            'Kod yazmadan oyun, animasyon ve hikaye oluşturun.</div></div>',
            unsafe_allow_html=True,
        )

        scratch_tabs = st.tabs(["🎮 Scratch Editör", "📖 Scratch Projeleri", "🎓 Başlangıç Rehberi"])

        with scratch_tabs[0]:
            st.markdown(
                '<div style="background:#111827;border:2px solid #e2e8f0;border-radius:12px;'
                'padding:16px;text-align:center">'
                '<p style="color:#475569;font-size:.95rem;margin-bottom:12px">'
                'Scratch editörü aşağıda yüklenecektir. Yüklenmezse butona tıklayın.</p></div>',
                unsafe_allow_html=True,
            )
            if st.button("🚀 Scratch Editörünü Aç", key="dk_kod_scratch_open", use_container_width=True):
                components.iframe("https://scratch.mit.edu/projects/editor/", height=600, scrolling=True)

        with scratch_tabs[1]:
            scratch_projeler = [
                {"ad": "Kedi Macerası", "url": "https://scratch.mit.edu/projects/946992544/", "aciklama": "Scratch varsayılan kedi ile temel hareket ve etkileşim"},
                {"ad": "Pong Oyunu", "url": "https://scratch.mit.edu/projects/10128407/", "aciklama": "Klasik Pong oyunu — top ve raket kontrolü"},
                {"ad": "Labirent Oyunu", "url": "https://scratch.mit.edu/projects/48519996/", "aciklama": "Ok tuşlarıyla labirentte gezin"},
                {"ad": "Müzik Yapıcı", "url": "https://scratch.mit.edu/projects/68618976/", "aciklama": "Kendi müziğinizi oluşturun — ses blokları"},
                {"ad": "Çizim Programı", "url": "https://scratch.mit.edu/projects/314900893/", "aciklama": "Kalem aracıyla ekrana çizim yapın"},
                {"ad": "Soru Oyunu", "url": "https://scratch.mit.edu/projects/10015060/", "aciklama": "Bilgi yarışması tarzı soru-cevap oyunu"},
            ]
            prj_cols = st.columns(2)
            for pi, prj in enumerate(scratch_projeler):
                with prj_cols[pi % 2]:
                    st.markdown(
                        f'<div style="background:#fff;border:1px solid #e2e8f0;border-radius:12px;'
                        f'padding:14px 16px;margin:4px 0;box-shadow:0 2px 6px rgba(0,0,0,0.05)">'
                        f'<div style="font-weight:700;color:#1e293b;font-size:.95rem">🧩 {prj["ad"]}</div>'
                        f'<div style="color:#64748b;font-size:.82rem;margin:4px 0">{prj["aciklama"]}</div>'
                        f'</div>',
                        unsafe_allow_html=True,
                    )
                    if st.button(f"▶ {prj['ad']}", key=f"dk_scratch_prj_{pi}", use_container_width=True):
                        components.iframe(prj["url"].rstrip("/") + "/embed/", height=400, scrolling=False)

        with scratch_tabs[2]:
            rehber_adimlari = [
                ("1. Scratch'e Giriş", "scratch.mit.edu adresine gidin → 'Oluştur' butonuna tıklayın", "#3b82f6"),
                ("2. Blok Kategorileri", "Hareket (mavi), Görünüm (mor), Ses (pembe), Olaylar (sarı), Kontrol (turuncu), Algılama (açık mavi)", "#8b5cf6"),
                ("3. İlk Program", "'Bayrak tıklanınca' bloğunu sürükleyin → altına '10 adım git' ekleyin → yeşil bayrağa tıklayın", "#22c55e"),
                ("4. Döngü Ekle", "'Sürekli tekrarla' bloğunun içine hareket bloğunu koyun → kedi sürekli hareket eder", "#f59e0b"),
                ("5. Kostüm Değiştir", "Kostümler sekmesinde yeni kostüm ekleyin → 'sonraki kostüme geç' bloğu ile animasyon", "#ef4444"),
                ("6. Ses Ekle", "Sesler sekmesinden ses seçin → 'sesi çal' bloğu ile kullanın", "#ec4899"),
            ]
            for ad, acik, renk in rehber_adimlari:
                st.markdown(
                    f'<div style="background:linear-gradient(135deg,{renk}12,{renk}05);border-left:4px solid {renk};'
                    f'border-radius:0 10px 10px 0;padding:10px 16px;margin:6px 0">'
                    f'<div style="font-weight:700;color:{renk};font-size:.9rem">{ad}</div>'
                    f'<div style="color:#475569;font-size:.85rem">{acik}</div></div>',
                    unsafe_allow_html=True,
                )

    # ══════════════ CANLI EDİTÖR ══════════════
    with alt_tabs[3]:
        styled_section("Serbest Kod Editörü")
        st.markdown(
            '<div style="background:#dbeafe;border:1px solid #60a5fa;border-radius:10px;padding:10px 16px;margin-bottom:10px">'
            '<span style="color:#1e40af;font-weight:600">🎨 Serbest mod:</span> '
            '<span style="color:#1d4ed8;font-size:.9rem">İstediğiniz kodu yazın ve çalıştırın. HTML/CSS anlık önizleme, JS konsol çıktısı.</span></div>',
            unsafe_allow_html=True,
        )

        ed_dil = st.radio(
            "Dil", ["HTML & CSS", "JavaScript"],
            horizontal=True, key="dk_kod_editor_dil", label_visibility="collapsed",
        )

        if ed_dil == "HTML & CSS":
            default_code = '<div style="text-align:center;padding:40px;font-family:Arial">\n  <h1 style="color:#3b82f6">Merhaba! 🚀</h1>\n  <p>Kodunuzu düzenleyin ve Çalıştır butonuna basın.</p>\n</div>'
            html = _build_code_runner_html(default_code, "html_css")
            components.html(html, height=550, scrolling=False)
        else:
            default_js = '// JavaScript kodunuzu buraya yazın\nconsole.log("Merhaba JavaScript! 🚀");\n\nfor (let i = 1; i <= 5; i++) {\n  console.log(`Sayı: ${i}`);\n}'
            html = _build_code_runner_html(default_js, "javascript")
            components.html(html, height=550, scrolling=False)


