def _build_art_studio_html() -> str:
    """Tam özellikli HTML5 Canvas çizim stüdyosu."""
    return """<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:Inter,-apple-system,sans-serif;background:#0B0F19;color:#e2e8f0;overflow:hidden}
.studio{display:flex;height:680px;gap:0}
.toolbar{width:72px;background:#1e293b;padding:8px 6px;display:flex;flex-direction:column;gap:4px;
  border-right:2px solid #334155;overflow-y:auto}
.tool-btn{width:56px;height:42px;border:none;border-radius:10px;background:#334155;color:#e2e8f0;
  cursor:pointer;font-size:18px;display:flex;align-items:center;justify-content:center;transition:.2s;
  -webkit-user-select:none;user-select:none}
.tool-btn:hover{background:#475569;transform:scale(1.05)}
.tool-btn.active{background:linear-gradient(135deg,#3b82f6,#6366f1);color:#fff;box-shadow:0 2px 8px rgba(59,130,246,.4)}
.canvas-area{flex:1;display:flex;flex-direction:column;background:#1a1a2e}
.canvas-top{background:#1e293b;padding:6px 14px;display:flex;align-items:center;gap:10px;border-bottom:1px solid #334155;flex-wrap:wrap}
.canvas-wrap{flex:1;display:flex;align-items:center;justify-content:center;padding:8px;overflow:hidden;position:relative}
canvas{border-radius:8px;box-shadow:0 4px 20px rgba(0,0,0,.3);cursor:crosshair;touch-action:none}
.opt-label{color:#94a3b8;font-size:11px;font-weight:600}
input[type=range]{width:80px;accent-color:#3b82f6;cursor:pointer}
input[type=color]{width:32px;height:28px;border:2px solid #475569;border-radius:6px;cursor:pointer;background:none;padding:0}
.color-preset{width:22px;height:22px;border-radius:50%;border:2px solid #475569;cursor:pointer;transition:.15s;display:inline-block}
.color-preset:hover{transform:scale(1.2);border-color:#fff}
.btn-sm{padding:4px 12px;border-radius:6px;border:none;font-size:11px;font-weight:700;cursor:pointer;transition:.2s}
.btn-green{background:#22c55e;color:#fff}.btn-green:hover{background:#16a34a}
.btn-purple{background:#8b5cf6;color:#fff}.btn-purple:hover{background:#7c3aed}
.btn-red{background:#ef4444;color:#fff}.btn-red:hover{background:#dc2626}
.btn-blue{background:#3b82f6;color:#fff}.btn-blue:hover{background:#2563eb}

/* Modal overlay */
.modal-overlay{position:absolute;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.6);
  display:none;align-items:center;justify-content:center;z-index:1000}
.modal-overlay.show{display:flex}
.modal-box{background:#1e293b;border:2px solid #3b82f6;border-radius:14px;padding:20px;
  box-shadow:0 8px 30px rgba(0,0,0,.5);min-width:300px;max-width:400px}
.modal-title{font-weight:700;font-size:15px;margin-bottom:12px;color:#e2e8f0}
.modal-input{width:100%;padding:8px 12px;border-radius:8px;border:1px solid #475569;
  background:#334155;color:#e2e8f0;font-size:14px;outline:none;margin-bottom:12px}
.modal-input:focus{border-color:#3b82f6}
.modal-btns{display:flex;gap:8px;justify-content:flex-end}

/* Stamp picker */
.stamp-picker{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);background:#1e293b;
  border:2px solid #3b82f6;border-radius:14px;padding:16px;z-index:999;box-shadow:0 8px 30px rgba(0,0,0,.5);
  max-width:360px;max-height:400px;overflow-y:auto;display:none}
.stamp-picker.show{display:block}
.stamp-grid{display:flex;flex-wrap:wrap;gap:6px;margin-top:8px}
.stamp-item{font-size:24px;width:38px;height:38px;display:flex;align-items:center;justify-content:center;
  background:#334155;border-radius:8px;cursor:pointer;transition:.15s}
.stamp-item:hover{background:#475569;transform:scale(1.15)}
.stamp-group{color:#94a3b8;font-size:11px;font-weight:700;margin:8px 0 4px;width:100%}

/* Status bar */
.status-bar{background:#1e293b;border-top:1px solid #334155;padding:4px 14px;display:flex;
  align-items:center;gap:12px;font-size:11px;color:#94a3b8}
.status-dot{width:8px;height:8px;border-radius:50%;background:#22c55e;display:inline-block}
</style>
</head>
<body>
<div class="studio">
  <!-- Toolbar -->
  <div class="toolbar" id="toolbarPanel">
    <button class="tool-btn active" id="tb_brush" title="Firca">&#x1f58c;&#xfe0f;</button>
    <button class="tool-btn" id="tb_pencil" title="Kalem">&#x270f;&#xfe0f;</button>
    <button class="tool-btn" id="tb_spray" title="Sprey">&#x1f3a8;</button>
    <button class="tool-btn" id="tb_eraser" title="Silgi">&#x1f9f9;</button>
    <button class="tool-btn" id="tb_line" title="Cizgi">&#x1f4cf;</button>
    <button class="tool-btn" id="tb_rect" title="Dikdortgen">&#x2b1c;</button>
    <button class="tool-btn" id="tb_circle" title="Daire">&#x2b55;</button>
    <button class="tool-btn" id="tb_triangle" title="Ucgen">&#x1f53a;</button>
    <button class="tool-btn" id="tb_star" title="Yildiz">&#x2b50;</button>
    <button class="tool-btn" id="tb_text" title="Yazi">&#x1f524;</button>
    <button class="tool-btn" id="tb_fill" title="Doldur">&#x1faa3;</button>
    <button class="tool-btn" id="tb_stamp" title="Damga">&#x1f4cc;</button>
    <button class="tool-btn" id="tb_eyedrop" title="Renk Al">&#x1f489;</button>
    <div style="flex:1"></div>
    <button class="tool-btn" id="btn_undo" title="Geri Al">&#x21a9;&#xfe0f;</button>
    <button class="tool-btn" id="btn_redo" title="Ileri Al">&#x21aa;&#xfe0f;</button>
  </div>

  <!-- Canvas Area -->
  <div class="canvas-area">
    <div class="canvas-top">
      <span class="opt-label">Renk</span>
      <input type="color" id="colorPick" value="#ffffff">
      <div style="display:flex;gap:3px" id="colorPresets"></div>
      <span class="opt-label">Kalinlik</span>
      <input type="range" id="sizeSl" min="1" max="50" value="4">
      <span id="sizeVal" style="color:#e2e8f0;font-size:12px;min-width:18px">4</span>
      <span class="opt-label">Opaklik</span>
      <input type="range" id="opacSl" min="10" max="100" value="100">
      <span id="opacVal" style="color:#e2e8f0;font-size:12px;min-width:30px">100%</span>
      <div style="flex:1"></div>
      <button class="btn-sm btn-green" id="btn_save">&#x1f4be; Kaydet</button>
      <button class="btn-sm btn-purple" id="btn_bg">&#x1f3a8; Arkaplan</button>
      <button class="btn-sm btn-red" id="btn_clear">&#x1f5d1;&#xfe0f; Temizle</button>
    </div>
    <div class="canvas-wrap" id="canvasWrap">
      <canvas id="artCanvas" width="800" height="500"></canvas>
      <!-- Stamp Picker (inside canvas-wrap for correct positioning) -->
      <div class="stamp-picker" id="stampModal">
        <div style="display:flex;justify-content:space-between;align-items:center">
          <span style="font-weight:700;font-size:14px">&#x1f4cc; Damga Sec</span>
          <button class="btn-sm btn-red" id="stampClose">&#x2715;</button>
        </div>
        <div class="stamp-grid" id="stampGrid"></div>
      </div>
      <!-- Text Input Modal -->
      <div class="modal-overlay" id="textModal">
        <div class="modal-box">
          <div class="modal-title">&#x1f524; Metin Girin</div>
          <input class="modal-input" id="textInput" placeholder="Yazinizi girin..." autofocus>
          <div class="modal-btns">
            <button class="btn-sm btn-red" id="textCancel">Iptal</button>
            <button class="btn-sm btn-blue" id="textOk">Ekle</button>
          </div>
        </div>
      </div>
      <!-- Confirm Clear Modal -->
      <div class="modal-overlay" id="clearModal">
        <div class="modal-box">
          <div class="modal-title">&#x1f5d1;&#xfe0f; Cizimi Temizle</div>
          <p style="color:#94a3b8;font-size:13px;margin-bottom:14px">Tum cizim silinecek. Emin misiniz?</p>
          <div class="modal-btns">
            <button class="btn-sm btn-purple" id="clearCancel">Vazgec</button>
            <button class="btn-sm btn-red" id="clearOk">Temizle</button>
          </div>
        </div>
      </div>
    </div>
    <div class="status-bar">
      <span class="status-dot"></span>
      <span id="statusText">Firca araci aktif</span>
      <div style="flex:1"></div>
      <span id="posText">x:0 y:0</span>
    </div>
  </div>
</div>

<script>
(function(){
  const cv=document.getElementById('artCanvas'),ctx=cv.getContext('2d');
  let curTool='brush',curColor='#ffffff',curSize=4,curOpacity=1;
  let drawing=false,startX,startY,lastX,lastY;
  let history=[],redoStack=[],curStamp='\u2b50';
  let bgColor='#ffffff';
  let textPos={x:0,y:0};

  // Tool names in Turkish
  const toolNames={brush:'Firca',pencil:'Kalem',spray:'Sprey',eraser:'Silgi',line:'Cizgi',
    rect:'Dikdortgen',circle:'Daire',triangle:'Ucgen',star:'Yildiz',text:'Yazi',
    fill:'Doldur',stamp:'Damga',eyedrop:'Renk Al'};

  // Init white bg
  ctx.fillStyle=bgColor;ctx.fillRect(0,0,cv.width,cv.height);
  saveState();

  // --- Color presets ---
  const presetColors=['#ffffff','#ef4444','#f97316','#facc15','#22c55e','#3b82f6',
    '#8b5cf6','#ec4899','#000000','#78350f','#0d9488','#94a3b8'];
  const cpDiv=document.getElementById('colorPresets');
  presetColors.forEach(function(c){
    var d=document.createElement('div');
    d.className='color-preset';
    d.style.background=c;
    d.addEventListener('click',function(){pickColor(c);});
    cpDiv.appendChild(d);
  });

  // --- Stamp data ---
  const stampData=[
    {grup:'Hayvanlar',items:['🐱','🐶','🐰','🦊','🐻','🐼','🐸','🦋','🐝','🐞','🐠','🐬','🦅','🦉','🐧']},
    {grup:'Doga',items:['🌸','🌺','🌻','🌹','🌳','🌴','🍀','🌈','☀️','⭐','❄️','🌙','💧','🔥','🍂']},
    {grup:'Yiyecek',items:['🍎','🍕','🍦','🧁','🍩','🍉','🍓','🥕','🌽','🍌','🍇','🍪','🎂','🍫','☕']},
    {grup:'Ulasim',items:['🚗','🚀','✈️','🚂','🚢','🚲','🏎️','🚁','⛵','🛸']},
    {grup:'Spor',items:['⚽','🏀','🎾','🏈','⚾','🎱','🏐','🎯','🏆','🥇']},
    {grup:'Sekiller',items:['❤️','⭐','💎','🔶','🔷','⬛','🟠','🟢','🔴','🟣']}
  ];
  var sg=document.getElementById('stampGrid');
  stampData.forEach(function(g){
    var lbl=document.createElement('div');lbl.className='stamp-group';lbl.textContent=g.grup;sg.appendChild(lbl);
    g.items.forEach(function(s){
      var el=document.createElement('div');el.className='stamp-item';el.textContent=s;
      el.addEventListener('click',function(){selectStamp(s);});
      sg.appendChild(el);
    });
  });

  function selectStamp(s){curStamp=s;document.getElementById('stampModal').classList.remove('show');}

  // --- Tool selection via event delegation ---
  document.getElementById('toolbarPanel').addEventListener('click',function(e){
    var btn=e.target.closest('.tool-btn');
    if(!btn)return;
    var id=btn.id;
    if(id==='btn_undo'){undo();return;}
    if(id==='btn_redo'){redo();return;}
    var tool=id.replace('tb_','');
    if(tool&&toolNames[tool])setTool(tool);
  });

  function setTool(t){
    curTool=t;
    document.querySelectorAll('.tool-btn').forEach(function(b){b.classList.remove('active');});
    var el=document.getElementById('tb_'+t);
    if(el)el.classList.add('active');
    cv.style.cursor=t==='eraser'?'cell':t==='fill'?'crosshair':t==='eyedrop'?'crosshair':
      t==='text'?'text':t==='stamp'?'copy':'crosshair';
    document.getElementById('statusText').textContent=(toolNames[t]||t)+' araci aktif';
    if(t==='stamp')document.getElementById('stampModal').classList.add('show');
  }

  function pickColor(c){curColor=c;document.getElementById('colorPick').value=c;}

  // Color picker change
  document.getElementById('colorPick').addEventListener('input',function(){curColor=this.value;});

  // Size slider
  document.getElementById('sizeSl').addEventListener('input',function(){
    curSize=+this.value;document.getElementById('sizeVal').textContent=this.value;
  });

  // Opacity slider
  document.getElementById('opacSl').addEventListener('input',function(){
    curOpacity=this.value/100;document.getElementById('opacVal').textContent=this.value+'%';
  });

  // --- History ---
  function saveState(){
    history.push(cv.toDataURL());
    if(history.length>40)history.shift();
    redoStack=[];
  }
  function undo(){
    if(history.length<=1)return;
    redoStack.push(history.pop());
    var img=new Image();img.onload=function(){ctx.clearRect(0,0,cv.width,cv.height);ctx.drawImage(img,0,0);};
    img.src=history[history.length-1];
  }
  function redo(){
    if(!redoStack.length)return;
    var d=redoStack.pop();history.push(d);
    var img=new Image();img.onload=function(){ctx.clearRect(0,0,cv.width,cv.height);ctx.drawImage(img,0,0);};
    img.src=d;
  }

  // --- Clear (custom modal instead of confirm()) ---
  document.getElementById('btn_clear').addEventListener('click',function(){
    document.getElementById('clearModal').classList.add('show');
  });
  document.getElementById('clearCancel').addEventListener('click',function(){
    document.getElementById('clearModal').classList.remove('show');
  });
  document.getElementById('clearOk').addEventListener('click',function(){
    document.getElementById('clearModal').classList.remove('show');
    ctx.fillStyle=bgColor;ctx.fillRect(0,0,cv.width,cv.height);saveState();
  });

  // --- Background change ---
  document.getElementById('btn_bg').addEventListener('click',function(){
    var colors=['#ffffff','#111827','#fef3c7','#dbeafe','#dcfce7','#fce7f3','#1e1e2e','#0B0F19','#fdf2f8','#ecfdf5'];
    var idx=colors.indexOf(bgColor);
    bgColor=colors[(idx+1)%colors.length];
    var imgData=ctx.getImageData(0,0,cv.width,cv.height);
    ctx.fillStyle=bgColor;ctx.fillRect(0,0,cv.width,cv.height);
    ctx.putImageData(imgData,0,0);
    saveState();
  });

  // --- Save image ---
  document.getElementById('btn_save').addEventListener('click',function(){
    var link=document.createElement('a');
    link.download='sanat_eseri_'+Date.now()+'.png';
    link.href=cv.toDataURL('image/png');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  });

  // --- Stamp close ---
  document.getElementById('stampClose').addEventListener('click',function(){
    document.getElementById('stampModal').classList.remove('show');
  });

  // --- Text modal ---
  document.getElementById('textCancel').addEventListener('click',function(){
    document.getElementById('textModal').classList.remove('show');
  });
  document.getElementById('textOk').addEventListener('click',function(){
    var txt=document.getElementById('textInput').value;
    if(txt){
      ctx.globalAlpha=curOpacity;ctx.fillStyle=curColor;
      ctx.font='bold '+Math.max(curSize*3,14)+'px Inter,Arial,sans-serif';
      ctx.textAlign='left';ctx.textBaseline='top';
      ctx.fillText(txt,textPos.x,textPos.y);
      ctx.globalAlpha=1;saveState();
    }
    document.getElementById('textInput').value='';
    document.getElementById('textModal').classList.remove('show');
  });
  document.getElementById('textInput').addEventListener('keydown',function(e){
    if(e.key==='Enter'){document.getElementById('textOk').click();}
  });

  // --- Canvas helpers ---
  function getPos(e){
    var r=cv.getBoundingClientRect();
    var t=e.touches?e.touches[0]:e;
    return{x:(t.clientX-r.left)*(cv.width/r.width),y:(t.clientY-r.top)*(cv.height/r.height)};
  }

  // Flood fill
  function floodFill(sx,sy,fc){
    var id=ctx.getImageData(0,0,cv.width,cv.height);
    var d=id.data,w=cv.width,h=cv.height;
    var si=(sy*w+sx)*4;
    var sr=d[si],sg2=d[si+1],sb=d[si+2];
    var fr=parseInt(fc.slice(1,3),16),fg=parseInt(fc.slice(3,5),16),fb=parseInt(fc.slice(5,7),16);
    if(sr===fr&&sg2===fg&&sb===fb)return;
    var stack=[[sx,sy]],visited=new Set();
    while(stack.length){
      var pt=stack.pop(),x=pt[0],y=pt[1];
      if(x<0||x>=w||y<0||y>=h)continue;
      var key=y*w+x;if(visited.has(key))continue;visited.add(key);
      var pi=key*4;
      if(Math.abs(d[pi]-sr)>30||Math.abs(d[pi+1]-sg2)>30||Math.abs(d[pi+2]-sb)>30)continue;
      d[pi]=fr;d[pi+1]=fg;d[pi+2]=fb;d[pi+3]=255;
      stack.push([x+1,y],[x-1,y],[x,y+1],[x,y-1]);
      if(visited.size>200000)break;
    }
    ctx.putImageData(id,0,0);
  }

  // Draw shapes
  var snapImg=null;
  function drawShape(ex,ey,final){
    if(!final&&snapImg)ctx.putImageData(snapImg,0,0);
    ctx.globalAlpha=curOpacity;ctx.strokeStyle=curColor;ctx.fillStyle=curColor;ctx.lineWidth=curSize;ctx.lineCap='round';
    var dx=ex-startX,dy=ey-startY;
    if(curTool==='line'){ctx.beginPath();ctx.moveTo(startX,startY);ctx.lineTo(ex,ey);ctx.stroke();}
    else if(curTool==='rect'){ctx.strokeRect(startX,startY,dx,dy);}
    else if(curTool==='circle'){
      var r=Math.sqrt(dx*dx+dy*dy);ctx.beginPath();ctx.arc(startX,startY,r,0,Math.PI*2);ctx.stroke();
    }
    else if(curTool==='triangle'){
      ctx.beginPath();ctx.moveTo(startX,startY);ctx.lineTo(startX+dx,startY+dy);
      ctx.lineTo(startX-dx,startY+dy);ctx.closePath();ctx.stroke();
    }
    else if(curTool==='star'){
      var r2=Math.sqrt(dx*dx+dy*dy),spikes=5;
      ctx.beginPath();
      for(var i=0;i<spikes*2;i++){
        var rad=r2*(i%2===0?1:0.5);
        var a=Math.PI/2*3+i*Math.PI/spikes;
        var px=startX+Math.cos(a)*rad,py=startY+Math.sin(a)*rad;
        i===0?ctx.moveTo(px,py):ctx.lineTo(px,py);
      }
      ctx.closePath();ctx.stroke();
    }
    ctx.globalAlpha=1;
  }

  // Spray
  function spray(x,y){
    ctx.globalAlpha=curOpacity*0.3;ctx.fillStyle=curColor;
    for(var i=0;i<20;i++){
      var ox=(Math.random()-0.5)*curSize*3;
      var oy=(Math.random()-0.5)*curSize*3;
      ctx.fillRect(x+ox,y+oy,1.5,1.5);
    }
    ctx.globalAlpha=1;
  }

  // --- Mouse Events ---
  cv.addEventListener('mousedown',function(e){
    e.preventDefault();
    var p=getPos(e);startX=lastX=p.x;startY=lastY=p.y;
    if(curTool==='fill'){floodFill(Math.round(p.x),Math.round(p.y),curColor);saveState();return;}
    if(curTool==='eyedrop'){
      var px=ctx.getImageData(Math.round(p.x),Math.round(p.y),1,1).data;
      var hex='#'+[px[0],px[1],px[2]].map(function(v){return v.toString(16).padStart(2,'0');}).join('');
      pickColor(hex);return;
    }
    if(curTool==='stamp'){
      ctx.font=(curSize*5+16)+'px serif';ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.fillText(curStamp,p.x,p.y);saveState();return;
    }
    if(curTool==='text'){
      textPos={x:p.x,y:p.y};
      document.getElementById('textInput').value='';
      document.getElementById('textModal').classList.add('show');
      setTimeout(function(){document.getElementById('textInput').focus();},100);
      return;
    }
    drawing=true;
    if(['line','rect','circle','triangle','star'].indexOf(curTool)>=0){
      snapImg=ctx.getImageData(0,0,cv.width,cv.height);
    }
    if(curTool==='brush'||curTool==='pencil'||curTool==='eraser'){
      ctx.beginPath();ctx.moveTo(p.x,p.y);
    }
  });

  cv.addEventListener('mousemove',function(e){
    var p=getPos(e);
    document.getElementById('posText').textContent='x:'+Math.round(p.x)+' y:'+Math.round(p.y);
    if(!drawing)return;
    if(['line','rect','circle','triangle','star'].indexOf(curTool)>=0){
      drawShape(p.x,p.y,false);
    } else if(curTool==='spray'){
      spray(p.x,p.y);
    } else {
      ctx.globalAlpha=curOpacity;
      ctx.lineWidth=curTool==='pencil'?Math.max(1,curSize*0.4):curSize;
      ctx.lineCap='round';ctx.lineJoin='round';
      if(curTool==='eraser'){ctx.strokeStyle=bgColor;ctx.lineWidth=curSize*3;}
      else ctx.strokeStyle=curColor;
      ctx.lineTo(p.x,p.y);ctx.stroke();
      ctx.globalAlpha=1;
    }
    lastX=p.x;lastY=p.y;
  });

  cv.addEventListener('mouseup',function(e){
    if(!drawing)return;drawing=false;
    if(['line','rect','circle','triangle','star'].indexOf(curTool)>=0){
      var p=getPos(e);drawShape(p.x,p.y,true);snapImg=null;
    }
    ctx.beginPath();saveState();
  });
  cv.addEventListener('mouseleave',function(){if(drawing){drawing=false;ctx.beginPath();saveState();}});

  // --- Touch support ---
  cv.addEventListener('touchstart',function(e){
    e.preventDefault();
    var touch=e.touches[0];
    cv.dispatchEvent(new MouseEvent('mousedown',{clientX:touch.clientX,clientY:touch.clientY}));
  },{passive:false});
  cv.addEventListener('touchmove',function(e){
    e.preventDefault();
    var touch=e.touches[0];
    cv.dispatchEvent(new MouseEvent('mousemove',{clientX:touch.clientX,clientY:touch.clientY}));
  },{passive:false});
  cv.addEventListener('touchend',function(e){
    e.preventDefault();
    cv.dispatchEvent(new MouseEvent('mouseup',{}));
  },{passive:false});

})();
</script>
</body>
</html>"""


def _render_sanat_studyosu():
    """Dijital Sanat Stüdyosu — tam Canvas çizim uygulaması + rehberli çizim + galeri."""
    import streamlit.components.v1 as components

    styled_header(
        "Dijital Sanat Stüdyosu",
        "Çiz, boya, damgala, kaydet — dijital sanat eserlerin burada!",
        icon="🎨",
    )

    art_tabs = st.tabs(["🖌️ Çizim Stüdyosu", "📖 Rehberli Çizim", "🖼️ Galeri"])

    # ══════════════ ÇİZİM STÜDYOSU ══════════════
    with art_tabs[0]:
        st.markdown(
            '<div style="background:linear-gradient(135deg,#ec4899,#8b5cf6);border-radius:12px;'
            'padding:12px 18px;margin-bottom:8px;color:#fff">'
            '<span style="font-weight:700">🖌️ Araçlar:</span> '
            'Fırça, Kalem, Sprey, Silgi, Çizgi, Dikdörtgen, Daire, Üçgen, Yıldız, Yazı, Doldur, Damga, Renk Al '
            '| <span style="font-weight:700">↩️ Geri Al</span> (40 adım) '
            '| <span style="font-weight:700">💾 PNG Kaydet</span></div>',
            unsafe_allow_html=True,
        )

        html = _build_art_studio_html()
        components.html(html, height=700, scrolling=True)

    # ══════════════ REHBERLİ ÇİZİM ══════════════
    with art_tabs[1]:
        styled_section("Adım Adım Çizim Dersleri")

        cizim_cols = st.columns(3)
        for ci, cizim in enumerate(_REHBERLI_CIZIMLER):
            with cizim_cols[ci % 3]:
                seviye_renk = {"Kolay": "#22c55e", "Orta": "#f59e0b", "Zor": "#ef4444"}.get(cizim["seviye"], "#64748b")
                st.markdown(
                    f'<div style="background:#fff;border:1px solid #e2e8f0;border-radius:12px;'
                    f'padding:14px 16px;margin:4px 0;text-align:center;box-shadow:0 2px 6px rgba(0,0,0,0.05)">'
                    f'<div style="font-size:2.5rem;margin-bottom:6px">{cizim["icon"]}</div>'
                    f'<div style="font-weight:700;color:#1e293b;font-size:.95rem">{cizim["baslik"]}</div>'
                    f'<span style="background:{seviye_renk}20;color:{seviye_renk};padding:2px 10px;'
                    f'border-radius:12px;font-size:.72rem;font-weight:600">{cizim["seviye"]}</span>'
                    f'</div>',
                    unsafe_allow_html=True,
                )

        # Seçili çizim dersi
        sec_cizim_labels = [f'{c["icon"]} {c["baslik"]} ({c["seviye"]})' for c in _REHBERLI_CIZIMLER]
        sec_idx = st.selectbox(
            "Çizim Dersi Seçin", range(len(_REHBERLI_CIZIMLER)),
            format_func=lambda i: sec_cizim_labels[i], key="dk_art_rehber_sec",
        )
        secili = _REHBERLI_CIZIMLER[sec_idx]

        styled_section(f"{secili['icon']} {secili['baslik']} — Adım Adım")

        for ai, adim in enumerate(secili["adimlar"]):
            adim_renk = f"hsl({ai * 45}, 70%, 45%)"
            st.markdown(
                f'<div style="display:flex;align-items:center;gap:12px;padding:8px 0;'
                f'border-bottom:1px solid #1A2035">'
                f'<div style="width:32px;height:32px;border-radius:50%;background:{adim_renk};'
                f'color:#fff;display:flex;align-items:center;justify-content:center;'
                f'font-weight:800;font-size:.85rem;flex-shrink:0">{ai+1}</div>'
                f'<div style="color:#334155;font-size:.9rem">{adim}</div>'
                f'</div>',
                unsafe_allow_html=True,
            )

        st.markdown(
            '<div style="background:#dbeafe;border:1px solid #60a5fa;border-radius:10px;'
            'padding:10px 16px;margin-top:12px">'
            '<span style="font-weight:700;color:#1e40af">💡 İpucu:</span> '
            '<span style="color:#1d4ed8;font-size:.9rem">'
            'Yukarıdaki Çizim Stüdyosu sekmesinde adımları takip ederek çizebilirsiniz!</span></div>',
            unsafe_allow_html=True,
        )

    # ══════════════ GALERİ ══════════════
    with art_tabs[2]:
        styled_section("Sanat Galerisi")

        # Galeri yükleme/kaydetme
        galeri_path = os.path.join(get_tenant_dir(), "dijital_kutuphane", "sanat_galerisi.json")

        import json as _json
        galeri_data: list[dict] = []
        if os.path.exists(galeri_path):
            try:
                with open(galeri_path, "r", encoding="utf-8") as _f:
                    galeri_data = _json.load(_f)
            except Exception:
                galeri_data = []

        # Eser yükleme
        with st.expander("📤 Eserini Galeriye Ekle", expanded=False):
            up_cols = st.columns(2)
            with up_cols[0]:
                eser_ad = st.text_input("Eser Adı", key="dk_art_eser_ad", placeholder="Eserinize bir isim verin")
                eser_sanatci = st.text_input("Sanatçı", key="dk_art_eser_sanatci",
                    value=st.session_state.get("user", {}).get("name", ""))
            with up_cols[1]:
                eser_sinif = st.text_input("Sınıf", key="dk_art_eser_sinif")
                eser_teknik = st.selectbox("Teknik", [
                    "Dijital Çizim", "Fırça Boyama", "Piksel Sanatı",
                    "Emoji Sanatı", "Karışık Teknik", "Diğer"
                ], key="dk_art_eser_teknik")
            eser_aciklama = st.text_input("Açıklama (opsiyonel)", key="dk_art_eser_aciklama")
            eser_dosya = st.file_uploader("Eser Dosyası (PNG/JPG)", type=["png", "jpg", "jpeg"], key="dk_art_eser_dosya")

            if eser_dosya:
                from utils.security import validate_upload
                _ok, _msg = validate_upload(eser_dosya, allowed_types=["png", "jpg", "jpeg"], max_mb=50)
                if not _ok:
                    st.error(f"⚠️ {_msg}")
                    eser_dosya = None

            if st.button("🖼️ Galeriye Ekle", key="dk_art_gonder", use_container_width=True):
                if eser_ad and eser_sanatci and eser_dosya:
                    import base64
                    img_b64 = base64.b64encode(eser_dosya.read()).decode()
                    from datetime import datetime
                    yeni_eser = {
                        "id": f"art_{len(galeri_data)+1}_{datetime.now().strftime('%Y%m%d%H%M%S')}",
                        "ad": eser_ad,
                        "sanatci": eser_sanatci,
                        "sinif": eser_sinif,
                        "teknik": eser_teknik,
                        "aciklama": eser_aciklama,
                        "tarih": datetime.now().strftime("%d.%m.%Y"),
                        "img_b64": img_b64[:500000],  # Max 500KB
                        "begeniler": 0,
                    }
                    galeri_data.append(yeni_eser)
                    os.makedirs(os.path.dirname(galeri_path), exist_ok=True)
                    with open(galeri_path, "w", encoding="utf-8") as _f:
                        _json.dump(galeri_data, _f, ensure_ascii=False, indent=2)
                    st.success(f"'{eser_ad}' galeriye eklendi!")
                    st.rerun()
                else:
                    st.warning("Eser adı, sanatçı ve dosya zorunludur.")

        # Galeri gösterimi
        if galeri_data:
            st.markdown(
                f'<div style="color:#64748b;font-size:.85rem;margin-bottom:8px">'
                f'Toplam {len(galeri_data)} eser sergileniyor</div>',
                unsafe_allow_html=True,
            )
            gal_cols = st.columns(3)
            for gi, eser in enumerate(reversed(galeri_data[-12:])):
                with gal_cols[gi % 3]:
                    img_html = ""
                    if eser.get("img_b64"):
                        img_html = (
                            f'<img src="data:image/png;base64,{eser["img_b64"]}" '
                            f'style="width:100%;height:150px;object-fit:cover;border-radius:8px 8px 0 0">'
                        )
                    st.markdown(
                        f'<div style="background:#fff;border:1px solid #e2e8f0;border-radius:12px;'
                        f'overflow:hidden;margin:4px 0;box-shadow:0 2px 8px rgba(0,0,0,0.06)">'
                        f'{img_html}'
                        f'<div style="padding:10px 14px">'
                        f'<div style="font-weight:700;color:#1e293b;font-size:.9rem">{eser.get("ad","")}</div>'
                        f'<div style="color:#64748b;font-size:.78rem">'
                        f'🎨 {eser.get("sanatci","")} • {eser.get("sinif","")} • {eser.get("tarih","")}</div>'
                        f'<div style="color:#94a3b8;font-size:.75rem;margin-top:2px">{eser.get("teknik","")}</div>'
                        f'</div></div>',
                        unsafe_allow_html=True,
                    )
        else:
            st.markdown(
                '<div style="background:#111827;border:2px dashed #cbd5e1;border-radius:12px;'
                'padding:40px;text-align:center;color:#94a3b8">'
                '<div style="font-size:3rem;margin-bottom:8px">🖼️</div>'
                '<div style="font-weight:600;font-size:1rem">Galeri henüz boş</div>'
                '<div style="font-size:.85rem">Stüdyoda bir eser çizin ve buraya yükleyin!</div></div>',
                unsafe_allow_html=True,
            )


