def _ai_asistan_data_path() -> str:
    """AI Asistan konuşma geçmişi ve istatistik dosya yolu."""
    base = os.path.join(get_tenant_dir(), "dijital_kutuphane")
    os.makedirs(base, exist_ok=True)
    return os.path.join(base, "ai_asistan_gecmisi.json")


def _ai_asistan_load() -> dict:
    """Geçmiş verisini yükle."""
    path = _ai_asistan_data_path()
    if os.path.exists(path):
        try:
            with open(path, encoding="utf-8") as f:
                return _json.load(f)
        except Exception:
            pass
    return {"konusmalar": [], "istatistik": {}}


def _ai_asistan_save(data: dict):
    """Geçmiş verisini kaydet."""
    path = _ai_asistan_data_path()
    with open(path, "w", encoding="utf-8") as f:
        _json.dump(data, f, ensure_ascii=False, indent=2)


def _ai_asistan_explain(konu: str, seviye: str, ders: str, ek_talimat: str = "") -> str | None:
    """OpenAI ile konu açıklaması üret."""
    client = _get_quiz_ai_client()
    if client is None:
        return None

    seviye_prompt = _KADEME_SEVIYE.get(seviye, _KADEME_SEVIYE["Ortaokul (5-8. sınıf)"])

    system_msg = (
        "Sen Türk eğitim müfredatına hakim, deneyimli, karizmatik ve ilham veren bir öğretmensin. "
        "Kitaptan okur gibi DEĞİL, sınıfta canlı ders anlatan bir öğretmen gibi yaz. "
        "Açıklamalarında:\n"
        "- MERAK UYANDIRARAK BAŞLA: 'Hiç düşündünüz mü...', 'Bir hayal edin...'\n"
        "- HİKAYE/SENARYO KULLAN: 'Ahmet markete gitti ve...', 'Bir bilim insanı...'\n"
        "- GÜNLÜK HAYATTAN ANALOJİ YAP: 'Bu tıpkı telefonunuzu şarj etmek gibi...'\n"
        "- ÖĞRENCİYE SORU SOR: 'Peki sence ne olur?', 'Tahmin et bakalım!'\n"
        "- ŞAŞIRTICI GERÇEKLER PAYLAŞ: 'Biliyor musunuz? Dünya'da her saniye...'\n"
        "- SIK YAPILAN HATALARI GÖSTER: 'Dikkat! Burada çok karışır...'\n"
        "- Başlıklar ve alt başlıklar kullan (markdown formatında)\n"
        "- Önemli kavramları **kalın** yaz\n"
        "- Türkçe yaz, sıcak ve samimi bir dil kullan\n"
        "- YASAK: Monoton, kitabi, ansiklopedik anlatım. Kuru bilgi sıralaması YAPMA.\n"
        f"\nSeviye talimatı: {seviye_prompt}"
    )

    user_msg = f"Ders: {ders}\nKonu: {konu}"
    if ek_talimat:
        user_msg += f"\n\nEk talimat: {ek_talimat}"

    try:
        resp = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": system_msg},
                {"role": "user", "content": user_msg},
            ],
            max_tokens=2000,
            temperature=0.7,
        )
        return resp.choices[0].message.content
    except Exception as e:
        return f"⚠️ AI yanıt üretemedi: {e}"


def _ai_asistan_generate_inline_visual(konu: str, ders: str, seviye: str, aciklama: str) -> str | None:
    """Açıklama ile birlikte gösterilecek tam HTML görsel (diyagram/harita/çizim) üret."""
    client = _get_quiz_ai_client()
    if client is None:
        return None

    system_msg = (
        "Sen eğitim görselleştirme uzmanısın. Bir konu açıklamasına eşlik edecek "
        "TAM ÇALIŞAN, TEK DOSYA halinde HTML görsel üreteceksin.\n\n"
        "KRİTİK KURALLAR:\n"
        "1. <!DOCTYPE html><html>...<body>...</body></html> ile BAŞLA VE BİTİR\n"
        "2. Tüm CSS <style> içinde, tüm JS <script> içinde olsun\n"
        "3. SVG kullanıyorsan viewBox tanımla, width='100%' height='auto' yap\n"
        "4. SVG içinde text için font-size, fill, text-anchor ZORUNLU\n"
        "5. Harici kaynak/CDN KULLANMA — her şey inline olsun\n"
        "6. Koyu tema: body background #0B0F19, metin fill/color #e2e8f0\n"
        "7. Vurgu renkleri: #6366F1 (gold), #3b82f6 (mavi), #22c55e (yeşil), #ef4444 (kırmızı), #a855f7 (mor)\n"
        "8. Kutucuklar: fill #1e293b, stroke #6366F1, rx=10 (yuvarlatılmış)\n"
        "9. Oklar: marker-end ile SVG arrow marker tanımla\n"
        "10. Hover: CSS ile .box:hover { opacity:0.8; transform:scale(1.02) } veya JS\n"
        "11. Tooltip: Ayrı bir div#tooltip ile position:fixed göster\n\n"
        "SVG ŞABLONU (bu yapıyı kullan):\n"
        "```\n"
        "<svg viewBox='0 0 800 400' width='100%' xmlns='http://www.w3.org/2000/svg'>\n"
        "  <defs>\n"
        "    <marker id='arrow' viewBox='0 0 10 10' refX='9' refY='5' markerWidth='6' markerHeight='6' orient='auto'>\n"
        "      <path d='M 0 0 L 10 5 L 0 10 z' fill='#6366F1'/>\n"
        "    </marker>\n"
        "  </defs>\n"
        "  <!-- rect: rx=10, fill=#1e293b, stroke=#6366F1 -->\n"
        "  <!-- text: fill=#e2e8f0, font-family=system-ui, text-anchor=middle -->\n"
        "  <!-- line: stroke=#6366F1, marker-end=url(#arrow) -->\n"
        "</svg>\n"
        "```\n\n"
        "GÖRSEL TİPLERİ (konuya göre en uygununu seç):\n"
        "- Akış Diyagramı: Kutu + ok ile süreç göster\n"
        "- Zihin Haritası: Merkez daire + dallar\n"
        "- Karşılaştırma: İki sütunlu tablo\n"
        "- Zaman Çizelgesi: Yatay çizgi + tarih noktaları\n"
        "- Anatomik Çizim: Etiketli SVG şekiller\n"
        "- Geometrik Şekil: Ölçülü çizim + formüller\n"
        "- Harita: Basit SVG path harita\n"
        "- Formül Kutusu: Büyük renkli formüller\n"
        "- Piramit: Katmanlı üçgen\n"
        "- Venn: Yarı saydam daireler\n"
        "- Tablo/Grid: Bilgi kartları\n\n"
        "Sadece HTML kodu döndür, başka hiçbir şey yazma."
    )

    user_msg = (
        f"Ders: {ders}\nKonu: {konu}\nSeviye: {seviye}\n\n"
        f"Açıklama özeti:\n{aciklama[:1500]}\n\n"
        "Bu açıklamayı destekleyecek açıklayıcı bir görsel/diyagram/harita oluştur."
    )

    try:
        resp = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": system_msg},
                {"role": "user", "content": user_msg},
            ],
            max_tokens=3500,
            temperature=0.7,
        )
        text = resp.choices[0].message.content.strip()
        if "```html" in text:
            text = text.split("```html")[1].split("```")[0].strip()
        elif "```" in text:
            text = text.split("```")[1].split("```")[0].strip()
        # Temel doğrulama — en az bir HTML etiketi olmalı
        if "<" in text and ">" in text:
            return text
        return None
    except Exception:
        return None


def _wrap_svg_as_full_html(html_fragment: str) -> str:
    """Parça SVG/HTML'yi tam çalışan HTML sayfasına sar.

    - Zaten tam HTML ise dokunmaz (3D modeller vb.)
    - Parça SVG/HTML'yi responsive sayfaya sarar
    """
    # Zaten tam HTML ise olduğu gibi döndür — CSS enjekte etme, bozar
    if "<!DOCTYPE" in html_fragment or "<html" in html_fragment:
        return html_fragment

    # Parça SVG/HTML → tam sayfaya sar
    return (
        '<!DOCTYPE html><html><head><meta charset="utf-8"><style>\n'
        '*{margin:0;padding:0;box-sizing:border-box}\n'
        'body{background:#0B0F19;font-family:system-ui,sans-serif;color:#e2e8f0;\n'
        '  display:flex;justify-content:center;align-items:flex-start;\n'
        '  min-height:100vh;padding:12px;overflow:auto}\n'
        '.container{width:100%;max-width:100%}\n'
        'svg{display:block;margin:0 auto}\n'
        'svg text{font-family:system-ui,sans-serif}\n'
        'svg rect,svg circle,svg ellipse{transition:filter 0.2s}\n'
        'svg rect:hover,svg circle:hover,svg ellipse:hover{\n'
        '  filter:brightness(1.3) drop-shadow(0 0 8px rgba(212,175,55,0.6));cursor:pointer}\n'
        '#tooltip{position:fixed;background:rgba(15,23,42,0.97);color:#fbbf24;\n'
        '  border:1px solid #6366F1;border-radius:8px;padding:8px 14px;font-size:13px;\n'
        '  pointer-events:none;display:none;z-index:999;max-width:260px;\n'
        '  box-shadow:0 4px 15px rgba(0,0,0,0.6)}\n'
        '</style></head><body>\n'
        '<div class="container">\n'
        + html_fragment +
        '\n</div>\n'
        '<div id="tooltip"></div>\n'
        '<script>\n'
        'function showTooltip(evt,text){\n'
        '  var t=document.getElementById("tooltip");\n'
        '  if(!t)return;t.textContent=text;t.style.display="block";\n'
        '  t.style.left=Math.min(evt.clientX+12,window.innerWidth-270)+"px";\n'
        '  t.style.top=(evt.clientY-35)+"px";\n'
        '}\n'
        'function hideTooltip(){var t=document.getElementById("tooltip");if(t)t.style.display="none"}\n'
        '// SVG fit\n'
        'document.querySelectorAll("svg").forEach(function(svg){\n'
        '  try{\n'
        '    var vb=svg.getAttribute("viewBox");\n'
        '    if(!vb){\n'
        '      var bb=svg.getBBox();\n'
        '      if(bb.width>0&&bb.height>0){\n'
        '        svg.setAttribute("viewBox",(bb.x-10)+" "+(bb.y-10)+" "+(bb.width+20)+" "+(bb.height+20));\n'
        '      }\n'
        '    }\n'
        '    svg.setAttribute("width","100%");\n'
        '    svg.removeAttribute("height");\n'
        '    svg.style.maxHeight="420px";\n'
        '  }catch(e){}\n'
        '});\n'
        '</script>\n'
        '</body></html>'
    )


def _ai_asistan_generate_visual(konu: str, ders: str, seviye: str) -> dict | None:
    """AI'dan konu için interaktif 3D/2D görsel kodu üret.

    Returns dict: {"type": "3d"|"diagram"|"chart"|"animation", "html": "...", "title": "..."}
    """
    client = _get_quiz_ai_client()
    if client is None:
        return None

    system_msg = (
        "Sen eğitim amaçlı interaktif görselleştirme üreten bir AI'sın.\n"
        "Kullanıcının belirttiği konu için TAM ÇALIŞAN, TEK DOSYA halinde HTML+JS kodu üreteceksin.\n\n"
        "KURALLAR:\n"
        "1. Tüm kod tek bir HTML bloğunda olmalı (inline CSS + JS)\n"
        "2. 3D konular için Three.js kullan (CDN: https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js)\n"
        "   - OrbitControls için: https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js\n"
        "3. 2D diyagram/grafik konuları için Canvas API veya SVG kullan\n"
        "4. Animasyonlu ve interaktif olsun (mouse/touch ile döndürme, zoom, tıklama)\n"
        "5. Koyu tema: arka plan #0B0F19, yazılar #e2e8f0, vurgular #6366F1 (gold)\n"
        "6. Türkçe etiketler ve açıklamalar kullan\n"
        "7. width:100%, height:500px olsun\n"
        "8. Sol alt köşeye kısa Türkçe açıklama/ipucu paneli ekle\n"
        "9. Sağ üste interaktif kontroller ekle (varsa: hız, boyut slider vb.)\n\n"
        "KONU TÜRLERİ ve GÖRSEL TİPLERİ:\n"
        "- Matematik (geometri, grafik): 3D şekiller, koordinat düzlemi, fonksiyon grafikleri\n"
        "- Fizik (kuvvet, hareket, dalga): 3D simülasyon, parçacık animasyonu\n"
        "- Kimya (atom, molekül, periyodik): 3D atom/molekül modeli, orbital\n"
        "- Biyoloji (hücre, DNA, organ): 3D model, kesit görünümü\n"
        "- Coğrafya (dünya, katmanlar): 3D küre, harita\n"
        "- Tarih (zaman çizelgesi, harita): İnteraktif timeline, SVG harita\n"
        "- Diğer: Konu-uygun en iyi görselleştirme\n\n"
        "YANIT FORMATI (sadece JSON, başka hiçbir şey yazma):\n"
        '{"type": "3d"|"diagram"|"chart"|"animation", "title": "Görsel başlık", "html": "<!DOCTYPE html>..."}\n'
    )

    user_msg = f"Ders: {ders}\nKonu: {konu}\nSeviye: {seviye}\n\nBu konu için interaktif görsel oluştur."

    try:
        resp = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": system_msg},
                {"role": "user", "content": user_msg},
            ],
            max_tokens=4000,
            temperature=0.7,
        )
        text = resp.choices[0].message.content.strip()
        if "```json" in text:
            text = text.split("```json")[1].split("```")[0].strip()
        elif "```" in text:
            text = text.split("```")[1].split("```")[0].strip()
        return _json.loads(text)
    except Exception:
        return None


