    # ── Harf-Canvas Görselleri ──
    def _harf_canvas(harf, renk="#e74c3c", w=120, h=140):
        """Tek harf için premium canvas görseli."""
        return f"""
        <canvas id="cv_{harf}" width="{w}" height="{h}" style="border-radius:12px;"></canvas>
        <script>
        (function(){{
            var c=document.getElementById('cv_{harf}').getContext('2d');
            var W={w},H={h};
            // Arka plan
            c.fillStyle='#1a1a2e';c.fillRect(0,0,W,H);
            // Çerçeve
            c.strokeStyle='{renk}';c.lineWidth=2;
            c.strokeRect(3,3,W-6,H-6);
            // Büyük harf
            c.fillStyle='{renk}';c.font='bold '+(W*0.5)+'px "Segoe UI", Arial';
            c.textAlign='center';c.textBaseline='middle';
            c.fillText('{harf.upper()}',W/2,H*0.35);
            // Küçük harf
            c.fillStyle='#FFD700';c.font='bold '+(W*0.35)+'px "Segoe UI", Arial';
            c.fillText('{harf}',W/2,H*0.72);
            // Alt çizgi
            c.fillStyle='{renk}';c.fillRect(W*0.2,H*0.9,W*0.6,3);
        }})();
        </script>
        """

    def _hece_canvas(hece, renk="#3498db", w=130, h=80):
        """Hece görseli."""
        harfler = list(hece)
        return f"""
        <canvas id="cv_h_{''.join(c if c.isascii() else str(ord(c)) for c in hece)}" width="{w}" height="{h}" style="border-radius:10px;"></canvas>
        <script>
        (function(){{
            var c=document.getElementById('cv_h_{''.join(c if c.isascii() else str(ord(c)) for c in hece)}').getContext('2d');
            var W={w},H={h};
            c.fillStyle='#0d1b2a';c.fillRect(0,0,W,H);
            c.strokeStyle='{renk}';c.lineWidth=2;c.strokeRect(2,2,W-4,H-4);
            var harfler={list(harfler)};
            var total=harfler.length;
            var cellW=W/total;
            c.textAlign='center';c.textBaseline='middle';
            for(var i=0;i<total;i++){{
                // Her harf için arka plan
                if(i%2===0) c.fillStyle='rgba(52,152,219,0.15)';
                else c.fillStyle='rgba(231,76,60,0.15)';
                c.fillRect(i*cellW+2,2,cellW-2,H-4);
                // Harf
                c.fillStyle=i%2===0?'#3498db':'#e74c3c';
                c.font='bold '+(Math.min(cellW*0.6,H*0.5))+'px "Segoe UI", Arial';
                c.fillText(harfler[i],i*cellW+cellW/2,H/2);
            }}
        }})();
        </script>
        """

