    def _oy_tts(text: str, voice: str = "nova") -> str | None:
        """OpenAI TTS ile ses üret, base64 döndür."""
        try:
            import openai, os, base64
            client = openai.OpenAI(api_key=os.getenv("OPENAI_API_KEY", ""))
            resp = client.audio.speech.create(
                model="tts-1", voice=voice,
                input=text[:4000], response_format="mp3",
            )
            return base64.b64encode(resp.content).decode()
        except Exception:
            return None

    def _oy_play_audio(b64: str | None, text: str, key_suffix: str):
        """Ses çal: OpenAI TTS varsa mp3, yoksa tarayıcı TTS."""
