        # ── İki renkli kelime gösterim fonksiyonu ──
        def _oy_renkli(text, r1="#1e40af", r2="#c2410c"):
            """Kelimeleri iki renkte gösterir."""
            words = text.split()
            parts = []
            for i, w in enumerate(words):
                c = r1 if i % 2 == 0 else r2
                parts.append(f'<span style="color:{c};font-weight:600;">{w}</span>')
            return ' '.join(parts)

