# ADMİN PANELİ
# ══════════════════════════════════════════════════════════════════════════════

def _render_admin_panel(store: DijitalKutuphaneDataStore):
    """Yönetim paneli — kaynak ekle, listele, sil."""
    styled_header("Yönetim Paneli", "Dijital kaynak ekle, düzenle, sil", icon="⚙️")

    counts = store.kaynak_sayilari()
    total = sum(counts.values())
    styled_stat_row([
        ("Toplam Kaynak", str(total), _CLR_BLUE, "📊"),
        ("Okul Öncesi", str(counts.get("okul_oncesi", 0)), _CLR_PURPLE, "🎒"),
        ("İlkokul", str(counts.get("ilkokul", 0)), _CLR_TEAL, "📕"),
        ("Ortaokul", str(counts.get("ortaokul", 0)), _CLR_GREEN, "📗"),
        ("Lise", str(counts.get("lise", 0)), _CLR_RED, "📘"),
    ])

    st.markdown("---")

    # ── Yeni Kaynak Formu ──
    styled_section("Yeni Kaynak Ekle", _CLR_BLUE)
    with st.form("dk_yeni_kaynak_form"):
        c1, c2 = st.columns(2)
        with c1:
            baslik = st.text_input("Başlık *", placeholder="Platform / Kanal adı")

            url = st.text_input("URL *", placeholder="https://...")

            kategori = st.selectbox("Kategori", KAYNAK_KATEGORILERI)

        with c2:
            aciklama = st.text_input("Açıklama", placeholder="Kısa tanım")

            kademe = st.selectbox(
                "Kademe",
                KADEME_SECENEKLERI,
                format_func=lambda x: KADEME_LABELS.get(x, x),
            )
            ikon = st.text_input("İkon (emoji)", value="🔗")


        c3, c4 = st.columns(2)
        with c3:
            renk1 = st.color_picker("Gradient Renk 1", value="#4472C4")

        with c4:
            renk2 = st.color_picker("Gradient Renk 2", value="#1e3a5f")


        sira = st.number_input("Sıra", min_value=0, value=0)

        submitted = st.form_submit_button("Kaynak Ekle", use_container_width=True, type="primary")

    if submitted:
        if baslik and url:
            kaynak = DijitalKaynak(
                baslik=baslik,
                aciklama=aciklama,
                url=url,
                kategori=kategori,
                kademe=kademe,
                ikon=ikon,
                renk1=renk1,
                renk2=renk2,
                sira=int(sira),
            )
            store.upsert("kaynaklar", kaynak)
            st.success(f"Kaynak eklendi: {baslik}")
            st.rerun()
        else:
            st.error("Başlık ve URL zorunludur.")

    # ── Mevcut Kaynaklar ──
    st.markdown("---")
    styled_section("Mevcut Kaynaklar", _CLR_ORANGE)
    all_kaynaklar = store.load_objects("kaynaklar")
    if not all_kaynaklar:
        styled_info_banner("Henüz yönetici tarafından eklenmiş kaynak yok.", "warning")
    else:
        for kademe_key in KADEME_SECENEKLERI:
            items = [k for k in all_kaynaklar if k.kademe == kademe_key]
            if items:
                with st.expander(f"{KADEME_LABELS[kademe_key]} ({len(items)} kaynak)", expanded=False
                ):
                    for k in sorted(items, key=lambda x: x.sira):
                        c1, c2, c3 = st.columns([4, 1, 1])
                        with c1:
                            st.markdown(
                                f'<div style="display:flex;align-items:center;gap:8px;padding:4px 0;">'
                                f'<span>{k.ikon}</span>'
                                f'<b>{k.baslik}</b>'
                                f'<span style="color:#64748b;font-size:0.8rem;">({k.kategori})</span>'
                                f'</div>',
                                unsafe_allow_html=True,
                            )
                        with c2:
                            if k.url:
                                st.link_button("Aç", k.url)
                        with c3:
                            if st.button("Sil", key=f"dk_sil_{k.id}"):
                                store.delete_by_id("kaynaklar", k.id)
                                st.success("Silindi.")
                                st.rerun()


