def _render_merakli_minik():
    """Meraklı Minik — Morpa Sihirli Sorular ansiklopedi flip book."""
    import streamlit.components.v1 as components

    # Başlık
    st.markdown(
        '<div style="background:linear-gradient(135deg,#1a1040,#0c1220,#1a1040);'
        'border:2px solid rgba(212,175,55,0.5);border-radius:16px;padding:24px;margin:0 0 20px;'
        'box-shadow:0 8px 32px rgba(0,0,0,0.4);text-align:center">'
        '<div style="font-size:2.5rem;margin-bottom:6px">🔍</div>'
        '<h2 style="color:#6366F1;margin:0;letter-spacing:2px;font-family:Playfair Display,Georgia,serif">'
        'Meraklı Minik Kütüphanesi</h2>'
        '<p style="color:#94a3b8;margin:6px 0 0;font-size:.9rem">'
        '5 Seri &bull; 35 Kitap &bull; 7404 Sayfa &bull; Flip Book</p></div>',
        unsafe_allow_html=True)

    # Kitap seçim kartları — seri bazlı
    sel_key = "_merakli_kitap_sec"
    if sel_key not in st.session_state:
        st.session_state[sel_key] = None

    for seri_id, seri in _MERAKLI_SERILER.items():
        seri_kitaplar = [k for k in _MERAKLI_KITAPLAR if k.get("seri") == seri_id]
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#0B0F19,#1e293b);border:1px solid {seri["renk"]}44;'
            f'border-radius:10px;padding:10px 16px;margin:14px 0 8px;display:flex;align-items:center;gap:10px">'
            f'<span style="font-size:1.3rem">{seri["icon"]}</span>'
            f'<span style="color:{seri["renk"]};font-weight:800;font-size:.95rem">{seri["baslik"]}</span>'
            f'<span style="color:#64748b;font-size:.75rem">— {seri["aciklama"]} ({len(seri_kitaplar)} kitap)</span>'
            f'</div>', unsafe_allow_html=True)

        cols = st.columns(len(seri_kitaplar))
        for i, kitap in enumerate(seri_kitaplar):
            with cols[i]:
                is_selected = st.session_state.get(sel_key) == kitap["id"]
                border = f"3px solid {kitap['renk']}" if is_selected else f"1px solid {kitap['renk']}44"
                shadow = f"0 0 20px {kitap['renk']}33" if is_selected else "none"
                st.markdown(
                    f'<div style="background:linear-gradient(135deg,#0B0F19,#1e293b);border:{border};'
                    f'border-radius:12px;padding:14px 8px;text-align:center;'
                    f'box-shadow:{shadow};min-height:120px">'
                    f'<div style="font-size:1.5rem;margin-bottom:4px">{kitap["icon"]}</div>'
                    f'<div style="color:{kitap["renk"]};font-size:.85rem;font-weight:800;line-height:1.2">'
                    f'{kitap["baslik"]}</div>'
                    f'<div style="color:#94a3b8;font-size:.65rem;margin-top:4px;line-height:1.3">'
                    f'{kitap["aciklama"]}</div></div>',
                    unsafe_allow_html=True)
                if st.button(f"📖 Oku", key=f"mm_sel_{kitap['id']}",
                             use_container_width=True, type="primary" if is_selected else "secondary"):
                    st.session_state[sel_key] = kitap["id"]
                    st.session_state["_mm_page"] = 1
                    # Eski sayfa cache'lerini temizle
                    for ck in list(st.session_state.keys()):
                        if ck.startswith("_mm_img_"):
                            del st.session_state[ck]
                    st.rerun()

    # Kitap seçildiyse flip book göster
    selected_id = st.session_state.get(sel_key)
    if not selected_id:
        st.markdown(
            '<div style="text-align:center;padding:40px;color:#64748b;font-size:1.1rem">'
            '👆 Okumak istediğin kitabı seç</div>', unsafe_allow_html=True)
        return

    kitap = next((k for k in _MERAKLI_KITAPLAR if k["id"] == selected_id), None)
    if not kitap:
        return

    pdf_path = os.path.join(os.path.dirname(os.path.dirname(__file__)), "data", "merakli_minik", kitap["dosya"])
    if not os.path.exists(pdf_path):
        st.error(f"PDF dosyası bulunamadı: {kitap['dosya']}")
        return

    # PDF sayfa sayısı cache
    cache_key = f"_mm_pages_{selected_id}"
    if cache_key not in st.session_state:
        try:
            import fitz
            doc = fitz.open(pdf_path)
            st.session_state[cache_key] = len(doc)
            doc.close()
        except Exception as e:
            st.error(f"PDF açılamadı: {e}")
            return

    total_pages = st.session_state[cache_key]
    page_key = "_mm_page"
    if page_key not in st.session_state:
        st.session_state[page_key] = 1

    # number_input widget'ından gelen değeri de kontrol et
    if "mm_page_input" in st.session_state:
        widget_val = st.session_state["mm_page_input"]
        if widget_val != st.session_state[page_key]:
            st.session_state[page_key] = widget_val

    current_page = max(1, min(total_pages, st.session_state[page_key]))

    # Kitap başlığı
    st.markdown(
        f'<div style="background:linear-gradient(135deg,#0B0F19,#1e293b);border:1px solid {kitap["renk"]}44;'
        f'border-radius:12px;padding:12px 18px;margin:16px 0;display:flex;align-items:center;'
        f'justify-content:space-between">'
        f'<div style="display:flex;align-items:center;gap:10px">'
        f'<span style="font-size:1.3rem">{kitap["icon"]}</span>'
        f'<span style="color:{kitap["renk"]};font-weight:800;font-size:1.1rem">{kitap["baslik"]}</span>'
        f'</div>'
        f'<span style="color:#94a3b8;font-size:.8rem">Sayfa {current_page} / {total_pages}</span></div>',
        unsafe_allow_html=True)

    # Sayfa navigasyon — callback tabanlı
    def _mm_go(pg):
        st.session_state[page_key] = pg
        # number_input widget key'ini de senkronize et
        st.session_state["mm_page_input"] = pg

    nav1, nav2, nav3, nav4, nav5 = st.columns([1, 1, 3, 1, 1])
    with nav1:
        st.button("⏮ İlk", key="mm_first", disabled=current_page <= 1,
                   use_container_width=True, on_click=_mm_go, args=(1,))
    with nav2:
        st.button("◀ Önceki", key="mm_prev", disabled=current_page <= 1,
                   use_container_width=True, on_click=_mm_go, args=(max(1, current_page - 1),))
    with nav3:
        new_page = st.number_input("Sayfa", min_value=1, max_value=total_pages,
                                    value=current_page, key="mm_page_input", label_visibility="collapsed")
        if new_page != current_page:
            st.session_state[page_key] = new_page
    with nav4:
        st.button("Sonraki ▶", key="mm_next", disabled=current_page >= total_pages,
                   use_container_width=True, on_click=_mm_go, args=(min(total_pages, current_page + 1),))
    with nav5:
        st.button("Son ⏭", key="mm_last", disabled=current_page >= total_pages,
                   use_container_width=True, on_click=_mm_go, args=(total_pages,))

    # PDF sayfasını render et (cache'li + JPEG hızlı)
    try:
        import fitz
        import base64 as b64

        img_cache_key = f"_mm_img_{selected_id}_{current_page}"
        img_b64 = st.session_state.get(img_cache_key)

        if not img_b64:
            doc = fitz.open(pdf_path)
            page = doc[current_page - 1]
            zoom = 1.5
            mat = fitz.Matrix(zoom, zoom)
            pix = page.get_pixmap(matrix=mat)
            img_bytes = pix.tobytes("jpeg")
            doc.close()
            img_b64 = b64.b64encode(img_bytes).decode()
            # Mevcut sayfayı cache'le, eski cache'leri temizle (max 5 sayfa tut)
            cached = [k for k in st.session_state if k.startswith(f"_mm_img_{selected_id}_")]
            if len(cached) > 5:
                for old_k in sorted(cached)[:-5]:
                    st.session_state.pop(old_k, None)
            st.session_state[img_cache_key] = img_b64

        # Flip book HTML — CSS 3D çevirme animasyonu
        flip_html = f"""
        <style>
          .mm-book-container {{
            perspective: 1500px;
            display: flex;
            justify-content: center;
            padding: 20px 0;
          }}
          .mm-page {{
            background: #fff;
            border-radius: 4px;
            box-shadow: 0 4px 24px rgba(0,0,0,0.5), 0 0 60px rgba(0,0,0,0.2);
            max-width: 700px;
            width: 100%;
            overflow: hidden;
            animation: mmFlipIn 0.5s ease-out;
            position: relative;
          }}
          .mm-page img {{
            width: 100%;
            height: auto;
            display: block;
          }}
          .mm-page::before {{
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            width: 30px;
            height: 100%;
            background: linear-gradient(90deg, rgba(0,0,0,0.15), transparent);
            pointer-events: none;
            z-index: 2;
          }}
          .mm-page::after {{
            content: '';
            position: absolute;
            top: 0;
            right: 0;
            width: 20px;
            height: 100%;
            background: linear-gradient(270deg, rgba(0,0,0,0.08), transparent);
            pointer-events: none;
            z-index: 2;
          }}
          @keyframes mmFlipIn {{
            0% {{ transform: rotateY(-12deg) scale(0.95); opacity: 0.3; }}
            100% {{ transform: rotateY(0deg) scale(1); opacity: 1; }}
          }}
          .mm-page-num {{
            position: absolute;
            bottom: 8px;
            right: 16px;
            color: rgba(0,0,0,0.3);
            font-size: 12px;
            font-family: Georgia, serif;
            z-index: 3;
          }}
        </style>
        <div class="mm-book-container">
          <div class="mm-page">
            <img src="data:image/jpeg;base64,{img_b64}" alt="Sayfa {current_page}"/>
            <div class="mm-page-num">{current_page}</div>
          </div>
        </div>
        """
        components.html(flip_html, height=900, scrolling=True)

    except Exception as e:
        st.error(f"Sayfa render hatası: {e}")

    # İlerleme barı
    progress = current_page / total_pages
    bar_color = kitap["renk"]
    st.markdown(
        f'<div style="background:#1e293b;border-radius:8px;height:6px;margin:8px 0;overflow:hidden">'
        f'<div style="background:{bar_color};width:{progress*100:.1f}%;height:100%;border-radius:8px;'
        f'transition:width 0.3s ease"></div></div>'
        f'<div style="text-align:center;color:#64748b;font-size:.75rem">%{progress*100:.0f} okundu</div>',
        unsafe_allow_html=True)

    # Başa Dön butonu
    st.markdown("<div style='height:12px'></div>", unsafe_allow_html=True)
    def _mm_back_to_list():
        st.session_state[sel_key] = None
        st.session_state[page_key] = 1
        for ck in list(st.session_state.keys()):
            if ck.startswith("_mm_img_"):
                del st.session_state[ck]
    st.button("📚 Kitap Listesine Dön", key="mm_back_list",
              use_container_width=True, on_click=_mm_back_to_list)


