def _render_masallar():
    """Masallar sekmesi - Edge-TTS premium sesli okuma."""
    from utils.masallar_data import get_collections, get_tales

    styled_section("Masal Koleksiyonu")

    collections = get_collections()
    if not collections:
        st.info("Henüz masal koleksiyonu eklenmemiş.")
        return

    col_names = [f'{c["icon"]} {c["name"]} ({len(c["tales"])} masal)' for c in collections]

    sel_col_idx = st.selectbox(
        "Masal Koleksiyonu",
        range(len(collections)),
        format_func=lambda i: col_names[i],
        key="dk_masallar_col_sel",
    )
    sel_col = collections[sel_col_idx]
    tales = get_tales(sel_col["key"])

    if not tales:
        st.warning("Bu koleksiyonda masal bulunamadı.")
        return

    styled_section("Masal Seçimi")

    cols_select = st.columns([3, 1])
    with cols_select[0]:
        tale_labels = [f'{t["id"]}. {t["title"]}' for t in tales]
        sel_tale_idx = st.selectbox(
            "Masal",
            range(len(tales)),
            format_func=lambda i: tale_labels[i],
            key="dk_masallar_tale_sel",
        )
    with cols_select[1]:
        st.metric("Toplam Masal", len(tales))

    selected_tale = tales[sel_tale_idx]
    tale_text = selected_tale["text"].strip()
    word_count = len(tale_text.split())
    read_min = max(1, word_count // 130)

    st.markdown(
        f'<div style="background:linear-gradient(135deg,#111827,#e2e8f0);border-radius:12px;'
        f'padding:14px 20px;margin:10px 0;border-left:4px solid {_CLR_BLUE};">'
        f'<span style="font-weight:700;color:#1e293b;font-size:1.1rem;">{selected_tale["title"]}</span>'
        f'<span style="color:#64748b;margin-left:16px;font-size:0.85rem;">'
        f'~{word_count} kelime &bull; ~{read_min} dk okuma</span>'
        f'</div>',
        unsafe_allow_html=True,
    )

    # --- Sesli Okuma (tek MP3 - Edge-TTS) ---
    styled_section("Sesli Okuma")

    cache_key = f"masal_mp3_{sel_col['key']}_{selected_tale['id']}"
    audio_bytes = st.session_state.get(cache_key)

    is_english = sel_col.get("lang") == "en"
    voice_label = "Jenny Neural (EN)" if is_english else "Emel Neural (TR)"

    if not audio_bytes:
        if st.button(f"🔊 Sesi Oluştur (Premium Kadın Sesi - {voice_label})", key=f"dk_masal_gen_{cache_key}", use_container_width=True):
            with st.spinner(f"Premium ses oluşturuluyor... (Microsoft {voice_label})"):
                audio_bytes = _generate_full_audio(tale_text, lang="en" if is_english else "tr")
            if audio_bytes:
                st.session_state[cache_key] = audio_bytes
                st.rerun()
            else:
                st.error("❌ Ses oluşturulamadı. İnternet bağlantınızı kontrol edin ve tekrar deneyin.")

    if audio_bytes:
        st.audio(audio_bytes, format="audio/mp3")

    # --- Masal Metni ---
    styled_section("Masal Metni")
    _masal_text_display(tale_text, selected_tale["title"])


def _generate_full_audio(text: str, lang: str = "tr") -> bytes:
    """Edge-TTS ile tum metni tek MP3 olarak uretir. Retry mekanizmali."""
    import asyncio
    import tempfile
    import os
    import uuid

    voice = "en-US-JennyNeural" if lang == "en" else "tr-TR-EmelNeural"
    tmp_path = os.path.join(tempfile.gettempdir(), f"masal_tts_{uuid.uuid4().hex[:8]}.mp3")

    async def _gen(t, p):
        import edge_tts
        c = edge_tts.Communicate(
            t,
            voice,
            rate="-5%",
            pitch="+2Hz",
        )
        await c.save(p)

    # 3 deneme yap
    for attempt in range(3):
        try:
            try:
                loop = asyncio.get_event_loop()
                if loop.is_running():
                    import concurrent.futures
                    with concurrent.futures.ThreadPoolExecutor() as pool:
                        pool.submit(lambda: asyncio.run(_gen(text, tmp_path))).result(timeout=120)
                else:
                    loop.run_until_complete(_gen(text, tmp_path))
            except RuntimeError:
                asyncio.run(_gen(text, tmp_path))

            if os.path.exists(tmp_path) and os.path.getsize(tmp_path) > 100:
                with open(tmp_path, "rb") as f:
                    data = f.read()
                try:
                    os.remove(tmp_path)
                except OSError:
                    pass
                return data
        except PermissionError:
            import time
            time.sleep(1)
        except Exception:
            try:
                if os.path.exists(tmp_path):
                    os.remove(tmp_path)
            except OSError:
                pass
            import time
            time.sleep(1)

    return b""


def _masal_text_display(text: str, title: str):
    """Masal metnini guzel formatta gosterir."""
    import html as html_mod
    safe_text = html_mod.escape(text)
    paragraphs = safe_text.split("\n")
    p_html = "".join(f"<p style='text-indent:1.5em;margin:0.6em 0;'>{p.strip()}</p>" for p in paragraphs if p.strip())

    st.markdown(
        f"""<div style="
            font-family: Georgia, 'Times New Roman', serif;
            max-width: 780px;
            background: linear-gradient(180deg, #fffbf0 0%, #fef7e8 50%, #fdf2d8 100%);
            border-radius: 16px;
            padding: 28px 32px;
            box-shadow: 0 4px 20px rgba(139, 90, 43, 0.15);
            border: 1px solid #e8d5b0;
            max-height: 500px;
            overflow-y: auto;
            line-height: 1.9;
            font-size: 1.05rem;
            color: #4a3520;
            text-align: justify;
        ">
            <div style="text-align:center;font-size:1.3rem;font-weight:700;color:#5a3e1b;
                margin-bottom:16px;padding-bottom:12px;border-bottom:2px solid #d4a853;">
                {html_mod.escape(title)}
            </div>
            {p_html}
        </div>""",
        unsafe_allow_html=True,
    )


def _render_kdg_dk_tab():
    """Kişisel Dil Gelişimi — CEFR Diamond Premium İngilizce."""
    import base64 as _b64

    auth = st.session_state.get("auth_user", {})
    username = auth.get("username", "misafir")

    try:
        from views.kdg_engine import build_kdg_html
        raw_html = build_kdg_html(username)
        full_html = f"<!DOCTYPE html><html><head><meta charset='utf-8'></head><body>{raw_html}</body></html>"
        b64 = _b64.b64encode(full_html.encode("utf-8")).decode("ascii")
        iframe_html = (
            f'<iframe src="data:text/html;base64,{b64}" '
            f'style="width:100%;height:1200px;border:none;border-radius:12px;" '
            f'sandbox="allow-scripts allow-same-origin allow-popups"></iframe>'
        )
        st.markdown(iframe_html, unsafe_allow_html=True)
    except Exception as e:
        st.error(f"CEFR platformu yüklenirken hata: {e}")


