#overlay {{ position:absolute; top:0; left:0; width:100%; height:100%; display:none; justify-content:center; align-items:center; z-index:20; background:rgba(0,0,0,0.7); backdrop-filter:blur(8px); }}
#overlay-box {{ background:linear-gradient(135deg,rgba(0,20,50,0.95),rgba(0,40,80,0.95)); border:2px solid #00aaff; border-radius:20px; padding:40px 50px; text-align:center; box-shadow:0 0 60px rgba(0,150,255,0.4); }}
#overlay-box h1 {{ color:#00d4ff; font-size:28px; margin-bottom:8px; text-shadow:0 0 20px rgba(0,150,255,0.6); }}
#overlay-box p {{ color:#8ec8e8; font-size:15px; margin-bottom:20px; }}
#overlay-box .score {{ color:#ff6b35; font-size:42px; font-weight:900; text-shadow:0 0 15px rgba(255,107,53,0.5); }}
#restart-btn {{ background:linear-gradient(135deg,#0066cc,#0099ff); color:white; border:none; padding:14px 40px; font-size:16px; font-weight:700; border-radius:30px; cursor:pointer; margin-top:16px; transition:all 0.3s; box-shadow:0 4px 20px rgba(0,100,255,0.4); }}
