def _load_dk_odevler() -> list:
    if os.path.exists(_DK_ODEV_PATH):
        with open(_DK_ODEV_PATH, encoding="utf-8") as f:
            return _json.load(f)
    return []


def _save_dk_odevler(data: list):
    os.makedirs(os.path.dirname(_DK_ODEV_PATH), exist_ok=True)
    with open(_DK_ODEV_PATH, "w", encoding="utf-8") as f:
        _json.dump(data, f, ensure_ascii=False, indent=2)


def _render_odev_gonder():
    """Dijital Kütüphane ödev gönderme sekmesi."""
    styled_header(
        "Dijital Kütüphane — Ödev Gönder",
        "Öğrencilere dijital kütüphane içeriklerini ödev olarak gönderin",
        icon="📤",
    )

    odev_tab, gecmis_tab = st.tabs(["📤 Yeni Ödev Gönder", "📋 Gönderilen Ödevler"])

    with odev_tab:
        _render_yeni_dk_odev()

    with gecmis_tab:
        _render_gecmis_dk_odevler()


def _render_yeni_dk_odev():
    from datetime import datetime, timedelta
    from utils.shared_data import get_sinif_sube_listesi

    st.markdown(
        '<div style="background:linear-gradient(135deg,#f0f9ff,#e0f2fe);border:1px solid #bae6fd;'
        'border-radius:10px;padding:14px 18px;margin-bottom:16px">'
        '<div style="font-size:0.85rem;color:#0369a1;font-weight:600">📌 Nasıl Çalışır?</div>'
        '<div style="font-size:0.78rem;color:#0c4a6e;margin-top:4px;line-height:1.6">'
        '1. İçerik türünü ve etkinliği seçin<br>'
        '2. Sınıf ve şubeleri belirleyin<br>'
        '3. Son tarih belirleyip gönderin<br>'
        '4. Ödev, öğrenci/veli ekranına ve günlük rapora işlenir</div></div>',
        unsafe_allow_html=True,
    )

    # ── 1. İçerik Seçimi ──
    col1, col2 = st.columns(2)
    with col1:
        kategori = st.selectbox("📂 İçerik Türü", list(_DK_ICERIK_HARITASI.keys()), key="dk_odev_kat")
    with col2:
        icerikler = list(_DK_ICERIK_HARITASI[kategori].keys())
        icerik = st.selectbox("🎯 Etkinlik", icerikler, key="dk_odev_icerik")

    secilen = _DK_ICERIK_HARITASI[kategori][icerik]

    st.markdown(
        f'<div style="background:linear-gradient(135deg,#f0fdf4,#dcfce7);border:1px solid #86efac;'
        f'border-radius:8px;padding:10px 16px;margin:8px 0">'
        f'<span style="font-size:0.9rem;font-weight:700;color:#166534">✅ {icerik}</span>'
        f'<span style="color:#15803d;font-size:0.8rem;margin-left:8px">— {secilen[2]}</span></div>',
        unsafe_allow_html=True,
    )

    # ── 2. Sınıf/Şube Seçimi ──
    st.markdown("---")
    st.markdown("**🏫 Sınıf ve Şube Seçimi**")

    sinif_sube_data = get_sinif_sube_listesi()
    sinif_sube_list = sinif_sube_data.get("sinif_sube", [])

    if not sinif_sube_list:
        st.warning("⚠️ Henüz öğrenci verisi bulunamadı. Kurumsal Organizasyon > İletişim > Sınıf Listeleri'nden öğrenci ekleyin.")
        return

    col_a, col_b = st.columns(2)
    with col_a:
        tum_sec = st.checkbox("📌 Tüm sınıfları seç", key="dk_odev_tum")
    if tum_sec:
        secilen_siniflar = sinif_sube_list
        with col_b:
            st.success(f"✅ {len(secilen_siniflar)} sınıf/şube seçildi")
    else:
        with col_b:
            secilen_siniflar = st.multiselect("Sınıf/Şube seçin", sinif_sube_list, key="dk_odev_siniflar")

    if not secilen_siniflar:
        st.info("☝️ En az bir sınıf/şube seçin")
        return

    # Seçilen sınıflar chip görünümü
    chips = " ".join(f'<span style="background:#dbeafe;color:#1e40af;padding:3px 10px;border-radius:12px;'
                     f'font-size:0.75rem;font-weight:600;margin:2px">{s}</span>' for s in secilen_siniflar)
    st.markdown(f'<div style="margin:6px 0">{chips}</div>', unsafe_allow_html=True)

    # ── 3. Mesaj ve Son Tarih ──
    st.markdown("---")
    col_msg, col_date = st.columns([2, 1])
    with col_msg:
        mesaj = st.text_area("💬 Ödev Notu (opsiyonel)", placeholder="Örn: Bu hafta sonu tamamlayın", height=80, key="dk_odev_mesaj")
    with col_date:
        son_tarih = st.date_input("📅 Son Tarih", value=datetime.now().date() + timedelta(days=3), key="dk_odev_tarih")

    # ── 4. Gönder Butonu ──
    st.markdown("")
    col_empty, col_btn, col_empty2 = st.columns([1, 2, 1])
    with col_btn:
        if st.button("📤 Ödevi Gönder", key="dk_odev_gonder_btn", use_container_width=True, type="primary"):
            import uuid as _uuid_mod
            odevler = _load_dk_odevler()
            yeni_odev = {
                "id": f"dko_{_uuid_mod.uuid4().hex[:10]}",
                "tarih": datetime.now().strftime("%Y-%m-%d %H:%M"),
                "kategori": kategori,
                "icerik": icerik,
                "sekme": secilen[0],
                "alt_sekme": secilen[1],
                "aciklama": secilen[2],
                "siniflar": secilen_siniflar,
                "mesaj": mesaj.strip() if mesaj else "",
                "son_tarih": son_tarih.strftime("%Y-%m-%d"),
                "durum": "aktif",
                "gonderen": st.session_state.get("user", {}).get("ad", "Öğretmen"),
            }
            odevler.append(yeni_odev)
            _save_dk_odevler(odevler)
            st.toast(f"✅ Ödev gönderildi! {len(secilen_siniflar)} sınıfa: {icerik}", icon="📤")
            st.balloons()


def _render_gecmis_dk_odevler():
    """Gönderilen ödevlerin listesi."""
    from datetime import datetime

    odevler = _load_dk_odevler()
    if not odevler:
        st.info("📭 Henüz gönderilen ödev yok.")
        return

    odevler_sorted = sorted(odevler, key=lambda x: x.get("tarih", ""), reverse=True)

    # İstatistik
    aktif = sum(1 for o in odevler_sorted if not _is_expired(o))
    suresi_dolan = len(odevler_sorted) - aktif
    styled_stat_row([
        ("Toplam", str(len(odevler_sorted)), "#0B0F19", "📊"),
        ("Aktif", str(aktif), "#059669", "✅"),
        ("Süresi Dolan", str(suresi_dolan), "#dc2626", "⏰"),
    ])

    st.markdown("---")

    for i, odev in enumerate(odevler_sorted):
        gecti_mi = _is_expired(odev)
        durum_renk = "#dc2626" if gecti_mi else "#059669"
        durum_text = "⏰ Süresi doldu" if gecti_mi else "✅ Aktif"

        sinif_text = ", ".join(odev.get("siniflar", [])[:6])
        if len(odev.get("siniflar", [])) > 6:
            sinif_text += f" +{len(odev['siniflar']) - 6}"

        mesaj_html = ""
        if odev.get("mesaj"):
            mesaj_html = f'<div style="font-size:0.78rem;color:#0369a1;margin-top:4px">💬 {odev["mesaj"]}</div>'

        st.markdown(
            f'<div style="background:#fff;border:1px solid #e2e8f0;border-radius:10px;padding:14px 18px;margin-bottom:8px;'
            f'border-left:4px solid {durum_renk}">'
            f'<div style="display:flex;justify-content:space-between;align-items:center">'
            f'<div>'
            f'<span style="font-size:0.95rem;font-weight:700;color:#1e293b">{odev.get("icerik","")}</span>'
            f'<span style="font-size:0.75rem;color:#64748b;margin-left:8px">({odev.get("kategori","")})</span>'
            f'</div>'
            f'<span style="font-size:0.75rem;color:{durum_renk};font-weight:600">{durum_text}</span>'
            f'</div>'
            f'<div style="font-size:0.78rem;color:#475569;margin-top:6px">'
            f'🏫 {sinif_text} &nbsp;|&nbsp; 📅 Son: {odev.get("son_tarih","")} &nbsp;|&nbsp; '
            f'🕐 {odev.get("tarih","")} &nbsp;|&nbsp; 👤 {odev.get("gonderen","")}'
            f'</div>'
            f'{mesaj_html}'
            f'</div>',
            unsafe_allow_html=True,
        )

        if st.button("🗑️ Sil", key=f"dk_odev_sil_{odev.get('id', i)}"):
            odevler_all = _load_dk_odevler()
            odevler_all = [o for o in odevler_all if o.get("id") != odev.get("id")]
            _save_dk_odevler(odevler_all)
            st.rerun()


def _is_expired(odev: dict) -> bool:
    from datetime import datetime
    son = odev.get("son_tarih", "")
    if not son:
        return False
    try:
        return datetime.strptime(son, "%Y-%m-%d").date() < datetime.now().date()
    except Exception:
        return False
